input_field_hint__wbl_offline_hint = TextObject(bs_BA="Korisničko ime", cs_CZ="Uživatelské jméno", da_DK="Brugernavn", de_DE="Benutzername", el_GR="Όνομα χρήστη", en_GB="User name", es_ES="Nombre de usuario", fi_FI="Käyttäjänimi", fr_FR="Nom d'utilisateur", hr_HR="Korisničko ime", hu_HU="Felhasználónév", it_IT="Nome utente", nl_NL="Gebruikersnaam", no_NO="Brukernavn", pl_PL="Nazwa użytkownika", pt_PT="Nome de utilizador", ro_RO="Nume utilizator", ru_RU="Имя пользователя", sk_SK="Meno používateľa", sl_SI="Uporabniško ime", sr_RS="Korisničko ime", sv_SE="Användarnamn", tr_TR="Kullanıcı adı", uk_UA="Ім’я користувача")
screen_content__adas_main_description = TextObject(de_DE="We have the ambition to enhance driving safety by provision of optimized ADAS functions , which serve directly\ntowards the users. By tapping accept, you agree to support us to realize the targets by collecting and processing\nthe data within your vehicle. The decline of collection and processing of aforesaid data will not impair your use\nof ADAS functions. This includes your general personal information as well as various technical data required\nonly to optimize the ADAS functions. If you no longer want these data to be collected and processed, you can\nalways change your preference in the general driver assistance systems settings.")
screen_content__adas_sensitive_description = TextObject(de_DE="To provision of optimized ADAS functions, we would also need to collect and process your sensitive personal\ninformation which includes the data listed as below, as permitted by Person Information Protection Law of PRC.\nWe will take security measures required by laws and regulations to protect the sensitive personal information. If\nyou would like to grant us the consent to collect and process, please tap the accept button. You can also apply an\nexpiration time for your consent. It is 12 months by default.")
screen_content__camera_description = TextObject(de_DE="In order to use ADAS relevant functions in a holistic way, please manually switch ON the Driver monitor Camera\nby tap the “Accept”. During the activation period you can always switch off the Driver Monitor Camera which is\nlocated in the ADAS setting page.")
screen_content__connect_device = TextObject(bs_BA="Da li po završetku želite povezati svoj telefon?", cs_CZ="Chcete následně připojit svůj telefon?", da_DK="Vil du efterfølgende forbinde din telefon?", de_DE="Möchtest du im Anschluss dein Telefon verbinden?", el_GR="Θέλετε στη συνέχεια να συνδέσετε το τηλέφωνό σας;", en_GB="Would you like to connect your phone afterwards?", es_ES="¿Desea conectar su teléfono a continuación?", fi_FI="Haluatko sitten yhdistää puhelimesi?", fr_FR="Souhaitez-vous ensuite connecter votre téléphone?", hr_HR="Želite li u nastavku spojiti svoj telefon?", hu_HU="Szeretné ezután csatlakoztatni a telefont?", it_IT="Collegare il telefono alla fine?", nl_NL="Wil je hierna je telefoon verbinden?", no_NO="Vil du opprette forbindelse med telefonen din etterpå?", pl_PL="Czy ccesz na koniec podłączyć swój telefon?", pt_PT="No final, queres ligar o teu telefone?", ro_RO="Doriţi să conectaţi apoi telefonul?", ru_RU="Хотите ли вы потом подключить телефон?", sk_SK="Chcete pripojiť váš telefón?", sl_SI="Ali želite nato povezati svoj telefon?", sr_RS="Da li nakon toga želite da povežete svoj telefon?", sv_SE="Vill du ansluta din telefon efteråt?", tr_TR="Ardından telefonunu bağlamak ister misin?", uk_UA="Чи хочете ви потім підключити телефон?")
screen_content__finish = TextObject(bs_BA="Čestitamo, %1! Želimo Vam mnogo zabave uz Vaš Audi.", cs_CZ="Srdečně blahopřejeme, %1! Přejeme Vám s Vaším vozem Audi hodně\npotěšení.", da_DK="Tillykke, %1! God fornøjelse med din Audi.", de_DE="Herzlichen Glückwunsch, %1! Viel Vergnügen mit deinem Audi.", el_GR="Θερμά συγχαρητήρια, %1! Καλή διασκέδαση με το Audi σας.", en_GB="Congratulations, %1! Enjoy your Audi!", es_ES="¡Enhorabuena, %1! Disfrute de su Audi.", fi_FI="Onnea, %1! Mukavia hetkiä Audin parissa.", fr_FR="Toutes nos félicitations %1! Nous vous souhaitons beaucoup de plaisir\navec votre Audi.", hr_HR="Čestitamo , %1! Želimo vam puno zadovoljstva s vašim Audijem.", hu_HU="Gratulálunk, %1! Használd örömmel Audi gépkocsidat!", it_IT="Congratulazioni, %1! Buon divertimento con la Sua Audi.", nl_NL="Gefeliciteerd, %1! Veel plezier met je Audi.", no_NO="Gratulerer, %1! God tur i din Audi.", pl_PL="Gratulacje, %1! Życzymy Ci dużo zadowolenia z Twojego Audi.", pt_PT="Parabéns, %1! Diverte-te com o teu Audi.", ro_RO="Felicitări, %1! Bucuraţi-vă de modelul dumneavoastră Audi.", ru_RU="Поздравляем, %1! Наслаждайтесь своим Ауди.", sk_SK="Srdečná gratulácia, %1! Zabávajte sa s vašim Audi.", sl_SI="Iskrene čestitke, %1! Obilo zabave z vašim vozilom Audi.", sr_RS="Čestitamo, %1! Mnogo zabave uz vaš Audi.", sv_SE="Grattis, %1! Ha det så kul med din Audi.", tr_TR="Tebrikler, %1! Audin ile iyi eğlenceler.", uk_UA="Вітаємо, %1! Насолоджуйтеся своїм Ауді.")
screen_content__ftw_cbl = TextObject(de_DE="Rufe %1 auf und melde dich an.\nGib dann folgenden Code ein: %2", en_GB="Go to %1 and sign in. Then\nenter this code: %2", es_ES="Ve a %1 e inicia sesión. Luego\nintroduce este código: %2", fr_FR="Rendez-vous sur %1 et\nconnectez-vous. Saisissez ensuite ce code :\n%2", it_IT="Visita la pagina %1 e accedi.\nQuindi inserisci questo codice:%2")
screen_content__ftw_error = TextObject(bs_BA="Prilikom uređivanja opcije Alexa je došlo do problema. Pokušajte aktualizirati aplikaciju\nAlexa u trgovini.", cs_CZ="Při nastavování Alexy se vyskytl problém. Zkuste prosím aktualizovat aplikaci Alexa ve\nStoru.", da_DK="Fejl opstået ved indstilling af Alexa. Forsøg at opdatere Alexa-app i store.", de_DE="Bei der Einrichtung von Alexa ist ein Problem aufgetreten. Bitte versuche, die Alexa\nApp im Store zu aktualisieren.", el_GR="Κατά τη ρύθμιση της Alexa προέκυψε πρόβλημα. Προσπαθήστε να ενημερώσετε την\nεφαρμογή της Alexa στο Store.", en_GB="A problem occurred while setting up Alexa. Please try to update the Alexa app\nin the store.", es_ES="Error al configurar Alexa. Por favor, intente actualizar la App de Alexa en la Store.", fi_FI="Alexan käyttöönotossa ilmeni virhe. Yritä päivittää Alexa-sovellus Storen kautta.", fr_FR="Un problème est apparu durant la configuration d'Alexa. Veuillez essayer de mettre à\njour l'application Alexa dans le Store.", hr_HR="Kod uređivanja Alexe nastupio je problem. Pokušajte aktualizirati aplikaciju Alexa u\nStoreu.", hu_HU="Az Alexa beállításánál probléma történt. Kérünk, próbáld meg frissíteni az Alexa\nalkalmazást az áruházban.", it_IT="Durante la configurazione di Alexa si è verificato un problema. Provare ad aggiornare\nl'app Alexa nello Store.", nl_NL="Bij het instellen van Alexa is een probleem opgetreden. Probeer de Alexa-app in de\nstore te actualiseren.", no_NO="Det oppsto et problem ved konfigureringen av Alexa. Prøv å oppdatere Alexa-appen i\nappbutikken.", pl_PL="Podczas konfigurowania funkcji Alexa wystąpił problem. Spróbuj zaktualizować\naplikację Alexa w sklepie.", pt_PT="Ocorreu um problema na instalação de Alexa.Por favor, tenta atualizar a aplicação\nAlexa na loja.", ro_RO="La configurarea Alexa a apărut o eroare. Încercaţi să actualizaţi aplicaţia Alexa în\nMagazin.", ru_RU="Во время настройки Alexa возникла проблема. Попробуйте обновить приложение\nAlexa в магазине.", sk_SK="Pri nastavovaní Alexy sa vyskytol problém. Prosím, pokúste sa aktualizovať aplikáciu\nAlexa v Store.", sl_SI="Pri nastavitvi Alexe je prišlo do težave. Aplikacijo Alexa poskusite posodobiti v trgovini.", sr_RS="Prilikom uređivanja aplikacije Alexa došlo je do greške. Pokušajte ažurirati aplikaciju\nAlexa u prodavnici.", sv_SE="Ett fel uppstod när Alexa skulle konfigureras. Försök uppdatera Alexa-appen i Store.", tr_TR="Alexa'nın kurulumu sırasında bir sorun oluştu. Lütfen Alexa uygulamasını mağazadan\ngüncellemeyi dene.", uk_UA="Під час налаштування Alexa виникла проблема. Спробуйте оновити програму Alexa\nв магазині.")
screen_content__ftw_intro_text = TextObject(de_DE="Mach das Beste aus deiner Autofahrt – ganz\neinfach per Sprachbefehl. Alexa liefert\nWegbeschreibungen, spielt Musik, tätigt\nAnrufe und vieles mehr.", en_GB="Use voice to make the most of your drive.\nAlexa can help with directions, music, calls and\nmuch more.", es_ES="Usa la voz para sacar el máximo partido a tu\ntrayecto. Alexa puede ayudarte con\nindicaciones, música, llamadas y mucho más.", fr_FR="Utilisez votre voix pour profiter au mieux de\nvotre trajet. Alexa peut vous aider avec\nl'itinéraire, la musique, les appels et bien plus.", it_IT="Usa la voce per sfruttare al meglio il tempo\nche passi in auto. Alexa può aiutarti con\nindicazioni stradali, musica, chiamate e molto\naltro ancora.")
screen_content__ftw_successful_login = TextObject(bs_BA="Uspješno ste se prijavili u Amazon! Otvorite aplikaciju za pokretanje opcije Alexa.", cs_CZ="Úspěšně jste se přihlásili do Amazonu! Otevřete aplikaci, abyste spustili Alexu.", da_DK="Du blev logget korrekt på Amazon! Åbn appen for at starte Alexa.", de_DE="Du hast dich erfolgreich bei Amazon eingeloggt! Öffne die App, um Alexa zu starten.", el_GR="Συνδεθήκατε επιτυχώς με την Amazon! Ανοίξτε την εφαρμογή για να ξεκινήσετε\nτην Alexa.", en_GB="You have logged into Amazon successfully. Open the app to start Alexa.", es_ES="¡Ha iniciado sesión en Amazon correctamente! Abra la aplicación para iniciar Alexa.", fi_FI="Kirjautuminen Amazoniin on onnistunut! Avaa sovellus käynnistääksesi Alexan.", fr_FR="Vous vous êtes connecté avec succès à Amazon! Ouvrez l'application pour lancer Alexa.", hr_HR="Uspješno ste se logirali u Amazonu! Otvorite aplikaciju kako biste pokrenuli Alexu.", hu_HU="Sikeresen bejelentkeztél az Amazonra! Nyisd meg az alkalmazást az Alexa\nelindításához.", it_IT="Il login ad Amazon è stato eseguito correttamente! Aprire l'app per avviare Alexa.", nl_NL="Je hebt succesvol bij Amazon ingelogd! Open de app om Alexa te starten.", no_NO="Du er logget på Amazon. Åpne appen for å starte Alexa.", pl_PL="Nastapiło pomyślne zalogowanie w Amazon! Aby uruchomić funkcję Alexa,\notwórz aplikację.", pt_PT="Fizeste login com sucesso em Amazon! Abre a aplicação para iniciar Alexa.", ro_RO="V-aţi autentificat cu succes la Amazon! Deschideţi aplicaţia, pentru a porni Alexa.", ru_RU="Вы успешно вошли в систему Amazon! Откройте приложение, чтобы\nзапустить Alexa.", sk_SK="Úspešne ste sa prihlásili do Amazonu! Na spustenie Alexy otvorte aplikáciu.", sl_SI="Uspešno ste se prijavili v storitev Amazon! Za zagon Alexe odprite aplikacijo.", sr_RS="Uspešno ste se prijavili u Amazon! Otvorite aplikaciju za pokretanje opcije Alexa.", sv_SE="Du har loggat in hos Amazon. Öppna appen för att starta Alexa.", tr_TR="Başarıyla Amazon'a giriş yaptın! Alexa'yı başlatmak için uygulamayı aç.", uk_UA="Ви успішно увійшли в систему Amazon! Відкрийте програму, щоб запустити Alexa.")
screen_content__mdk_introduction_description_1 = TextObject(bs_BA="Sa ovom Audi connect uslugom Vaš pametni telefon postaje ključ z\nsve funkcije vozila. Otključajte i zaključajte vozilo tako što Vaš\npametni telefon držite na bravi vrata vozača ili se jednostavno\npribližite vozilu. Za pokretanje vozila stavite pametni telefon na\nmjesto za odlaganje telefona.", cs_CZ="S touto službou Audi connect se z Vašeho smartphonu stane\nplnohodnotný klíček od vozidla. Vozidlo můžete odemykat a zamykat\ntak, že přidržíte smartphone u kliky dveří řidiče nebo se jednoduše\npřiblížíte k vozidlu. Pro nastartování vozidla položte smartphone do\ntelefonní přihrádky.", da_DK="Med denne Audi connect-tjeneste bliver din smartphone til en\nfuldgyldig bilnøgle. Bilen kan låses op og låses ved at holde din\nsmartphone mod førerdørens dørhåndtag eller ved bare at nærme\ndig bilen. Læg smartphonen på opbevaringsfladen til telefonen for at\nstarte bilen.", de_DE="Mit diesem Audi connect Dienst wird dein Smartphone zum\nvollwertigen Fahrzeugschlüssel.\n\nDas Fahrzeug kann entriegelt und verriegelt werden, indem du das\nSmartphone an den Türgriff der Fahrertür hältst oder dich einfach\ndem Fahrzeug näherst. Lege das Smartphone zum Starten des\nFahrzeugs in die Telefonablage.", el_GR="Με αυτήν την υπηρεσία Audi connect, το smartphone σας γίνεται\nπλήρες κλειδί του οχήματος. Το όχημα μπορεί να ξεκλειδωθεί και να\nκλειδωθεί με το να κρατήσετε το smartphone κοντά στο χερούλι της\nπόρτας του οδηγού ή απλά πλησιάστε το όχημα. Για να εκκινήσετε το\nόχημα, τοποθετήστε το smartphone στη θήκη απόθεσης τηλεφώνου.", en_GB="This Audi connect service turns your smartphone into a fully\nfunctional vehicle key.\n\nHold the smartphone to the door handle on the driver's side or simply\napproach the vehicle to lock and unlock it. To start the vehicle, place\nthe smartphone in the phone compartment.", es_ES="Con este servicio Audi connect, su smartphone se convierte en una\nllave del vehículo completamente válida. El vehículo se puede\ndesbloquear y bloquear arrimando el smartphone a la manilla de la\npuerta del conductor o, simplemente, acercándose al vehículo.\n\nPara arrancar el vehículo, deje el smartphone en el alojamiento para\nel teléfono.", fi_FI="Tämän Audi connect -palvelun avulla älypuhelimestasi tulee auton\ntäysivaltainen avain. Auton lukot voidaan avata ja lukita pitämällä\nälypuhelinta kuljettajan ovenkahvaa vasten tai vain lähestymällä\nautoa. Aseta älypuhelin puhelinlokeroon auton käynnistämistä\nvarten.", fr_FR="Ce service Audi connect fait de votre smartphone une clé de véhicule\nà part entière.\n\nVous pouvez verrouiller et déverrouiller le véhicule en maintenant\nvotre smartphone au niveau de la poignée de porte du conducteur ou\ntout simplement en vous approchant du véhicule. Pour démarrer le\nvéhicule, déposez le smartphone dans le compartiment pour\ntéléphone.", hr_HR="Ova Audi connect usluga pretvara vaš smartphone u ključ vozila.\nVozilo možete otključati i zaključati tako da smarthone naslonite na\nručicu vozačevih vrata ili jednostavno približavanjem vozilu. Za\npokretanje vozila stavite smartphone u pretinac za odlaganje\ntelefona.", hu_HU="Okostelefonod ezzel az Audi connect szolgáltatással teljes értékű\njárműkulccsá válik. A jármű nyitható és zárható, ha az okostelefont a\nvezetőoldali ajtó kilincséhez tartod, vagy egyszerűen csak a jármű\nközelébe érsz. A jármű indításához helyezd az okostelefont a\ntelefontartóba.", it_IT="Con questo servizio Audi connect il Suo smartphone diventa una\nchiave della vettura a tutti gli effetti. È possibile sbloccare e bloccare\nla vettura tenendo lo smartphone sulla maniglia della porta del\nconducente o semplicemente avvicinandosi alla vettura. Per avviare la\nvettura riporre lo smartphone nel vano per telefono.", nl_NL="Met deze Audi connect dienst wordt je smartphone een volwaardige\nvoertuigsleutel. Het voertuig kan worden ontgrendeld en vergrendeld\ndoor de smartphone aan de portiergreep van het bestuurdersportier\nte houden of door gewoon het voertuig te benaderen. Plaats de\nsmartphone in de telefoonhouder om het voertuig te starten.", no_NO="Med denne Audi connect-tjenesten kan du bruke smarttelefonen som\nbilnøkkel. Du kan låse opp og låse bilen ved å holde smarttelefonen\nmot dørhåndtaket på førerdøren, eller ganske enkelt ved å nærme\ndeg bilen. Legg smarttelefonen på oppbevaringsplassen for\nmobiltelefon for å starte bilen.", pl_PL="Dzięki usłudze Audi connect, tej Twój smartfon staje się\npełnowartościoowym kluczykiem do samochodu. Przykładając\nsmartfon do klamki w drzwiach kierowcy, albo po prostu zbliżając się\ndo samochodu, możesz otwierać i zamykać samochód. Aby uruchomić\nsamochód, połóż smartfon w schowku na smartfon.", pt_PT="Com este serviço Audi connect o teu veículo torna-se na chave\ndo veículo.\n\nO veículo pode ser destrancado e trancado quando seguras o\nsmartphone junto do manípulo da porta do condutor ou quando\nte encontras próximo do veículo. Para ligar o veículo coloca o\nsmartphone no compartimento do telefone.", ro_RO="Cu acest serviciu Audi connect, smartphone-ul dumneavoastră devine\no cheie cu telecomandă veritabilă. Autovehiculul poate fi descuiat şi\nîncuiat, ţinând smartphone-ul lângă mânerul portierei şoferului sau\npur şi simplu prin apropierea de autovehicul. Pentru a porni\nautovehiculul, aşezaţi smartphone-ul în suportul pentru telefon.", ru_RU="Благодаря Audi connect ваш смартфон становится полноценным\nключом автомобиля. Вы можете открывать и закрывать\nавтомобиль, удерживая смартфон у ручки двери на стороне\nводителя или просто приближаясь к автомобилю. Чтобы завести\nавтомобиль, положите смартфон в держатель телефона.", sk_SK="Pomocou tejto služby Audi connect sa váš smartfón stane\nplnohodnotným kľúčom od vozidla. Vozidlo je možné odomknúť a\nzamknúť priložením smartfónu ku kľučke dverí vodiča alebo\njednoduchým priblížením sa k vozidlu. Pre naštartovanie vozidla\nvložte smartfón do odkladacieho priestoru telefónu.", sl_SI="S to storitvijo Audi connect vaš pametni telefon postane enakovreden\nključ vozila. Vozilo lahko odklenete in zaklenete tako, da pametni\ntelefon držite na vratni kljuki voznikovih vrat ali se preprosto\npribližate vozilu. Za zagon vozila pametni telefon položite v predal za\ntelefon.", sr_RS="Uz ovu Audi connect uslugu vaš pametni telefon postaje ključ vozila\nsa svim funkcijama. Vozilo možete da otključate i zaključate tako što\npametni telefon držite na kvaci na vratima vozača ili se jednostavno\npribližavate vozilu. Za pokretanje vozila stavite pametni telefon na\nmesto za odlaganje telefona.", sv_SE="Med denna Audi connect-tjänst blir din smartphone en fullvärdig\nfordonsnyckel.\n\nLås upp och lås fordonet genom att hålla din smartphone mot\ndörrhandtaget på förarsidan eller genom att närma dig fordonet.\nLägg din smartphone i telefonfacket för att starta fordonet.", tr_TR="Bu Audi connect hizmeti ile akıllı telefonun tam kapsamlı bir araç\nanahtarı olacaktır. Akıllı telefonu sürücü kapısının kapı koluna\ntuttuğunda veya sadece araca yaklaştığında araç kilidi açılabilir ve\nkilitlenebilir. Aracı çalıştırmak için akıllı telefonu telefon tepsisi içine\nyerleştir.", uk_UA="Ця служба Audi connect перетворює ваш смартфон  на ключ від\nавтомобіля. Щоб відчинити або зачинити автомобіль, піднесіть\nсмартфон до ручки дверей водія або просто підійдіть до\nавтомобіля. Щоб запустити автомобіль, покладіть смартфон до\nвідсіку для телефону.")
screen_content__mdk_introduction_description_2 = TextObject(bs_BA="Za uređivanje digitalnog ključa je neophodna verifikacija od strane\nvašeg Audi partnera. Dodatne preduslove za povezivanje osnovnog\nuređaja možete pronaći u myAudi aplikaciji.", cs_CZ="Pro nastavení digitálního klíče je nutné ověření partnerem Audi. Další\npožadavky na připojení hlavní jednotky naleznete v aplikaci myAudi.", da_DK="For at kunne konfigurere den digitale nøgle er det nødvendigt med en\nverificering fra din Audi partner. Du kan finde yderligere\nforudsætninger for oprettelse af forbindelse for primært apparat i\nmyAudi-appen.", de_DE="Um den digitalen Schlüssel einrichten zu können, ist eine\nVerifizierung durch deinen Audi Partner erforderlich. Weitere\nVoraussetzungen für die Hauptgerätverbindung findest du in der\nmyAudi App.", el_GR="Για να μπορέσει να γίνει η ρύθμιση του ψηφιακού κλειδιού, απαιτείται\nη επαλήθευση ταυτότητας από τον εξουσιοδοτημένο συνεργάτη Audi\nπου σας εξυπηρετεί. Σχετικά με τις περαιτέρω προϋποθέσεις για τη\nσύνδεση της βασικής συσκευής θα ενημερωθείτε στην εφαρμογή\nmyAudi.", en_GB="In order to set up the digital key, verification by your Audi Partner is\nrequired. You will find further requirements for connecting the main\ndevice in the myAudi app.", es_ES="Para poder configurar la llave digital se precisa una verificación por\nparte de su Concesionario Audi . Encontrará el resto de requisitos\npara la conexión del dispositivo principal en la App myAudi.", fi_FI="Digitaalisen avaimen muodostaminen edellyttää Audi-jälleenmyyjäsi\ntekemää varmennusta. Muut päälaitteen yhdistämisen edellytykset\nlöytyvät myAudi-sovelluksesta.", fr_FR="Pour pouvoir configurer la clé numérique, une vérification par votre\nPartenaire Audi est nécessaire.\nVous trouverez d'autres conditions préalables pour la connexion\ndu périphérique principal dans l'application myAudi.", hr_HR="Kako biste uredili digitalni ključ, potrebna je verifikacija od strane\nAudi partnera. Ostale preduvjete za spajanje glavnog uređaja možete\npronaći u myAudi aplikaciji.", hu_HU="A digitális kulcs beállításához Audi partnerednek ellenőrzést kell\nvégeznie. A főkészülék csatlakoztatásának további feltételeit a\nmyAudi alkalmazásban találhatod meg.", it_IT="Per poter configurare la chiave digitale è necessaria una verifica da\nparte del partner Audi. Gli ulteriori requisiti per il collegamento del\ndispositivo principale sono disponibili nell'app myAudi.", nl_NL="Om de digitale sleutel in te stellen is verificatie door jouw\nAudi-partner vereist. Meer vereisten voor de aansluiting van het\nhoofdapparaat vind je in de myAudi-app.", no_NO="Du må verifisere deg hos Audi-forhandleren for å kunne sette opp\nden digitale nøkkelen. Du finner flere forutsetninger for å opprette\nforbindelse med en hovedenhet i myAudi-appen.", pl_PL="Aby skonfigurować klucz cyfrowy, wymagana jest weryfikacja przez\ndealera Audi. Dodatkowe warunki podłączenia urządzenia głównego\nmożna znaleźć w aplikacji myAudi.", pt_PT="Para poderes configurar a chave digital é necessário que o teu\nConcessionário Audi faça uma verificação. Podes consultar mais\nrequisitos para a ligação ao aparelho principal na myAudi app.", ro_RO="Pentru a putea configura cheia digitală, este necesară o verificare de\ncătre partenerul Audi. Premise suplimentare pentru conectarea\ndispozitivului principal găsiţi în aplicaţia myAudi.", ru_RU="Для установки цифрового ключа требуется верификация у\nпартнера Audi. Дополнительные требования к подключению\nосновного устройства можно найти в приложении myAudi.", sk_SK="Aby ste mohli nastaviť digitálny kľúč, je potrebné overenie partnerom\nAudi. Ďalšie predpoklady na pripojenie hlavného zariadenia nájdete v\naplikácii myAudi.", sl_SI="Za nastavitev digitalnega ključa je potrebno preverjanje pristnosti, ki\nga opravi vaš pooblaščeni partner Audi. Dodatne pogoje za povezavo\nglavne naprave najdete v aplikaciji myAudi.", sr_RS="Da biste mogli urediti digitalni ključ, neophodna je verifikacija od\nstrane vašeg Audi partnera. Ostale preduslove za povezivanje\nosnovnog uređaja možete pronaći u aplikaciji myAudi.", sv_SE="För att kunna ställa in den digitala nyckeln krävs verifiering via din\nAudi-partner. Fler villkor för att ansluta en huvudenhet hittar du i\nmyAudi-appen.", tr_TR="Dijital anahtarın kurulumu için Audi yetkili servisin tarafından\ndoğrulama yapılması gerekmektedir. Ana cihaz bağlantısına ilişkin\ndiğer gereksinimleri myAudi uygulamasında bulabilirsin.", uk_UA="Для налаштування цифрового ключа необхідна перевірка вашого\nпартнера Audi. Інші вимоги до підключення основного пристрою\nможна знайти в програмі myAudi.")
screen_content__mdk_key_not_successful_description = TextObject(bs_BA="Uređivanje osnovnog uređaja, na žalost, nije bilo moguće zbog\ntehničke greške. Pokušajte ponovo kasnije preko myAudi aplikacije.", cs_CZ="Hlavní jednotku bohužel nebylo možné nastavit kvůli technické chybě. Zkuste to prosím později znovu\nprostřednictvím aplikace myAudi.", da_DK="Primært apparat kunne ikke konfigureres på grund af en teknisk fejl.\nForsøg igen senere via myAudi-appen.", de_DE="Das Hauptgerät konnte aufgrund eines technischen Fehlers leider nicht eingerichtet werden. Bitte versuche es\nspäter erneut über die myAudi App.", el_GR="Η ρύθμιση της βασικής συσκευής δεν ήταν εφικτή εξαιτίας ενός τεχνικού σφάλματος. Προσπαθήστε πάλι αργότερα\nμέσω της εφαρμογής myAudi.", en_GB="Unable to configure main device due to a technical error. Please try again later via the myAudi app.", es_ES="El dispositivo principal no se ha podido configurar por un fallo técnico. Por favor, inténtelo de nuevo más tarde\ncon la App myAudi.", fi_FI="Päälaitetta ei voitu muodostaa teknisen virheen vuoksi. Yritä myöhemmin uudelleen myAudi-sovelluksessa.", fr_FR="Le périphérique principal n'a malheureusement pas pu être configuré en raison d'une erreur technique.\nVeuillez réessayer ultérieurement via l'application myAudi.", hr_HR="Glavni uređaj zbog tehničke greške na žalost nije bilo moguće urediti. Pokušajte ponovno kasnije preko\nmyAudi aplikacije.", hu_HU="Sajnos a főkészüléket műszaki hiba miatt nem sikerült beállítani. Próbáld újra később a myAudi alkalmazással.", it_IT="Non è stato possibile configurare il dispositivo principale a causa di un errore tecnico. Si prega di riprovare più\ntardi tramite l'app myAudi.", nl_NL="Helaas kon het hoofdapparaat vanwege een technische fout niet worden ingesteld. Probeer het later opnieuw via\nde myAudi-app.", no_NO="Kan ikke sette opp hovedenheten på grunn av en teknisk feil. Prøv igjen i myAudi-appen senere.", pl_PL="Niestety, nie można skonfigurować urządzenia głównego z powodu błędu technicznego. Spróbuj ponownie\npóźniej za pomocą aplikacji myAudi.", pt_PT="Devido a uma falha técnica, infelizmente não é possível configurar o aparelho principal. Por favor, volta a tentar\nmais tarde através da myAudi app.", ro_RO="Dispozitivul principal nu a putut fi configurat din cauza unei erori tehnice. Reîncercaţi mai târziu prin\naplicaţia myAudi.", ru_RU="К сожалению, основное устройство не удалось настроить из-за технической ошибки. Пожалуйста, повторите\nпопытку позже через приложение myAudi.", sk_SK="Žiaľ, hlavnú jednotku nie je možné nastaviť z dôvodu technickej chyby. Prosím, pokúste sa o to znovu neskôr\nprostredníctvom aplikácie myAudi.", sl_SI="Glavne naprave zaradi tehnične napake žal ni bilo mogoče nastaviti. Poskusite znova pozneje v aplikaciji myAudi.", sr_RS="Uređivanje osnovnog uređaja, na žalost, nije bilo moguće zbog tehničke greške.\nPokušajte ponovo kasnije preko aplikacije myAudi.", sv_SE="Huvudenheten kunde tyvärr inte konfigureras på grund av ett tekniskt fel. Försök igen senare via myAudi-appen.", tr_TR="Ne yazık ki teknik bir hata nedeniyle ana cihaz kurulamadı. Lütfen\ndaha sonra myAudi uygulaması üzerinden tekrar dene.", uk_UA="На жаль, основний пристрій не вдалося налаштувати через технічну помилку. Будь ласка, спробуйте пізніше\nчерез програму myAudi.")
screen_content__mdk_key_not_successful_title = TextObject(bs_BA="Neuspješno uređivanje digitalnog ključa", cs_CZ="Nepodařilo se nastavit digitální klíč", da_DK="Konfigurering af digital nøgle mislykkedes.", de_DE="Einrichten des digitalen Schlüssels fehlgeschlagen", el_GR="Η ρύθμιση του ψηφιακού κλειδιού απέτυχε", en_GB="Setup of digital key failed", es_ES="Error al configurar la llave digital", fi_FI="Digitaalisen avaimen muodostaminen epäonnistui", fr_FR="Échec de la configuration de la clé numérique", hr_HR="Uređivanje digitalnog ključa nije uspjelo", hu_HU="A digitális kulcs beállítása sikertelen", it_IT="Configurazione della chiave digitale non riuscita", nl_NL="Instellen van de digitale sleutel is mislukt", no_NO="Oppsett av den digitale nøkkelen mislyktes", pl_PL="Konfigurowanie klucza cyfrowego nie powiodło się", pt_PT="Configuração da chave digital falhou", ro_RO="Configurarea cheii digitale a eşuat", ru_RU="Не удалось настроить цифровой ключ", sk_SK="Nastavenie digitálneho kľúča sa nepodarilo", sl_SI="Nastavitev digitalnega ključa ni uspela", sr_RS="Neuspešno uređivanje digitalnog ključa", sv_SE="Inställningen av den digitala nyckeln misslyckades", tr_TR="Dijital anahtarın kurulumu başarısız oldu", uk_UA="Не вдалося налаштувати цифровий ключ")
screen_content__mdk_key_successful_description = TextObject(bs_BA="Sada digitalni ključ možete koristiti kao ravnopravni ključ za otvaranje i pokretanje vozila.", cs_CZ="Svůj digitální klíček nyní můžete používat jako plnohodnotný klíček od vozidla k otevírání\na startování vozidla.", da_DK="Du kan nu anvende din digitale nøgle som fuldgyldig bilnøgle til at åbne og\nstarte bilen med.", de_DE="Du kannst deinen digitalen Schlüssel jetzt als vollwertigen Fahrzeugschlüssel zum Öffnen\nund Starten des Fahrzeugs verwenden.", el_GR="Μπορείτε να χρησιμοποιήσετε το ψηφιακό κλειδί σας πλέον ως πλήρες κλειδί οχήματος για\nτο άνοιγμα και την εκκίνηση του οχήματος.", en_GB="You can now use your digital key as a full substitute for the vehicle key to open and start\nthe vehicle.", es_ES="Ahora puede utilizar su llave digital como una llave del vehículo completamente válida\npara abrir y arrancar el vehículo.", fi_FI="Voit nyt käyttää digitaalista avainta täysiarvoisena autonavaimena auton avaamiseen ja\nkäynnistämiseen.", fr_FR="Vous pouvez désormais utiliser votre clé numérique comme une clé de véhicule à part\nentière pour ouvrir et démarrer le véhicule.", hr_HR="Sada svoj digitalni ključ možete koristiti kao potpuno funkcionalan ključ vozila za\notvaranje i pokretanje vozila.", hu_HU="Mostantól teljes értékű járműkulcsként használhatod digitális kulcsodat a jármű\nnyitásához és elindításához.", it_IT="Ora è possibile utilizzare la chiave digitale come una vera e propria chiave della vettura\nper aprire e avviare la vettura.", nl_NL="Je kunt je digitale sleutel nu als volwaardige voertuigsleutel voor het openen en starten\nvan het voertuig gebruiken.", no_NO="Nå kan du bruke den digitale nøkkelen som en bilnøkkel som du kan åpne og\nstarte bilen med.", pl_PL="Od teraz możesz używać swojego kluczyka cyfrowego jako pełnowartościowego kluczyka\ndo otwierania i uruchamiania pojazdu.", pt_PT="Podes agora utilizar a tua chave digital como chave do veículo sem limitações para abrir e\nligar o veículo.", ro_RO="Puteţi utiliza acum cheia dumneavoastră digitală ca pe o cheie complet funcţională a\nautovehiculului, pentru descuierea şi pornirea acestuia.", ru_RU="Теперь Вы можете использовать свой цифровой ключ в качестве полноценного ключа\nавтомобиля для открывания и запуска автомобиля.", sk_SK="Teraz môžete svoj digitálny kľúč použiť ako plnohodnotný kľúč od vozidla na otvorenie a\nnaštartovanie vozidla.", sl_SI="Svoj digitalni ključ lahko zdaj kot enakovreden ključ vozila uporabljate za odklepanje in\nzagon vozila.", sr_RS="Sada digitalni ključ možete koristiti kao ravnopravni ključ za otvaranje i pokretanje vozila.", sv_SE="Du kan nu använda din digitala nyckel som fullvärdig fordonsnyckel för att öppna och\nstarta bilen.", tr_TR="Artık dijital anahtarını aracı açmak ve çalıştırmak için tam kapsamlı bir araç anahtarı\nolarak kullanabilirsin.", uk_UA="Тепер ви можете використовувати свій цифровий ключ як повноцінний ключ від\nавтомобіля для відчинення та запуску автомобіля.")
screen_content__mdk_key_successful_not_tracked__description = TextObject(bs_BA="Provjerite na svom pametnom telefonu možete li ga koristiti kao digitalni ključ. Uvjerite\nse da vaš pametni telefon ima aktivnu internet vezu.", cs_CZ="Na svém smartphonu prosím zkontrolujte, zda ho můžete používat jako digitální klíček.\nZkontrolujte, že má Váš smartphone aktivní připojení k internetu.", da_DK="Kontroller på din smartphone, om du kan anvende den som digital nøgle. Kontroller i den\nforbindelse, at din smartphone har en aktiv internetforbindelse.", de_DE="Bitte überprüfe auf deinem Smartphone, ob du es als digitalen Schlüssel verwenden\nkannst. Stelle dazu sicher, dass dein Smartphone eine aktive Internetverbindung hat.", el_GR="Ελέγξτε στο smartphone σας, αν μπορείτε να το χρησιμοποιήσετε ως ψηφιακό κλειδί. Για\nτον σκοπό αυτό βεβαιωθείτε ότι το smartphone σας διαθέτει ενεργή σύνδεση με το\nδιαδίκτυο.", en_GB="Please check on your smartphone whether it can be used as a digital key. You should also\nensure that it has an active Internet connection.", es_ES="Compruebe en su smartphone si puede utilizarlo como llave digital. Asegúrese de que el\nsmartphone tiene conexión a Internet.", fi_FI="Tarkasta älypuhelimesta, voidaanko sitä käyttää digitaalisena avaimena. Varmista sitä\nvarten, että älypuhelimella on aktiivinen internet-yhteys.", fr_FR="Veuillez vérifier sur votre smartphone si vous pouvez l'utiliser en tant que clé numérique.\nAssurez-vous à cet effet que votre smartphone dispose d'une connexion Internet active.", hr_HR="Provjerite na svom smartphoneu da li ga možete koristiti kao digitalni ključ. U tu svrhu\nvaš smartphone mora imat i aktivnu internetsku vezu.", hu_HU="Kérünk, ellenőrizd okostelefonodat, hogy használható-e digitális kulcsként. Ehhez\ngyőződj meg róla, hogy okostelefonod rendelkezik aktív internetkapcsolattal.", it_IT="Controllare sullo smartphone se è possibile utilizzarlo come chiave digitale. Accertarsi\nche lo smartphone abbia un collegamento internet attivo.", nl_NL="Controleer op je smartphone of je deze als digitale sleutel kunt gebruiken. Zorg er\ndaarnaast voor dat je smartphone een actieve internetverbinding heeft.", no_NO="Kontroller på smarttelefonen om du kan bruke den som digital nøkkel. Når du gjør det,\nmå smarttelefonen ha internettforbindelse.", pl_PL="Sprawdź w swoim smartfoonie, czy możesz go używać jako kluczyka cyfrowego. W tym\ncelu upewnij się, że Twój smartfon ma aktywne połączenie z Internetem.", pt_PT="Por favor, verifica no teu smartphone se o podes utilizar como chave digital. Certifica-te\nque o teu smartphone tem uma ligação à Internet ativa.", ro_RO="Verificaţi pe smartphone-ul dumneavoastră, dacă îl puteţi utiliza ca şi cheie digitală.\nAsiguraţi-vă că smartphone-ul dumneavoastră dispune de o conexiune activă la Internet.", ru_RU="Пожалуйста, проверьте на своем смартфоне, можно ли использовать его в качестве\nцифрового ключа. Для этого убедитесь, что Ваш смартфон имеет активное\nинтернет-соединение.", sk_SK="Skontrolujte si na svojom smartfóne, či ho môžete použiť ako digitálny kľúč. K tomu sa\nuistite, že váš smartfón má aktívne internetové pripojenie.", sl_SI="Na svojem pametnem telefonu preverite, ali ga lahko uporabljate kot digitalni ključ.\nPoleg tega preverite, da ima vaš pametni telefon aktivno internetno povezavo.", sr_RS="Proverite na svom pametnom telefonu da li ga možete koristiti kao digitalni ključ. Uverite\nse da vaš pametni telefon ima aktivnu internet vezu.", sv_SE="Kontrollera på din smartphone om du kan använda den som digital nyckel. Säkerställ att\ndin smartphone har en aktiv internetanslutning.", tr_TR="Lütfen akıllı telefonunda, bunu dijital anahtar olarak kullanıp kullanamayacağını\nkontrol et. Bunun için, akıllı telefonunun aktif bir internet bağlantısına sahip\nolduğundan emin ol.", uk_UA="Будь ласка, перевірте на своєму смартфоні, чи можна використовувати його як\nцифровий ключ. Для цього переконайтеся, що ваш смартфон має активне з'єднання з\nІнтернетом.")
screen_content__mdk_key_successful_not_tracked_title = TextObject(bs_BA="Čestitamo vam na digitalnom ključu!", cs_CZ="Gratulujeme k Vašemu digitálnímu klíčku!", da_DK="Tillykke med din digitale nøgle!", de_DE="Glückwunsch zu deinem digitalen Schlüssel!", el_GR="Συγχαρητήρια για το ψηφιακό κλειδί σας!", en_GB="Congratulations on your digital key!", es_ES="¡Enhorabuena por su llave digital!", fi_FI="Onnittelut digitaalisesta avaimesta!", fr_FR="Félicitation pour la configuration de votre clé numérique!", hr_HR="Čestitamo vam na vašem digitalnom ključu!", hu_HU="Gratulálunk digitális kulcsodhoz!", it_IT="Congratulazioni per la Sua nuova chiave digitale!", nl_NL="Gefeliciteerd met je digitale sleutel!", no_NO="Gratulerer med den digitale nøkkelen!", pl_PL="Gratulujemy Ci kluczyka cyfrowego!", pt_PT="Parabéns pela tua chave digital!", ro_RO="Felicitări pentru cheia dumneavoastră digitală!", ru_RU="Поздравляем с получением цифрового ключа!", sk_SK="Gratulujeme k vášmu digitálnemu kľúču!", sl_SI="Čestitke za digitalni ključ!", sr_RS="Čestitamo vam na digitalnom ključu!", sv_SE="Lycka till med din digitala nyckel!", tr_TR="Dijital anahtarını kutlarız!", uk_UA="Вітаємо з отриманням цифрового ключа!")
screen_content__mdk_key_successful_title = TextObject(bs_BA="Čestitamo vam na digitalnom ključu!", cs_CZ="Gratulujeme k Vašemu digitálnímu klíčku!", da_DK="Tillykke med din digitale nøgle!", de_DE="Glückwunsch zu deinem digitalen Schlüssel!", el_GR="Συγχαρητήρια για το ψηφιακό κλειδί σας!", en_GB="Congratulations on your digital key!", es_ES="¡Enhorabuena por su llave digital!", fi_FI="Onnittelut digitaalisesta avaimesta!", fr_FR="Félicitation pour la configuration de votre clé numérique!", hr_HR="Čestitamo vam na vašem digitalnom ključu!", hu_HU="Gratulálunk digitális kulcsodhoz!", it_IT="Congratulazioni per la Sua nuova chiave digitale!", nl_NL="Gefeliciteerd met je digitale sleutel!", no_NO="Gratulerer med den digitale nøkkelen!", pl_PL="Gratulujemy Ci kluczyka cyfrowego!", pt_PT="Parabéns pela tua chave digital!", ro_RO="Felicitări pentru cheia dumneavoastră digitală!", ru_RU="Поздравляем с получением цифрового ключа!", sk_SK="Gratulujeme k vášmu digitálnemu kľúču!", sl_SI="Čestitke za digitalni ključ!", sr_RS="Čestitamo vam na digitalnom ključu!", sv_SE="Lycka till med din digitala nyckel!", tr_TR="Dijital anahtarını kutlarız!", uk_UA="Вітаємо з отриманням цифрового ключа!")
screen_content__mdk_loading_ble = TextObject(bs_BA="Proces podešavanja glavnog uređaja je u toku. Nemojte deaktivirati Bluetooth\ntokom postupka. Sačekajte...", cs_CZ="Proces vytváření hlavního zařízení probíhá. Během procesu prosím nedeaktivujte\nBluetooth. Čekejte prosím...", da_DK="Primært apparats konfigureringsproces i gang. Deaktiver ikke Bluetooth i løbet af\nprocessen. Vent...", de_DE="Der Einrichtungsprozess des Hauptgeräts läuft. Bitte Bluetooth während des\nVorgangs nicht deaktivieren. Bitte warten...", el_GR="Η διαδικασία ρύθμισης της βασικής συσκευής είναι σε εξέλιξη.\nΜην απενεργοποιήσετε το Bluetooth κατά τη διάρκεια της διαδικασίας.\nΠαρακαλώ περιμένετε…", en_GB="Setting up the main device. Please do not deactivate Bluetooth during this\nprocess. Please wait...", es_ES="Proceso de configuración del dispositivo principal en curso. No desactive el\nBluetooth durante el proceso. Por favor, espere...", fi_FI="Päälaitteen käyttöönottoprosessi on käynnissä. Älä deaktivoi Bluetoothia\nmenettelyn aikana. Odota...", fr_FR="La procédure de configuration du périphérique principal est en cours. Veuillez ne\npas désactiver le Bluetooth pendant la procédure. Veuillez patienter...", hr_HR="U tijeku je proces uređivanja glavnog uređaja. Nemojte deaktivirati Bluetooth\ntijekom ovog postupka. Čekajte...", hu_HU="A főkészülék beállítása folyamatban van. A Bluetooth ne legyen kikapcsolva a\nfolyamat közben. Kérem, várjon...", it_IT="È in corso il processo di configurazione del dispositivo principale. Non disattivare il\nBluetooth durante l'operazione. Attendere prego...", nl_NL="Het proces voor het instellen van het hoofdapparaat is bezig. Schakel Bluetooth\ngedurende het proces niet uit. Even geduld...", no_NO="Prosessen for å sette opp hovedenhet kjører. Ikke deaktiver Bluetooth under\nprosessen. Vent litt...", pl_PL="Trwa proces konfigurowania urządzenia głównego. W trakcie procesu nie wyłączaj\nfunkcji Bluetooth. Proszę czekać...", pt_PT="Está em curso o processo de criação do aparelho principal. Por favor, não desativar\no Bluetooth durante o procedimento. Por favor, aguardar...", ro_RO="Se execută configurarea dispozitivului principal. Nu dezactivaţi conexiunea\nBluetooth pe durata procesului. Aşteptaţi...", ru_RU="Идет процесс настройки основного устройства. Не выключайте Bluetooth во\nвремя процесса. Пожалуйста, ждите...", sk_SK="Prebieha proces nastavenia hlavného zariadenia. Prosím, nevypínajte Bluetooth\npočas procesu. Čakajte, prosím...", sl_SI="Nastavitev glavne naprave poteka. Med postopkom ne deaktivirajte vmesnika\nBluetooth. Prosimo, počakajte ...", sr_RS="Proces aktiviranja glavnog uređaja je u toku. Nemojte deaktivirati Bluetooth tokom\npostupka. Sačekajte...", sv_SE="Inställningsprocessen för huvudenheten pågår. Avaktivera inte Bluetooth under\nförloppet. Vänta...", tr_TR="Ana cihazın kurulum süreci devam ediyor. Lütfen işlem sırasında Bluetooth'u\nkapatmayın. Lütfen bekleyin...", uk_UA="Триває процес налаштування основного пристрою. Не вимикайте Bluetooth під\nчас процесу. Зачекайте...")
screen_content__mdk_loading_nfc = TextObject(bs_BA="Proces podešavanja glavnog uređaja je u toku. Tokom postupka, nemojte sklanjati\npametni telefon sa mjesta za odlaganje telefona. Sačekajte...", cs_CZ="Probíhá nastavování hlavního zařízení. Během procesu prosím neodstraňujte\nsmartphone z telefonní přihrádky. Čekejte prosím...", da_DK="Primært apparats konfigureringsproces i gang. Fjern ikke smartphone fra\nopbevaringsflade til telefon i løbet af processen. Vent...", de_DE="Der Einrichtungsprozess des Hauptgeräts läuft. Bitte Smartphone während des\nVorgangs nicht aus der Telefonablage entfernen. Bitte warten…", el_GR="Η διαδικασία ρύθμισης της βασικής συσκευής είναι σε εξέλιξη. Μην αφαιρείτε το\nsmartphone από τη θήκη απόθεσης τηλεφνου κατά τη διάρκεια της διαδικασίας.\nΠαρακαλώ περιμένετε…", en_GB="The main device is currently being set up. Please do not remove your smartphone\nfrom the phone compartment during this process. Please wait…", es_ES="Proceso de configuración del dispositivo principal en curso. No retire el\nsmartphone del alojamiento para el teléfono durante el proceso. Por favor,\nespere...", fi_FI="Päälaitteen käyttöönottoprosessi on käynnissä. Älä poista älypuhelinta\npuhelinlokerosta menettelyn aikana. Odota...", fr_FR="La procédure de configuration du périphérique principal est en cours. Veuillez ne\npas retirer le smartphone du compartiment pour téléphone pendant la procédure.\nVeuillez patienter...", hr_HR="Proces uređivanja glavnog uređaja je u tijeku. Tijekom postupka nemojte vaditi\nsmartphone iz pretinca za odlaganje telefona. Čekajte....", hu_HU="A főkészülék beállítása folyamatban van. Nem szabad eltávolítani az okostelefont\na telefontartóból a folyamat közben. Kérünk, várj...", it_IT="È in corso il processo di configurazione del dispositivo principale. Non rimuovere lo\nsmartphone dal vano per telefono durante l'operazione. Attendere prego...", nl_NL="Het instellingsproces van het hoofdapparaat wordt uitgevoerd. Haal je\nsmartphone niet uit de telefoonhouder tijdens het proces. Even geduld...", no_NO="Prosessen for å sette opp hovedenhet kjører. Ikke fjern smarttelefonen fra\noppbevaringsplassen under prosessen. Vent litt...", pl_PL="Trwa proces konfigurowania urządzenia głównego. Podczas tego procesu nie\nnależy wyjmować smartfona ze schowka na telefon. Proszę czekać...", pt_PT="O processo de instalação do aparelho principal está em curso. Durante este\nprocedimento não retirar o smartphone do compartimento do telefone. Por favor,\naguardar...", ro_RO="Se execută configurarea dispozitivului principal. Nu scoateţi smartphone-ul din\nsuportul pentru telefon pe durata procesului. Aşteptaţi...", ru_RU="Идет процесс настройки основного устройства. Не вынимайте смартфон из\nдержателя телефона во время процесса. Пожалуйста, ждите…", sk_SK="Prebieha proces nastavenia hlavného zariadenia. Prosím, v priebehu tohto procesu\nneodstraňujte svoj smartfón z odkladacieho priestoru telefónu. Čakajte, prosím...", sl_SI="Nastavitev glavne naprave poteka. Pametnega telefona med postopkom ne\nodstranite iz predala za telefon. Prosimo, počakajte ...", sr_RS="Proces aktiviranja glavnog uređaja je u toku. Tokom postupka, nemojte sklanjati\npametni telefon sa mesta za odlaganje telefona. Sačekajte...", sv_SE="Upprättandet av huvudenheten körs. Ta inte bort smartphone ur telefonfacket\nunder förloppet. Vänta…", tr_TR="Ana cihazın kurulum süreci devam ediyor. Lütfen işlem sırasında akıllı telefonu\ntelefon tepsisinden çıkarmayın. Lütfen bekleyin...", uk_UA="Триває процес налаштування основного пристрою. Не виймайте смартфон з\nвідсіку для телефону під час процесу. Зачекайте...")
screen_content__mdk_no_connection_description = TextObject(bs_BA="Jest li već instalirali myAudi aplikaciju na Vašem pametnom telefonu?\nU tom slučaju možete povezati Vaš uređaj direktno kao glavni uređaj\nputem Bluetooth-a ili NFC.\n\nBluetooth: Provjerite da li je na Vašem uređaju aktiviran Bluetooth i\npotvrdite upit.\n\nNFC: Odložite Vaš pametni telefon na mjesto za odlaganje.", cs_CZ="Nainstalovali jste si již aplikaci myAudi do svého chytrého telefonu?\nPak můžete své zařízení připojit přímo jako hlavní zařízení\nprostřednictvím Bluetooth nebo NFC.\n\nBluetooth: Zkontrolujte, zda je v zařízení aktivováno Bluetooth, a\npotvrďte požadavek.\n\n NFC: Umístěte váš chytrý telefon do přihrádky na telefon.", da_DK="Har du allerede installeret myAudi-appen på din smartphone?\nSå kan du forbinde dit apparat direkte som primært apparat via\nBluetooth eller NFC.\n\nBluetooth: Kontroller, om Bluetooth er aktiveret på dit apparat,\nog bekræft spørgsmålet.\n\nNFC: Placer din smartphone i telefonholderen.", de_DE="Hast du bereits die myAudi App auf deinem Smartphone installiert?\nDann kannst du dein Gerät direkt als Hauptgerät per Bluetooth oder\nNFC verbinden.\n\nBluetooth: Überprüfe, ob Bluetooth auf deinem Gerät aktiviert ist\nund bestätige die Anfrage.\n\nNFC: Bitte lege dein Smartphone in die Telefonablage.", el_GR="Έχετε ήδη εγκαταστήσει την εφαρμογή myAudi στο smartphone σας;\nΤότε μπορείτε να συνδέσετε τη συσκευή σας απευθείας ως βασική\nσυσκευή μέσω Bluetooth ή NFC.\n\nBluetooth: Ελέγξτε αν το Bluetooth είναι ενεργοποιημένο στη συσκευή\nσας και επιβεβαιώστε το αίτημα.\n\nNFC: Τοποθετήστε το smartphone σας στη θήκη απόθεσης τηλεφώνου.", en_GB="Have you already installed the myAudi app on your smartphone?\nThen you can connect your device directly as the main device via\nBluetooth or NFC.\n\nBluetooth: check whether Bluetooth is activated on your device and\nconfirm the request.\n\nNFC: please place your smartphone in the phone compartment.", es_ES="¿Ha instalado ya la App myAudi en su smartphone? Entonces podrá\nconectar su dispositivo directamente como dispositivo principal por\nBluetooth o NFC.\n\nBluetooth: Compruebe si el Bluetooth está activado en su dispositivo\ny confirme la pregunta.\n\nNFC: Coloque su smartphone en el alojamiento para el teléfono.", fi_FI="Oletko jo asentanut myAudi-sovelluksen älypuhelimeesi?\nSen jälkeen voit yhdistää laitteesi suoraan päälaitteena Bluetoothin\ntai NFC:n avulla.\n\nBluetooth: Tarkasta, onko Bluetooth aktivoitu laitteeltasi ja vahvista\nkysymys.\n\nNFC: Aseta älypuhelin puhelinlokeroon.", fr_FR="Avez-vous déjà installé l'application myAudi sur votre smartphone?\nVous pourrez ensuite connecter directement votre périphérique\ncomme périphérique principal via Bluetooth ou NFC.\n\nBluetooth: vérifiez que le Bluetooth est activé sur votre périphérique\net confirmez la demande.\n\nNFC: veuillez déposer votre smartphone dans le compartiment pour\ntéléphone.", hr_HR="Jeste li već instalirali myAudi aplikaciju na svom smartphoneu?\nMožete spojiti svoj uređaj direktno kao glavni uređaj preko\nbluetootha ili NFC-a.\n\nBluetooth: provjerite je li na vašem uređaju aktiviran bluetooth i\npotvrdite upit.\n\nNFC: odložite svoj smartphone u pretinac za odlaganje telefona.", hu_HU="Telepítetted már okostelefonodra a myAudi alkalmazást? Ezzel\nközvetlenül főkészülékként csatlakoztathatod készülékedet a\nBluetooth-on vagy NFC-n keresztül.\n\nBluetooth: ellenőrizd, hogy a Bluetooth aktiválva van-e a\nkészülékeden, és erősítsd meg a kérést.\n\nNFC: helyezd okostelefonodat a telefontartóba.", it_IT="Ha già installato l'app myAudi sul Suo smartphone? Allora può\ncollegare direttamente il Suo dispositivo come dispositivo principale\ntramite Bluetooth o NFC.\n\nBluetooth: controlli che sul Suo dispositivo sia attivato il Bluetooth e\nconfermi la richiesta.\n\nNFC: riponga lo smartphone nel vano per telefono.", nl_NL="Heb je de myAudi-app al op je smartphone geïnstalleerd? Dan kun je\nje apparaat direct als hoofdapparaat verbinden via Bluetooth of NFC.\n\nBluetooth: Controleer of Bluetooth op je apparaat is geactiveerd en\nbevestig het verzoek.\n\nNFC: Plaats je smartphone in de telefoonhouder.", no_NO="Har du installert myAudi-appen på smarttelefonen? Som\nhovedbruker kan du da opprette forbindelse med enheten ved hjelp\nav Bluetooth eller NFC.\n\nBluetooth: Kontroller at Bluetooth er aktivert på enheten, og bekreft\nforespørselen.\n\nNFC: Legg smarttelefonen på oppbevaringsplassen for mobiltelefon.", pl_PL="Czy aplikacja myAudi została już zainstalowana w smartfonie?\nMożesz wówczas podłączyć swoje urządzenie bezpośrednio jako\nurządzenie główne przez Bluetooth lub NFC.\n\nBluetooth: sprawdź, czy funkcja Bluetooth jest włączona w\nurządzeniu i potwierdź zapytanie.\n\nNFC: Umieść smartfon w schowku na telefon.", pt_PT="Já instalas-te a myAudi app no teu smartphone? Depois podes ligar\ndiretamente o teu aparelho como aparelho principal através de\nBluetooth ou de NFC.\n\nBluetooth: Verifica se o Bluetooth está tivo no teu aparelho e\nconfirma a questão.\n\nNFC: Por favor, coloca o teu smartphone no compartimento do\ntelemóvel.", ro_RO="Aţi instalat deja pe smartphone aplicaţia myAudi? Atunci puteţi\nconecta dispozitivul direct, ca dispozitiv principal, prin Bluetooth\nsau NFC.\n\nBluetooth: verificaţi dacă Bluetooth este activat pe dispozitivul\ndumneavoastră şi confirmaţi solicitarea.\n\nNFC: aşezaţi smartphone-ul în suportul pentru telefon.", ru_RU="Если вы уже установили приложение myAudi на свой смартфон,\nвы можете подключить свое устройство непосредственно в\nкачестве основного устройства через Bluetooth или NFC.\n\nBluetooth: проверьте, активирован ли Bluetooth на вашем\nустройстве, и подтвердите запрос.\n\nNFC: поместить смартфон в держатель телефона.", sk_SK="Nainštalovali ste si už aplikáciu myAudi do svojho smartfónu?\nPotom môžete svoje zariadenie pripojiť priamo ako hlavné zariadenie\nprostredníctvom Bluetooth alebo NFC.\n\nBluetooth: skontrolujte, či je na vašom zariadení aktivovaná funkcia\nBluetooth a potvrďte požiadavku.\n\nNFC: prosím, umiestnite svoj smartfón do priehradky na telefón.", sl_SI="Ali ste aplikacijo myAudi že namestili na svoj pametni telefon? Potem\nlahko svojo napravo kot glavno napravo neposredno povežete preko\nvmesnika Bluetooth ali NFC.\n\nBluetooth: preverite, ali je Bluetooth aktiviran na vaši napravi, in\npotrdite zahtevo.\n\nNFC: svoj pametni telefon položite v predal za telefon.", sr_RS="Da li ste već instalirali aplikaciju myAudi na vaš pametni telefon?\nU tom slučaju, vaš uređaj možete da povežete direktno kao\nosnovni uređaj preko Bluetooth-a ili NFC.\n\nBluetooth: Proverite da li je aktiviran Bluetooth na vašem uređaju\ni potvrdite zahtev.\n\nNFC: Molimo vas da odložite pametni telefon na mesto za odlaganje.", sv_SE="Har du redan installerat myAudi-appen på din smartphone? Då kan\ndu ansluta din enhet direkt som huvudenhet via Bluetooth eller NFC.\n\nBluetooth: Kontrollera att Bluetooth är aktiverat på din enhet och\nbekräfta förfrågan.\n\nNFC: Lägg smartphonen i telefonfacket.", tr_TR="Önceden myAudi uygulamasını akıllı telefonuna yükledin mi?\nArdından cihazını Bluetooth veya NFC üzerinden doğrudan ana cihaz\nolarak bağlayabilirsin.\n\nBluetooth: Cihazında Bluetooth'un etkin olup olmadığını kontrol et ve\ntalebi onayla.\n\nNFC: Lütfen akıllı telefonunu telefon tepsisine yerleştir.", uk_UA="Якщо на вашому смартфоні вже встановлено програму myAudi, ви\nможете підключити пристрій безпосередньо як основний пристрій\nчерез Bluetooth або NFC.\n\nBluetooth: перевірте, чи увімкнено Bluetooth на вашому пристрої, і\nпідтвердіть запит.\n\nNFC: покладіть смартфон у відсік для телефону.")
screen_content__mdk_no_password_description = TextObject(bs_BA="Vaš pametni telefon se ne nalazi u režimu uređivanja. Pokrenite režim uređivanja u myAudi aplikaciji pod opcijom\n„Digitalni ključ“. Alternativno uređivanje možete pokrenuti preko poveznice koja je dostavljena glavnom\nkorisniku. Nakon toga slijedite smjernice na Vašem pametnom telefonu. Pogledajte priručnik", cs_CZ="Chytrý telefon není v režimu nastavení. Spusťte prosím režim nastavení v aplikaci myAudi v části „Digitální klíč“.\nPřípadně můžete spustit režim nastavení prostřednictvím odkazu zaslaného hlavnímu uživateli. Poté postupujte\npodle pokynů v chytrém telefonu. Viz palubní kniha", da_DK="Din smartphone er ikke i konfigureringsmodus. Start konfigureringsmodus i myAudi-appen under \"Digital\nnøgle\". Alternativt kan du starte konfigureringen via det link, som er blevet sendt til den primære bruger. Følg\nderefter anvisningerne på din smartphone. Se instruktionsbog.", de_DE="Dein Smartphone ist nicht im Einrichtungsmodus. Bitte starte den Einrichtungsmodus in der myAudi App unter\n„Digitaler Schlüssel“. Alternativ kannst du die Einrichtung über den Link starten, der dem Hauptnutzer\nzugesendet wurde. Folge anschließend den Anweisungen auf deinem Smartphone. Siehe Bordbuch", el_GR="Το smartphone σας δεν είναι σε λειτουργία ρύθμισης. Εκκινήστε τη λειτουργία ρύθμισης στην εφαρμογή myAudi\nστο σημείο “Ψηφιακό κλειδί”. Εναλλακτικά, μπορείτε να ξεκινήσετε τη ρύθμιση μέσω του συνδέσμου που έχει\nαποσταλεί  στον βασικό χρήστη. Μετά από αυτό, ακολουθήστε τις οδηγίες στο smartphone σας. Δείτε βιβλίο\nοδηγιών", en_GB="Your smartphone is not in setup mode. Please start setup mode in the myAudi app under \"Digital key\".\nAlternatively, you can start setup via the link which was sent to the key user. Then follow the instructions on your\nsmartphone. See owner's manual", es_ES="Su smartphone no está en modo de configuración. Inicie el modo de configuración en la App myAudi, dentro del\napartado \"Llave digital\". También puede iniciar la configuración con el enlace enviado al usuario principal. A\ncontinuación, siga las indicaciones que aparezcan en su smartphone. Ver Manual", fi_FI="Älypuhelin ei ole käyttöönottotilassa. Käynnistä käyttöönottotila myAudi-sovelluksen kohdassa Digitaalinen\navain. Voit käynnistää käyttöönoton myös linkistä, joka on lähetetty pääkäyttäjälle. Noudata sitten ohjeita\nälypuhelimesi näytöllä. Ks. käyttöohjekirja.", fr_FR="Votre smartphone n'est pas en mode de configuration.\nVeuillez lancer le mode de configuration dans l'application myAudi sous «Clé numérique».\nVous pouvez également lancer la configuration via le lien envoyé à l'utilisateur principal.\nSuivez ensuite les instructions sur votre smartphone.\nVoir Notice d'Utilisation", hr_HR="Vaš smartphone nije u modusu za uređivanje. Pokrenite modus za uređivanje u myAudi aplikaciji pod \"Digitalni\nključ\". Alternativno uređivanje možete pokrenuti preko linka koji je poslan glavnom korisniku. Nakon toga\nslijedite upute na svom smartphoneu. Vidi priručnu literaturu", hu_HU="Az okostelefonod nincs beállítási módban. Indítsd el a beállítási módot a myAudi alkalmazásban a „Digitális\nkulcs” alatt. Alternatívaként a főfelhasználónak küldött linken keresztül is elindíthatod a beállítást. Ezután\nkövesd az okostelefonodon megjelenő utasításokat. Lásd a fedélzeti irodalmat", it_IT="Lo smartphone non è in modalità configurazione. Avviare la modalità configurazione nell'app myAudi alla voce\n\"Chiave digitale\". In alternativa, è possibile avviare la configurazione tramite il link inviato all'utente principale.\nSeguire quindi le indicazioni sullo smartphone. Vedi libretto", nl_NL="Je smartphone staat niet in de installatiemodus. Start de installatiemodus in de myAudi-app onder \"Digitale\nsleutel\". Je kunt de installatie ook starten via de link die naar de hoofdgebruiker is verzonden. Volg daarna de\ninstructies op je smartphone. Zie instructieboekje", no_NO="Smarttelefonen er ikke i oppsettsmodus. Start oppsettsmodus under «Digital nøkkel» i myAudi-appen. Du kan\nogså starte oppsettet ved hjelp av lenken som ble sendt til hovedbrukeren. Følg deretter instruksjonene på\nsmarttelefonen. Se instruksjonsboken", pl_PL="Twój smartfon nie jest w trybie konfiguracji. Uruchom tryb konfiguracji w aplikacji myAudi w sekcji „Klucz\ncyfrowy”. Alternatywnie możesz rozpocząć konfigurację za pomocą linku wysłanego do głównego użytkownika.\nNastępnie postępuj zgodnie z instrukcjami na smartfonie. Patrz instrukcja obsługi", pt_PT="O teu smartphone não está no modo de configuração. Por favor, inicia o modo de configuração na myAudi app\nem \"Chave digital\". Em alternativa podes iniciar a configuração através do link que é enviado ao utilizador\nprincipal. Em seguida segue as instruções no teu smartphone. Ver Manual de Bordo", ro_RO="Smartphone-ul dumneavoastră se află în modul de configurare. Porniţi modul de configurare în aplicaţia myAudi\nla \"Cheie digitală\". Alternativ puteţi iniţia configurarea prin linkul care a fost transmis utilizatorului principal.\nUrmaţi apoi instrucţiunile de pe smartphone. Consultaţi mapa de bord", ru_RU="Ваш смартфон не находится в режиме настройки. Пожалуйста, запустите режим настройки в приложении\nmyAudi в разделе «Цифровой ключ». Кроме того, вы можете запустить настройку по ссылке, отправленной\nосновному пользователю. Затем следуйте инструкциям на смартфоне. См. руководство по эксплуатации", sk_SK="Váš smartfón nie je v režime nastavenia. Prosím, spustite režim nastavenia v aplikácii myAudi v časti „Digitálny\nkľúč“. Prípadne môžete spustiť nastavenie prostredníctvom linku, ktorý bol zaslaný hlavnému používateľovi.\nPotom postupujte podľa pokynov v smartfóne. Pozrite palubnú dokumentáciu", sl_SI="Vaš pametni telefon ni v načinu za nastavitev. Zaženite način za nastavitev v meniju \"Digitalni ključ\" v aplikaciji\nmyAudi. Nastavitev lahko zaženete tudi preko povezave, ki je bila poslana glavnemu uporabniku. Nato sledite\nnavodilom na pametnem telefonu. Glejte Navodila", sr_RS="Vaš pametni telefon se ne nalazi u režimu uređivanja. Pokrenite režim uređivanja u aplikaciji myAudi pod opcijom\n„Digitalni ključ“.Alternativno uređivanje možete da pokrenete preko linka koji je dostavljen glavnom korisniku.\nNakon toga sledite smernice na vašem pametnom telefonu. Videti priručnu literaturu", sv_SE="Din smartphone är inte i inställningsläge. Aktivera inställningsläget i myAudi-appen under ”Digital nyckel”. Du\nkan även starta inställningen via länken som skickats till huvudanvändaren. Följ sedan anvisningarna på din\nsmartphone. Se instruktionsboken", tr_TR="Akıllı telefonun kurulum modunda değil. Lütfen myAudi uygulamasında “Dijital Anahtar” altında kurulum\nmodunu başlat. Alternatif olarak, ana kullanıcıya gönderilen bağlantıyı kullanarak kurulumu başlatabilirsin.\nArdından akıllı telefonundaki talimatları izley. Kullanım kılavuzuna bakın", uk_UA="Ваш смартфон не перебуває в режимі налаштування. Будь ласка, запустіть режим налаштування в програмі\nmyAudi в розділі «Цифровий ключ». Крім того, ви можете розпочати налаштування за посиланням,\nнадісланим основному користувачеві. Потім дотримуйтесь інструкцій на вашому смартфоні. Див. бортову\nдокументацію")
screen_content__mdk_no_password_title = TextObject(bs_BA="Neuspješno uređivanje digitalnog ključa", cs_CZ="Nepodařilo se nastavit digitální klíč", da_DK="Konfigurering af digital nøgle mislykkedes.", de_DE="Einrichten des digitalen Schlüssels fehlgeschlagen", el_GR="Η ρύθμιση του ψηφιακού κλειδιού απέτυχε", en_GB="Setup of digital key failed", es_ES="Error al configurar la llave digital", fi_FI="Digitaalisen avaimen muodostaminen epäonnistui", fr_FR="Échec de la configuration de la clé numérique", hr_HR="Uređivanje digitalnog ključa nije uspjelo", hu_HU="A digitális kulcs beállítása sikertelen", it_IT="Configurazione della chiave digitale non riuscita", nl_NL="Instellen van de digitale sleutel is mislukt", no_NO="Oppsett av den digitale nøkkelen mislyktes", pl_PL="Konfigurowanie klucza cyfrowego nie powiodło się", pt_PT="Configuração da chave digital falhou", ro_RO="Configurarea cheii digitale a eşuat", ru_RU="Не удалось настроить цифровой ключ", sk_SK="Nastavenie digitálneho kľúča sa nepodarilo", sl_SI="Nastavitev digitalnega ključa ni uspela", sr_RS="Neuspešno uređivanje digitalnog ključa", sv_SE="Inställningen av den digitala nyckeln misslyckades", tr_TR="Dijital anahtarın kurulumu başarısız oldu", uk_UA="Не вдалося налаштувати цифровий ключ")
screen_content__mdk_password_incorrect_blocked_description = TextObject(bs_BA="Lozinka za aktiviranje je nažalost blokirana. Ponovo pristupi lozinki za aktiviranje i ponovi postupak. Uvjeri se da\nimaš aktivnu internet vezu.", cs_CZ="Heslo je bohužel zablokované. Heslo prosím vyvolejte znovu a postup zopakujte. zkontrolujte prosím, že máte\naktivní připojení k internetu.", da_DK="Konfigureringspasswordet er desværre spærret. Kald konfigureringspasswordet frem igen, og gentag processen.\nKontroller i den forbindelse, at du har en aktiv internetforbindelse.", de_DE="Das Einrichtungspasswort ist leider gesperrt. Bitte rufe das Einrichtungspasswort erneut ab und wiederhole den\nVorgang. Bitte stelle dazu sicher, dass du eine aktive Internetverbindung hast.", el_GR="Ο κωδικός πρόσβασης ρύθμισης έχει φραγεί. Καλέστε ξανά τον κωδικό πρόσβασης ρύθμισης και επαναλάβετε τη\nδιαδικασία. Για τον σκοπό αυτό βεβαιωθείτε ότι διαθέτετε ενεργή σύνδεση με το διαδίκτυο.", en_GB="The setup password is locked. Please call up the setup password again and repeat the process. To do so, please\nensure that you have an active Internet connection.", es_ES="La contraseña generada durante la configuración está bloqueada. Recupere la contraseña y repita el proceso.\nAsegúrese de tener conexión a Internet.", fi_FI="Käyttöönottosalasana on valitettavasti lukittu. Hae salasana uudelleen ja toista menettely. Varmista ennen sitä,\nettä sinulla on aktiivinen internet-yhteys.", fr_FR="Le mot de passe de configuration est malheureusement bloqué. Veuillez faire une nouvelle demande de mot de\npasse de configuration et répétez la procédure. Veuillez vous assurer à cet effet que vous disposez d'une\nconnexion Internet active.", hr_HR="Lozinka za uređivanje na žalost je blokirana. Ponovno pozovite lozinku za uređivanje i ponovite postupak. U tu\nsvrhu osigurajte aktivnu vezu s internetom.", hu_HU="A beállítási jelszó sajnos le van tiltva. Kérjük, újra kérd le a beállítási jelszót, és ismételd meg a folyamatot.\nEhhez győződj meg róla, hogy rendelkezel aktív internetkapcsolattal.", it_IT="Purtroppo la password di configurazione è bloccata. Richiamare nuovamente la password di configurazione e\nripetere l'operazione. Accertarsi di avere un collegamento internet attivo.", nl_NL="Sorry, het instellingswachtwoord is vergrendeld. Vraag het instellingswachtwoord opnieuw op en herhaal de\nbewerking. Zorg ervoor dat je een actieve internetverbinding hebt.", no_NO="Oppsettspassordet er sperret. Hent oppsettspassordet igjen, og gjenta prosessen. Pass på at du har\ninternettforbindelse.", pl_PL="Hasło konfiguracyjne jest niestety zablokowane. Proszę ponownie wywołać hasło konfiguracyjne i powtórzyć\nprocedurę. W tym celu proszę się upewnić, że masz połączenie z Internetem.", pt_PT="Infelizmente a palavra-passe da criação está bloqueada. Por favor, recupera a palavra-passe de criação e repita o\nprocedimento. Por favor, certifica-te primeiro que possuis uma ligação à Internet ativa.", ro_RO="Din păcate, parola de configurare este blocată. Reapelaţi parola de configurare şi reluaţi procedura. Asiguraţi-vă\ncă dispuneţi de o conexiune activă la Internet.", ru_RU="К сожалению, пароль настройки заблокирован. Запросите пароль настройки еще раз и повторите процесс.\nУбедитесь в наличии активного интернет-соединения.", sk_SK="Žiaľ, heslo pre nastavenie je zablokované. Prosím, znova získajte heslo nastavenia a proces zopakujte. Uistite sa,\nže máte aktívne internetové pripojenie.", sl_SI="Geslo za nastavitev je žal blokirano. Znova prikličite geslo za nastavitev in ponovite postopek. Poleg tega\npreverite, da imate aktivno internetno povezavo.", sr_RS="Lozinka za aktiviranje je nažalost blokirana. Ponovo pristupite lozinki za aktiviranje i ponovite postupak. Uverite\nse da imate aktivnu internet vezu.", sv_SE="Lösenordet för inställning har tyvärr spärrats. Ange ett nytt lösenord för inställning och upprepa förloppet.\nSäkerställ att du har en aktiv internetanslyuning.", tr_TR="Ne yazık ki, kurulum şifresi kilitli. Lütfen kurulum parolasını yeniden al ve işlemi tekrarla. Lütfen bunun için aktif\nbir internet bağlantısı olduğundan emin ol.", uk_UA="На жаль, пароль налаштування заблоковано. Запросіть пароль ще раз і повторіть процес. Переконайтеся в\nнаявності активного з’єднання з Інтернетом.")
screen_content__mdk_password_incorrect_blocked_title = TextObject(bs_BA="Neuspješno uređivanje digitalnog ključa", cs_CZ="Nepodařilo se nastavit digitální klíč", da_DK="Konfigurering af digital nøgle mislykkedes.", de_DE="Einrichten des digitalen Schlüssels fehlgeschlagen", el_GR="Η ρύθμιση του ψηφιακού κλειδιού απέτυχε", en_GB="Setup of digital key failed", es_ES="Error al configurar la llave digital", fi_FI="Digitaalisen avaimen muodostaminen epäonnistui", fr_FR="Échec de la configuration de la clé numérique", hr_HR="Uređivanje digitalnog ključa nije uspjelo", hu_HU="A digitális kulcs beállítása sikertelen", it_IT="Configurazione della chiave digitale non riuscita", nl_NL="Instellen van de digitale sleutel is mislukt", no_NO="Oppsett av den digitale nøkkelen mislyktes", pl_PL="Konfigurowanie klucza cyfrowego nie powiodło się", pt_PT="Configuração da chave digital falhou", ro_RO="Configurarea cheii digitale a eşuat", ru_RU="Не удалось настроить цифровой ключ", sk_SK="Nastavenie digitálneho kľúča sa nepodarilo", sl_SI="Nastavitev digitalnega ključa ni uspela", sr_RS="Neuspešno uređivanje digitalnog ključa", sv_SE="Inställningen av den digitala nyckeln misslyckades", tr_TR="Dijital anahtarın kurulumu başarısız oldu", uk_UA="Не вдалося налаштувати цифровий ключ")
screen_content__mdk_password_incorrect_description = TextObject(bs_BA="Lozinka za aktiviranje je nažalost neispravna i glavni uređaj nije mogao biti aktiviran. Ponovi postupak s\nispravnom lozinkom za aktivaciju.\n\nPreostalo pokušaja: %1", cs_CZ="Heslo bohužel není správné a hlavní zařízení nelze vytvořit. Zopakujte prosím pokus se správným heslem.\n\nPočet zbývajících pokusů: %1", da_DK="Konfigureringspasswordet er desværre ikke korrekt, og det primære apparat kunne ikke konfigureres. Gentag\nprocessen med det korrekte konfigureringspassword.\n\nResterende forsøg: %1", de_DE="Das Einrichtungspasswort ist leider nicht korrekt und das Hauptgerät konnte nicht eingerichtet werden. Bitte\nwiederhole den Vorgang mit dem korrekten Einrichtungspasswort.\n\nVerbleibende Versuche: %1", el_GR="Ο κωδικός πρόσβασης ρύθμισης δεν είναι σωστός και δεν κατέστη εφικτή η ρύθμιση της βασικής συσκευής.\nΕπαναλάβετε τη διαδικασία με τον σωστό κωδικό πρόσβασης ρύθμισης.\n\nΥπολειπόμενες προσπάθειες: %1", en_GB="Unfortunately, the setup password is incorrect and the main device could not be set up. Please repeat the\nprocess with the correct setup password.\n\nAttempts remaining: %1", es_ES="La contraseña no es correcta y el dispositivo principal no se ha podido configurar. Repita el proceso con la\ncontraseña correcta.\n\nIntentos disponibles: %1", fi_FI="Käyttöönottosalasana on valitettavasti virheellinen eikä päälaitetta voitu ottaa käyttöön. Toista menettely\noikealla käyttöönottosalasanalla.\n\nYrityksiä jäljellä: %1", fr_FR="Le mot de passe de configuration est malheureusement incorrect et le périphérique principal n'a pas pu être\nconfiguré. Veuillez répéter la procédure avec le bon mot de passe de configuration.\n\nNombre d'essais restants: %1", hr_HR="Lozinka za uređivanje na žalost nije ispravna i glavni uređaj nije kreiran. Ponovite postupak s pravilnom lozinkom\nza uređivanje.\n\nPreostali pokušaji: %1", hu_HU="A beállítási jelszó sajnos helytelen, és a főkészüléket nem lehetett beállítani. Kérjük, ismételd meg a folyamatot\na megfelelő beállítási jelszóval.\n\nFennmaradó próbálkozások: %1", it_IT="Purtroppo la password di configurazione non è corretta e non è stato possibile configurare il dispositivo\nprincipale. Ripeta l'operazione con la password di configurazione corretta.\n\nTentativi rimanenti: %1", nl_NL="Het instellingswachtwoord is helaas niet correct en het hoofdapparaat kon niet worden ingesteld. Herhaal de\nbewerking met het correcte instellingswachtwoord.\n\nResterende pogingen: %1", no_NO="Oppsettspassordet er feil, og hovedenheten ble ikke satt opp. Gjenta prosessen med korrekt oppsettspassord.\n\nDu har %1 forsøk igjen", pl_PL="Hasło konfiguracyjne jest niestety nieprawidłowe i nie można skonfigurować urządzenia głównego. Proszę\npowtórzyć procedurę z prawidłowym hasłem konfiguracyjnym.\n\nPozostało prób: %1", pt_PT="Infelizmente a palavra-passe de criação está incorreta e o aparelho principal não pode ser criado. Por favor,\nrepete o procedimento com a palavra-passe correta.\n\nTentativas restantes: %1", ro_RO="Parola de configurare este incorectă şi nu s-a putut configura dispozitivul principal. Repetaţi procedura cu parola\nde configurare corectă.\n\nÎncercări rămase: %1", ru_RU="К сожалению, пароль настройки неправильный, и основное устройство не может быть настроено. Повторите\nпроцесс с правильным паролем настройки.\n\nОсталось попыток: %1", sk_SK="Žiaľ heslo nastavenia je nesprávne a hlavné zariadenie sa nepodarilo nastaviť. Prosím, skúste to znova so\nsprávnym heslom nastavenia.\n\nZostávajúce pokusy: %1", sl_SI="Geslo za nastavitev žal ni pravilno in glavne naprave ni bilo mogoče nastaviti. Postopek ponovite s pravilnim\ngeslom za nastavitev.\n\nPreostali poskusi: %1", sr_RS="Lozinka za aktiviranje je nažalost neispravna i glavni uređaj nije mogao biti aktiviran. Ponovite postupak s\nispravnom lozinkom za aktivaciju.\n\nPreostalo pokušaja: %1", sv_SE="Lösenordet för inställning är tyvärr inte korrekt och huvudenheten kunde inte ställas in. Upprepa förloppet med\nkorrekt lösenord för inställning.\n\nÅterstående försök: %1", tr_TR="Maalesef kurulum şifresi doğru değil ve ana cihaz kurulumu yapılamadı. Lütfen işlemi doğru kurulum şifresi ile\ntekrarla.\n\nKalan deneme sayısı: %1", uk_UA="На жаль, пароль налаштування неправильний, і основний пристрій не може бути налаштований. Повторіть\nпроцес із правильним паролем налаштування.\n\nЗалишилось спроб: %1")
screen_content__mdk_password_incorrect_title = TextObject(bs_BA="Neuspješno uređivanje digitalnog ključa", cs_CZ="Nepodařilo se nastavit digitální klíč", da_DK="Konfigurering af digital nøgle mislykkedes.", de_DE="Einrichten des digitalen Schlüssels fehlgeschlagen", el_GR="Η ρύθμιση του ψηφιακού κλειδιού απέτυχε", en_GB="Setup of digital key failed", es_ES="Error al configurar la llave digital", fi_FI="Digitaalisen avaimen muodostaminen epäonnistui", fr_FR="Échec de la configuration de la clé numérique", hr_HR="Uređivanje digitalnog ključa nije uspjelo", hu_HU="A digitális kulcs beállítása sikertelen", it_IT="Configurazione della chiave digitale non riuscita", nl_NL="Instellen van de digitale sleutel is mislukt", no_NO="Oppsett av den digitale nøkkelen mislyktes", pl_PL="Konfigurowanie klucza cyfrowego nie powiodło się", pt_PT="Configuração da chave digital falhou", ro_RO="Configurarea cheii digitale a eşuat", ru_RU="Не удалось настроить цифровой ключ", sk_SK="Nastavenie digitálneho kľúča sa nepodarilo", sl_SI="Nastavitev digitalnega ključa ni uspela", sr_RS="Neuspešno uređivanje digitalnog ključa", sv_SE="Inställningen av den digitala nyckeln misslyckades", tr_TR="Dijital anahtarın kurulumu başarısız oldu", uk_UA="Не вдалося налаштувати цифровий ключ")
screen_content__privacy_description_clu43 = TextObject(bs_BA="Za bolji doživljaj vozila, možete aktivirati mobilne podatke za korištenje online usluga i time dati\nsaglasnost za preuzimanje aktualizacija softvera. Upravljanje izborom odnosno opoziv izbora možete u\nsvakom trenutku izvršiti u postavkama za zaštitu podataka. Pojedinosti o online uslugama možete\npročitati u napomenama za zaštitu podataka.", cs_CZ="Pro zvýšení zážitků s vozidlem můžete aktivovat mobilní data pro využívání online služeb, čímž povolíte\ndownload aktualizačního softwaru. Svou volbu můžete kdykoli spravovat, resp. odvolat v nastavení\nochrany dat. Podrobnosti k online službám se dozvíte v pokynech k ochraně dat.", da_DK="For en bedre biloplevelse kan du aktivere mobildata til anvendelse af onlinetjenester og dermed give\nsamtykke til downloading af softwareopdateringer. Du kan til enhver tid administrere eller tilbagekalde\ndette i databeskyttelsesindstillingerne. Du kan læse detaljerede informationer vedr. onlinetjenesterne i\ndatabeskytelsesinformationerne.", de_DE="Für ein besseres Fahrzeugerlebnis kannst du mobile Daten zur Nutzung von Online-Diensten aktivieren\nund damit in den Download von Software-Updates einwilligen. Du kannst dies jederzeit in den\nDatenschutzeinstellungen verwalten bzw. widerrufen. Details zu den Online-Diensten kannst du in den\nDatenschutzhinweisen nachlesen.", el_GR="Για μια καλύτερη εμπειρία με το όχημα, μπορείτε να ενεργοποιήσετε τα δεδομένα κινητής τηλεφωνίας για τη\nχρήση online υπηρεσιών, συναινώντας με τον τρόπο αυτό στη λήψη (download) αναβαθμίσεων λογισμικού.\nΑυτό μπορείτε ανά πάσα στιγμή να το διαχειριστείτε ή να το ανακαλέσετε στις ρυθμίσεις προστασίας\nδεδομένων. Λεπτομέρειες σχετικά με τις online υπηρεσίες μπορείτε να βρείτε στις υποδείξεις προστασίας\nδεδομένων προσωπικού χαρακτήρα.", en_GB="For a better in-car experience, you can activate mobile data to use online services and thereby consent to\nthe software update downloads. You can manage this and revoke your consent at any time in the privacy\nsettings. Detailed information on online services can be found in the data protection notes.", es_ES="Si desea aumentar la experiencia de la conducción, puede activar los datos móviles para utilizar los\nservicios online y, así, permitir la descarga de actualizaciones de software. Esto se puede gestionar en\ntodo momento en los ajustes de privacidad. Encontrará todos los detalles sobre los servicios online en el\naviso de privacidad.", fi_FI="Paremman ajokokemuksen saavuttamiseksi voit aktivoida mobiilidatan käyttääksesi online-palveluja ja\nsiten hyväksyä ohjelmistopäivitysten lataamisen. Voit milloin tahansa hallinnoida toimintoa\ntietosuoja-asetuksista tai perua sen. Tarkempia tietoja online-palveluista saat tietosuojaohjeista.", fr_FR="Pour une meilleure expérience du véhicule, vous pouvez activer les données mobiles pour utiliser les\nservices en ligne et ainsi consentir au téléchargement des mises à jour logicielles. Vous pouvez gérer ou\nrévoquer cela à tout moment dans les réglages de la confidentialité. Vous trouverez des détails sur les\nservices en ligne dans les informations relatives à la protection des données.", hr_HR="Kako biste obogatili svoj doživljaj vožnje, možete aktivirati mobilne podatke za korištenje online usluga i\ntako odobriti download softverskih ažuriranja. Time možete upravljati odnosno možete to u svakom\ntrenutku opozvati u postavkama zaštite podataka. Detaljne informacije o online uslugama možete pronaći\nu napomenama o zaštiti podataka.", hu_HU="Még élménytelibbé teheted a jármű használatát azzal, hogy aktiválod a mobil adatokat az online\nszolgáltatások használatához, és ezzel hozzájárulsz a szoftverfrissítések letöltéséhez. Ezt az adatvédelmi\nbeállításokban bármikor kezelheted, ill. visszavonhatod. Az online szolgáltatásokkal kapcsolatos\nrészleteket az adatvédelmi irányelvek tartalmazzák.", it_IT="Per migliorare l'esperienza a bordo, è possibile attivare i dati mobili per utilizzare i servizi online e\nacconsentire così al download degli update software. È possibile gestire o revocare in qualunque\nmomento questa funzionalità nelle impostazioni per la protezione dati. Per dettagli sui servizi online\nconsultare le avvertenze sulla protezione dati.", nl_NL="Voor een betere voertuigervaring kun je mobiele gegevens voor het gebruik van onlinediensten activeren\nen daarmee toestemming geven voor het downloaden van software-updates. Je kunt dit altijd in je\nprivacy-instellingen beheren en je toestemming intrekken. Details over onlinediensten kun je nalezen in\nde richtlijnen voor gegevensbescherming.", no_NO="Du kan aktivere mobildata for å bruke online-tjenestene og få en enda bedre kjøreopplevelse. Da\nsamtykker du også i nedlasting av programvareoppdateringer. Du kan når som helst administrere valgene\ndine og trekke tilbake samtykket i personverninnstillingene. Du kan lese mer om online-tjenestene i\npersonverninformasjonen.", pl_PL="Aby uzyskać lepsze wrażenia z użytkowania pojazdu, możesz włączyć dane mobilne, aby korzystać z usług\nonline i wyrazić zgodę na pobieranie aktualizacji oprogramowania. Możesz mią zarządzać lub ją wycofać w\nkażdej chwili w ustawieniach prywatności. Szczegóły dotyczące usług online można przeczytać w polityce\nprywatności.", pt_PT="Para uma melhor experiência auomóvel podes ativar os dados móveis para utilização de serviços online e\npermitir o download de atualizações de software. Podes gerir ou cancelar isto em qualquer altura nos\najustes da proteção de dados. Podes consultar os detalhes sobre os serviços online nas indicações da\nproteção de dados.", ro_RO="Pentru îmbunătăţirea experienţei cu autovehiculul, puteţi activa datele mobile pentru utilizarea serviciilor\nonline, acceptând astfel descărcarea actualizărilor software. Puteţi administra respectiv revoca acest\nlucru în orice moment, în setările de protecţia datelor. Detalii referitoare la serviciile online puteţi afla din\nindicaţiile privind protecţia datelor.", ru_RU="Для более удобной эксплуатации автомобиля вы можете включить мобильные данные для\nиспользования онлайн-сервисов и дать согласие на загрузку обновлений программного обеспечения.\nВы можете в любой момент изменить или отменить это в настройках защиты данных. Подробную\nинформацию об онлайн-сервисах вы можете найти в примечаниях по защите данных.", sk_SK="Aby ste vylepšili svoj zážitok z jazdy vo vozidle, môžete aktivovať mobilné dáta na používanie online\nslužieb a tým súhlasiť so sťahovaním aktualizácií softvéru. To môžete kedykoľvek spravovať alebo odvolať\nv nastaveniach ochrany údajov. Podrobnosti o online službách si môžete prečítať v upozorneniach o\nochrane údajov.", sl_SI="Za boljše doživetje vožnje lahko mobilne podatke aktivirate za uporabo spletnih storitev in s tem\nsoglašate s prenosom posodobitev programske opreme. Soglasje lahko kadar koli upravljate oz. prekličete\nv nastavitvah zasebnosti. Podrobnosti o spletnih storitvah lahko preberete v obvestilih o varstvu\npodatkov.", sr_RS="Za bolji doživljaj vozila, možete da aktivirate mobilne podatke kako biste koristili onlajn usluge i time dali\nsaglasnost za preuzimanje ažuriranja softvera. Upravljanje izborom odnosno opoziv izbora možete u\nsvakom trenutku da izvršite u podešavanjima za zaštitu podataka. Detaljne informacije o onlajn uslugama\nmožete da pročitate u napomenama o zaštiti podataka.", sv_SE="För en bättre körupplevelse kan du aktivera mobildata för användning av onlinetjänster och därmed ge\nsamtycke till nedladdning av programvaruuppdateringar. Du kan när som helst hantera eller dra tillbaka\nditt samtycke i integritetsinställningarna. Information om onlinetjänsterna hittar du i\nintegritetsinformationen.", tr_TR="Daha iyi bir araç deneyimi için, çevrimiçi hizmetleri kullanmak üzere mobil verileri etkinleştirbilir ve\nböylece yazılım güncellemelerinin indirilmesine izin verebilirsin. Bunu istediğin zaman veri koruma\nayarlarında yönetebilir veya iptal edebilirsin. Çevrimiçi hizmetler hakkındaki ayrıntıları veri koruma\nbilgilerinde okuyabilirsin.", uk_UA="Для зручнішої експлуатації автомобіля ви можете увімкнути мобільні дані для використання\nонлайн-служб і дати згоду на завантаження оновлень програмного забезпечення. Ви можете в\nбудь-який момент змінити або скасувати це в налаштуваннях захисту даних. Детальну інформацію\nпро онлайн-служби ви можете знайти в примітках щодо захисту даних.")
screen_content__privacy_description_deactivated = TextObject(bs_BA="Da biste povećali doživljaj vozila, možete uključiti online usluge kako biste ih koristili. Na taj način\ndeaktivirate režim zaštite podataka. Detaljne informacije o online uslugama možete pročitati u\nnapomenama za zaštitu podataka. Svojim odabirom možete uvijek upravljati u postavkama za zaštitu\npodataka.", cs_CZ="Pro zvýšení svého požitku z jízdy můžete zapnout a používat služby online. Tím deaktivujete režim ochrany\ndat. Detaily ke službám online najdete v pokynech k ochraně dat. Svou volbu můžete kdykoli spravovat v\nnastaveních ochrany dat.", da_DK="For at forbedre din køreoplevelse kan du aktivere onlinetjenester med henblik på at anvende dem. Derved\ndeaktiverer du databeskyttelsesfunktionen. Du kan læse nærmere om onlinetjenesterne i\ndatabeskyttelsesinformationerne. Du kan til enhver tid administrere dit valg i\ndatabeskyttelsesindstillingerne.", de_DE="Um dein Fahrzeugerlebnis zu erhöhen, kannst du Online-Dienste einschalten, um diese zu nutzen.\nDadurch deaktivierst du den Datenschutzmodus. Details zu den Online-Diensten kannst du in den\nDatenschutzhinweisen nachlesen. Du kannst deine Auswahl jederzeit in den Datenschutzeinstellungen\nverwalten.", el_GR="Για να βελτιώσετε την εμπειρία που ζείτε με το όχημά σας, μπορείτε να ενεργοποιήσετε τις online υπηρεσίες,\nώστε να τις χρησιμοποιήσετε. Από αυτό θα απενεργοποιηθεί η λειτουργία προστασίας προσωπικών\nδεδομένων. Για λεπτομέρειες σχετικά με τις online υπηρεσίες, ανατρέξτε στις υποδείξεις προστασίας\nδεδομένων προσωπικού χαρακτήρα. Μπορείτε να διαχειριστείτε τις επιλογές σας ανά πάσα στιγμή στις\nρυθμίσεις προστασίας προσωπικών δεδομένων.", en_GB="For more in-car experiences, you can switch online services on to use them. Doing this deactivates privacy\nmode. For details on the online services, refer to the data protection notes. You can manage your\nselection at any time in the privacy settings.", es_ES="Conecte los servicios online para sacarles provecho y aumentar la experiencia de la conducción. Al hacerlo\nse desactiva el modo de privacidad. Encontrará los detalles sobre los servicios online en el aviso de\nprivacidad. Las opciones seleccionadas se pueden cambiar en todo momento en los ajustes de privacidad.", fi_FI="Voit parantaa autoilukokemustasi käynnistämällä ja käyttämällä online-palveluja. Samalla tietosuojatila\ndeaktivoituu. Tarkemmat tiedot online-palveluista voit lukea tietosuojaohjeista. Voit milloin tahansa\nhallinnoida valintojasi tietosuoja-asetustesi kautta.", fr_FR="Pour une meilleure expérience avec votre véhicule, vous pouvez activer des services en ligne afin de les\nutiliser. Cela désactivera alors le mode de confidentialité. Vous trouverez des détails sur les services en\nligne dans les informations relatives à la protection des données. Vous pouvez gérer vos choix à tout\nmoment dans les réglages de la confidentialité.", hr_HR="Kako biste obogatili svoj doživljaj vozila, možete uključiti online usluge kako biste ih koristili. Na taj način\naktivirate modus zaštite podataka. Detaljne informacije o online uslugama možete pronaći u\nnapomenama o zaštiti podataka. Svojim odabirom možete u svakom trenutku upravljati preko postavki\nzaštite podataka.", hu_HU="Még élménytelibbé teheted a jármű használatát azzal, hogy bekapcsolod az online szolgáltatásokat a\nhasználatukhoz. Ezzel kikapcsolod az adatvédelmi módot. Az online szolgáltatásokkal kapcsolatos\nrészleteket az adatvédelmi irányelvek tartalmazzák. A választott opciót bármikor kezelheted az\nadatvédelmi beállításokban.", it_IT="Per migliorare l'esperienza a bordo della vettura, può attivare i servizi online per utilizzarli. In questo\nmodo si disattiva la modalità protezione dati. Per dettagli sui servizi online consulti le avvertenze sulla\nprotezione dati. Può gestire le Sue scelte in qualunque momento nelle impostazioni per la protezione\ndati.", nl_NL="Om je voertuigervaring te verbeteren, kun je onlinediensten inschakelen om te gebruiken. Hierdoor wordt\nde privacymodus uitgeschakeld. Voor meer informatie over de onlinediensten, zie de privacyrichtlijnen. Je\nkunt je keuzes op elk moment herzien in de privacy-instellingen.", no_NO="Du kan slå på og bruke online-tjenestene for å få en enda bedre kjøreopplevelse. Da deaktiveres\npersonvernmodusen. Du kan lese mer om online-tjenestene i personverninformasjonen. Du kan når som\nhelst tilpasse valgene dine i personverninnstillingene.", pl_PL="Aby poprawić wrażenia związane z korzystaniem z pojazdu, możesz włączyć usługi online i z nich\nkorzystać. Spowoduje to wyłączenie trybu prywatności. Szczegółowe informacje na temat usług online\nmożna znaleźć w polityce prywatności. Swoim wyborem możesz w każdej chwili zarządzać w ustawieniach\nprywatności.", pt_PT="Para aumentar a tua experiência com o veículo podes ligar os serviços online para os poderes utilizar. Com\nisto, desativas o modo de proteção de dados. Podes consultar os detalhes sobre os serviços online na\npolítica de proteção de dados. Em qualquer altura podes gerir a tua opção nos ajustes da proteção de\ndados.", ro_RO="Pentru a îmbunătăţi experienţa dumneavoastră cu autovehiculul, puteţi activa servicii online, pentru a le\nutiliza. Astfel dezactivaţi modul de protecţia datelor. Detalii referitoare la serviciile online puteţi afla din\nindicaţiile privind protecţia datelor. Puteţi administra selecţia în orice moment, în setările de protecţia\ndatelor.", ru_RU="Чтобы повысить комфорт при эксплуатации автомобиля, Вы можете включить онлайн-сервисы, чтобы\nиспользовать их. Этим Вы отключите режим защиты данных. Подробную информацию об\nонлайн-сервисах можно посмотреть в примечаниях по защите данных. Свой выбор можно изменить в\nлюбое время в настройках защиты данных.", sk_SK="Ak chcete zvýšiť zážitok z jazdy, môžete zapnúť online služby pre ich používanie. Tým deaktivujete režim\nochrany údajov. Detaily o online službách si môžete prečítať v pokynoch o ochrane údajov. Váš výber\nmôžete kedykoľvek spravovať v nastaveniach ochrany údajov.", sl_SI="Za izboljšanje vašega doživetja vožnje lahko spletne storitve vključite za uporabo. S tem deaktivirate\nzasebni način. Podrobnosti o spletnih storitvah lahko preberete v obvestilih o varstvu podatkov. Svojo\nizbiro lahko kadar koli upravljate v nastavitvah zasebnosti.", sr_RS="Da biste povećali doživljaj vozila, možete da uključite online usluge kako biste ih koristili. Na taj način\ndeaktivirate režim za zaštitu podataka. Detaljne informacije o online uslugama možete da pročitate u\nnapomenama za zaštitu podataka. Svojim izborom možete uvek da upravljate u podešavanjima za zaštitu\npodataka.", sv_SE="För att förbättra din fordonsupplevelse kan du aktivera onlinetjänster för att använda dem.\nDetta inaktiverar sekretessläget. Du kan läsa mer om onlinetjänsterna i integritetsinformationen.\nDu kan hantera ditt val när som helst i integritetsinställningarna.", tr_TR="Araç deneyimini artırmak için, bunları kullanmak üzere çevrimiçi hizmetleri açabilirsin. Böylece gizlilik\nmodunu devre dışı bırakırsın. Çevrimiçi hizmetler hakkındaki ayrıntıları veri koruma bilgilerinde\nokuyabilirsin. Seçimini istediğin zaman gizlilik ayarlarında yönetebilirsin.", uk_UA="Щоб підвищити комфорт під час експлуатації автомобіля, ви можете увімкнути онлайнові служби,\nщоб використовувати їх. Цим ви вимкнете режим захисту даних. Детальну інформацію про онлайнові\nслужби можна переглянути у вказівках із захисту даних. Свій вибір можна змінити у будь-який час у\nнастройках захисту даних.")
screen_content__privacy_description_time_limit = TextObject(bs_BA="Za bolji doživljaj vozila, možete aktivirati mobilne podatke za korištenje online usluga i time dati\nsaglasnost za preuzimanje aktualizacija softvera. Upravljanje izborom odnosno opoziv izbora možete u\nsvakom trenutku izvršiti u postavkama za zaštitu podataka. Pojedinosti o online uslugama možete\npročitati u napomenama za zaštitu podataka.", cs_CZ="Pro zvýšení zážitků s vozidlem můžete aktivovat mobilní data pro využívání online služeb, čímž povolíte\ndownload aktualizačního softwaru. Svou volbu můžete kdykoli spravovat, resp. odvolat v nastavení\nochrany dat. Podrobnosti k online službám se dozvíte v pokynech k ochraně dat.", da_DK="For en bedre biloplevelse kan du aktivere mobildata til anvendelse af onlinetjenester og dermed give\nsamtykke til downloading af softwareopdateringer. Du kan til enhver tid administrere eller tilbagekalde\ndette i databeskyttelsesindstillingerne. Du kan læse detaljerede informationer vedr. onlinetjenesterne i\ndatabeskytelsesinformationerne.", de_DE="Für ein besseres Fahrzeugerlebnis kannst du mobile Daten zur Nutzung von Online-Diensten aktivieren\nund damit in den Download von Software-Updates einwilligen. Du kannst dies jederzeit in den\nDatenschutzeinstellungen verwalten bzw. widerrufen. Details zu den Online-Diensten kannst du in den\nDatenschutzhinweisen nachlesen.", el_GR="Για μια καλύτερη εμπειρία με το όχημα, μπορείτε να ενεργοποιήσετε τα δεδομένα κινητής τηλεφωνίας για τη\nχρήση online υπηρεσιών, συναινώντας με τον τρόπο αυτό στη λήψη (download) αναβαθμίσεων λογισμικού.\nΑυτό μπορείτε ανά πάσα στιγμή να το διαχειριστείτε ή να το ανακαλέσετε στις ρυθμίσεις προστασίας\nδεδομένων. Λεπτομέρειες σχετικά με τις online υπηρεσίες μπορείτε να βρείτε στις υποδείξεις προστασίας\nδεδομένων προσωπικού χαρακτήρα.", en_GB="For a better in-car experience, you can activate mobile data to use online services and thereby consent to\nthe software update downloads. You can manage this and revoke your consent at any time in the privacy\nsettings. Detailed information on online services can be found in the data protection notes.", es_ES="Si desea aumentar la experiencia de la conducción, puede activar los datos móviles para utilizar los\nservicios online y, así, permitir la descarga de actualizaciones de software. Esto se puede gestionar en\ntodo momento en los ajustes de privacidad. Encontrará todos los detalles sobre los servicios online en el\naviso de privacidad.", fi_FI="Paremman ajokokemuksen saavuttamiseksi voit aktivoida mobiilidatan käyttääksesi online-palveluja ja\nsiten hyväksyä ohjelmistopäivitysten lataamisen. Voit milloin tahansa hallinnoida toimintoa\ntietosuoja-asetuksista tai perua sen. Tarkempia tietoja online-palveluista saat tietosuojaohjeista.", fr_FR="Pour une meilleure expérience du véhicule, vous pouvez activer les données mobiles pour utiliser les\nservices en ligne et ainsi consentir au téléchargement des mises à jour logicielles. Vous pouvez gérer ou\nrévoquer cela à tout moment dans les réglages de la confidentialité. Vous trouverez des détails sur les\nservices en ligne dans les informations relatives à la protection des données.", hr_HR="Kako biste obogatili svoj doživljaj vožnje, možete aktivirati mobilne podatke za korištenje online usluga i\ntako odobriti download softverskih ažuriranja. Time možete upravljati odnosno možete to u svakom\ntrenutku opozvati u postavkama zaštite podataka. Detaljne informacije o online uslugama možete pronaći\nu napomenama o zaštiti podataka.", hu_HU="Még élménytelibbé teheted a jármű használatát azzal, hogy aktiválod a mobil adatokat az online\nszolgáltatások használatához, és ezzel hozzájárulsz a szoftverfrissítések letöltéséhez. Ezt az adatvédelmi\nbeállításokban bármikor kezelheted, ill. visszavonhatod. Az online szolgáltatásokkal kapcsolatos\nrészleteket az adatvédelmi irányelvek tartalmazzák.", it_IT="Per migliorare l'esperienza a bordo, è possibile attivare i dati mobili per utilizzare i servizi online e\nacconsentire così al download degli update software. È possibile gestire o revocare in qualunque\nmomento questa funzionalità nelle impostazioni per la protezione dati. Per dettagli sui servizi online\nconsultare le avvertenze sulla protezione dati.", nl_NL="Voor een betere voertuigervaring kun je mobiele gegevens voor het gebruik van onlinediensten activeren\nen daarmee toestemming geven voor het downloaden van software-updates. Je kunt dit altijd in je\nprivacy-instellingen beheren en je toestemming intrekken. Details over onlinediensten kun je nalezen in\nde richtlijnen voor gegevensbescherming.", no_NO="Du kan aktivere mobildata for å bruke online-tjenestene og få en enda bedre kjøreopplevelse. Da\nsamtykker du også i nedlasting av programvareoppdateringer. Du kan når som helst administrere valgene\ndine og trekke tilbake samtykket i personverninnstillingene. Du kan lese mer om online-tjenestene i\npersonverninformasjonen.", pl_PL="Aby uzyskać lepsze wrażenia z użytkowania pojazdu, możesz włączyć dane mobilne, aby korzystać z usług\nonline i wyrazić zgodę na pobieranie aktualizacji oprogramowania. Możesz mią zarządzać lub ją wycofać w\nkażdej chwili w ustawieniach prywatności. Szczegóły dotyczące usług online można przeczytać w polityce\nprywatności.", pt_PT="Para uma melhor experiência auomóvel podes ativar os dados móveis para utilização de serviços online e\npermitir o download de atualizações de software. Podes gerir ou cancelar isto em qualquer altura nos\najustes da proteção de dados. Podes consultar os detalhes sobre os serviços online nas indicações da\nproteção de dados.", ro_RO="Pentru îmbunătăţirea experienţei cu autovehiculul, puteţi activa datele mobile pentru utilizarea serviciilor\nonline, acceptând astfel descărcarea actualizărilor software. Puteţi administra respectiv revoca acest\nlucru în orice moment, în setările de protecţia datelor. Detalii referitoare la serviciile online puteţi afla din\nindicaţiile privind protecţia datelor.", ru_RU="Для более удобной эксплуатации автомобиля вы можете включить мобильные данные для\nиспользования онлайн-сервисов и дать согласие на загрузку обновлений программного обеспечения.\nВы можете в любой момент изменить или отменить это в настройках защиты данных. Подробную\nинформацию об онлайн-сервисах вы можете найти в примечаниях по защите данных.", sk_SK="Aby ste vylepšili svoj zážitok z jazdy vo vozidle, môžete aktivovať mobilné dáta na používanie online\nslužieb a tým súhlasiť so sťahovaním aktualizácií softvéru. To môžete kedykoľvek spravovať alebo odvolať\nv nastaveniach ochrany údajov. Podrobnosti o online službách si môžete prečítať v upozorneniach o\nochrane údajov.", sl_SI="Za boljše doživetje vožnje lahko mobilne podatke aktivirate za uporabo spletnih storitev in s tem\nsoglašate s prenosom posodobitev programske opreme. Soglasje lahko kadar koli upravljate oz. prekličete\nv nastavitvah zasebnosti. Podrobnosti o spletnih storitvah lahko preberete v obvestilih o varstvu\npodatkov.", sr_RS="Za bolji doživljaj vozila, možete da aktivirate mobilne podatke kako biste koristili onlajn usluge i time dali\nsaglasnost za preuzimanje ažuriranja softvera. Upravljanje izborom odnosno opoziv izbora možete u\nsvakom trenutku da izvršite u podešavanjima za zaštitu podataka. Detaljne informacije o onlajn uslugama\nmožete da pročitate u napomenama o zaštiti podataka.", sv_SE="För en bättre körupplevelse kan du aktivera mobildata för användning av onlinetjänster och därmed ge\nsamtycke till nedladdning av programvaruuppdateringar. Du kan när som helst hantera eller dra tillbaka\nditt samtycke i integritetsinställningarna. Information om onlinetjänsterna hittar du i\nintegritetsinformationen.", tr_TR="Daha iyi bir araç deneyimi için, çevrimiçi hizmetleri kullanmak üzere mobil verileri etkinleştirbilir ve\nböylece yazılım güncellemelerinin indirilmesine izin verebilirsin. Bunu istediğin zaman veri koruma\nayarlarında yönetebilir veya iptal edebilirsin. Çevrimiçi hizmetler hakkındaki ayrıntıları veri koruma\nbilgilerinde okuyabilirsin.", uk_UA="Для зручнішої експлуатації автомобіля ви можете увімкнути мобільні дані для використання\nонлайн-служб і дати згоду на завантаження оновлень програмного забезпечення. Ви можете в\nбудь-який момент змінити або скасувати це в налаштуваннях захисту даних. Детальну інформацію\nпро онлайн-служби ви можете знайти в примітках щодо захисту даних.")
screen_content__privacy_sensitive_data_description = TextObject(bs_BA="Odlučite koje od sljedećih postavki želite aktivirati za usluge u svom vozilu. Imajte na umu da su infotainment\nsistemu eventualno potrebna dodatna ovlaštenja za obradu i prenos određenih ličnih podataka. Online obrada\npodataka vrši se samo kada su mobilni podaci aktivirani.", cs_CZ="Rozhodněte, která z následujících nastavení mají být aktivována pro služby ve vašem vozidle. Vezměte prosím na\nvědomí, že váš systém Infotainment může vyžadovat další oprávnění pro zpracování a přenos určitých osobních\núdajů. Zpracování dat online probíhá pouze v případě, že jsou aktivována mobilní data.", da_DK="Beslut dig for, hvilke af følgende indstillinger der skal aktiveres for tjenesterne i din bil. Vær opmærksom på, at\ndit infotainmentsystem muligvis kan have brug for yderligere autorisationer til behandling og overførsel af visse\npersonrelaterede data. Onlinedatabehandling sker kun ved aktivering af mobildata.", de_DE="Bitte entscheide, welche der folgenden Einstellungen für die Dienste in deinem Fahrzeug aktiviert werden sollen.\nBeachte, dass dein Infotainmentsystem ggf. weitere Berechtigungen für die Verarbeitung und Übertragung von\nbestimmten personenbezogenen Daten benötigt. Eine Online-Datenverarbeitung erfolgt nur bei Aktivierung der\nmobilen Daten.", el_GR="Αποφασίστε ποιες από τις παρακάτω ρυθμίσεις πρέπει να ενεργοποιηθούν για τις υπηρεσίες στο όχημά σας. Έχετε\nυπόψη ότι το σύστημα Infotainment σας χρειάζεται ενδεχομένως περαιτέρω δικαιώματα για την επεξεργασία και\nμεταβίβαση ορισμένων δεδομένων προσωπικού χαρακτήρα. Η online επεξεργασία λαμβάνει χώρα μόνο όταν είναι\nενεργοποιημένα τα δεδομένα κινητής τηλεφωνίας.", en_GB="Please decide which of the following settings should be activated for services in your vehicle. Please note that\nyour infotainment system may require further authorisations for processing and and transmitting certain types of\npersonal data. Online data processing is only performed when mobile data is activated.", es_ES="Indique cuáles de los siguientes ajustes desea activar para los servicios en su vehículo. Tenga en cuenta que su\nservicio de infotainment puede necesitar más permisos para procesar y transmitir determinados datos\npersonales. Los datos online solo se tratan con los datos móviles activados.", fi_FI="Voit valita, minkä seuraavista palvelua koskevista asetuksista haluat aktivoida. Ota huomioon, että\ninfotainment-järjestelmäsi saattaa tarvita lisää oikeuksia tiettyjen henkilötietojen käsittelyyn ja siirtämiseen.\nOnline-tietoja käsitellään vain, kun mobiilidata on aktivoitu.", fr_FR="Veuillez décider lesquels des réglages suivants doivent être activés pour les services dans votre véhicule.\nVeuillez tenir compte du fait que votre système d'infodivertissement peut nécessiter des autorisations\nsupplémentaires pour traiter et transférer certaines données à caractère personnel.\nLe traitement des données en ligne n'a lieu que lorsque les données mobiles sont activées.", hr_HR="Odlučite se koje od sljedećih postavki za usluge u vašem vozilu želite aktivirati. Imajte na umu da vaš infotainment\neventualno treba dodatna odobrenja za obradu i prijenos određenih osobnih podataka. Obrada online podataka\nvrši se samo uz aktiviranje mobilnih podataka.", hu_HU="Kérünk, dönts arról, hogy a következő beállítások közül melyeket szeretnéd aktiválni a járművedben elérhető\nszolgáltatásokhoz. Vedd figyelembe, hogy infotainment-rendszered számára esetleg további engedélyek lehetnek\nszükségesek bizonyos személyes adatok feldolgozásához és továbbításához. Az online adatfeldolgozás csak a\nmobiladatok aktiválása után történik meg.", it_IT="Decida quali delle seguenti impostazioni per i servizi a bordo della vettura debbano essere attivate. Tenga\npresente che il sistema di infotainment potrebbe richiedere ulteriori autorizzazioni per il trattamento e la\ntrasmissione di determinati dati personali. L'elaborazione dei dati online avviene solo all'attivazione dei dati\nmobili.", nl_NL="Bepaal welke van de volgende instellingen voor de diensten in je voertuig dienen te worden geactiveerd. Houd er\nrekening mee dat voor je infotainmentsysteem eventueel andere autorisaties voor de verwerking en overdracht\nvan bepaalde persoonsgerelateerde gegevens vereist zijn. Een online gegevensverwerking kan alleen plaatsvinden\nwanneer mobiele data zijn geactiveerd.", no_NO="Velg hvilke av følgende innstillinger som skal aktiveres for tjenestene i bilen din. Merk: Det kan hende du må gi\nflere tillatelser for at infotainmentsystemet skal kunne behandle og overføre visse personopplysninger.\nOpplysningene kan bare behandles online hvis du aktiverer mobildata.", pl_PL="Proszę zdecydować, które z poniższych ustawień powinny zostać włączone dla usług w pojeździe. Należy\npamiętać, że system Infotainment może wymagać dodatkowych uprawnień do przetwarzania i przesyłania\nniektórych danych osobowych. Przetwarzanie danych online odbywa się tylko wtedy, gdy dane mobilne są\nwłączone.", pt_PT="Por favor, decide qual dos seguintes ajustes deve ser ativado para os serviços no teu veículo. Tem em consideração\nque o teu sistema Infotainment poderá necessitar de mais permissões para o processamento e transmissão de\ndeterminados dados pessoais. Um processamento de dados online só pode ser feito após a ativação dos dados\nmóveis.", ro_RO="Vă rugăm să vă decideţi care din următoarele setări să fie activate pentru serviciile din autovehiculul\ndumneavoastră. Reţineţi că sistemul dumneavoastră Infotainment necesită drepturi suplimentare pentru\nprelucrarea şi transmiterea anumitor date cu caracter personal. Prelucrarea online a datelor are loc numai când\nsunt active datele mobile.", ru_RU="Решите, какие из следующих настроек должны быть активированы для сервисов в вашем автомобиле.\nОбратите внимание, что ваша информационно-развлекательная система может потребовать\nдополнительных разрешений на обработку и передачу определенных персональных данных. Обработка\nданных в режиме онлайн происходит только при активированных мобильных данных.", sk_SK="Prosím, rozhodnite sa, ktoré z nasledujúcich nastavení sa má aktivovať pre služby vo vašom vozidle. Pamätajte na\nto, že váš informačný systém vozidla môže vyžadovať dodatočné oprávnenia na spracovanie a prenos určitých\nosobných údajov. Online spracovanie údajov prebieha iba pri aktivácii mobilných dát.", sl_SI="Določite, katere od naslednjih nastavitev za storitve v vašem vozilu naj se aktivirajo. Upoštevajte, da vaš sistem\nInfotainment morda potrebuje dodatna pooblastila za obdelavo in prenos določenih osebnih podatkov. Spletna\nobdelava podatkov poteka samo pri aktivaciji mobilnih podatkov.", sr_RS="Odlučite koja od sledećih podešavanja za usluge u svom vozilu želite da aktivirate. Imajte na umu da su\ninfotainment sistemu eventualno potrebna dodatna ovlašćenja za obradu i prenos određenih ličnih podataka.\nOnlajn obrada podataka vrši se samo kada su mobilni podaci aktivirani.", sv_SE="Välj vilka av följande inställningar för tjänsterna i din bil som ska aktiveras. Observera att ditt infotainmentsystem\nev. behöver ytterligare behörigheter för behandling och överföring av specifika personuppgifter. Behandling av\ndata online sker endast när mobildata har aktiverats.", tr_TR="Lütfen aracındaki hizmetler için aşağıdaki ayarlardan hangilerinin etkinleştirilmesi gerektiğine karar ver.\nBilgilendirici sisteminin, belirli kişisel verilerin işlenmesi ve iletilmesi için ek izinler gerektirebileceğini dikkate al.\nÇevrimiçi veri işleme sadece mobil verilerin etkinleştirilmesi durumunda gerçekleşir.", uk_UA="Вирішіть, які з наступних налаштувань мають бути активовані для служб у вашому автомобілі. Зверніть увагу,\nщо ваша інформаційно-командна система може зажадати додаткових дозволів на обробку та передачу\nпевних персональних даних. Обробка даних у режимі онлайн відбувається тільки за активованих мобільних\nданих.")
screen_content__privacy_ttdsg_description = TextObject(bs_BA="Pomozite nam da poboljšamo usluge i proizvode kompanije Audi. Uz Vašu saglasnost, Audi može pristupiti Vašem\nvozilu u svrhe navedene u nastavku. Opoziv možete u svakom trenutku da izvršite u postavkama za zaštitu\npodataka. Prikupljanje podataka vrši se samo ako su mobilni podaci aktivirani.", cs_CZ="Pomozte nám zlepšovat služby a produkty společnosti Audi. S Vaším souhlasem může společnost Audi může níže\nuvedenými účely přistupovat k Vašemu vozidlu. Souhlas můžete kdykoli odvolat v nastaveních ochrany dat.\nShromažďování dat probíhá, jen když jsou mobilní data aktivována.", da_DK="Hjælp med at forbedre tjenester og produkter hos Audi. Med dit samtykke kan Audi få adgang til din bil til\nnedenstående formål. Du kan til enhver tid tilbagekalde det i databeskyttelsesindstillingerne.\nOnlinedatabehandling sker kun ved aktivering af mobildata.", de_DE="Hilf mit, Dienste und Produkte bei Audi zu verbessern. Mit deiner Einwilligung kann Audi zu den unten genannten\nZwecken auf dein Fahrzeug zugreifen. Ein Widerruf ist jederzeit in den Datenschutzeinstellungen möglich. Eine\nDatenerhebungen erfolgt nur, wenn die mobilen Daten aktiviert sind.", el_GR="Βοηθήστε να βελτιωθούν οι υπηρεσίες και τα προϊόντα της Audi. Με τη συναίνεσή σας, η Audi μπορεί να έχει\nπρόσβαση στο όχημά σας, για τους αναφερόμενους παρακάτω σκοπούς. Η ανάκληση είναι εφικτή ανά πάσα στιγμή\nστις ρυθμίσεις προστασίας δεδομένων. Η συλλογή δεδομένων λαμβάνει χώρα μόνον όταν είναι ενεργοποιημένα τα\nδεδομένα κινητής τηλεφωνίας.", en_GB="Help to improve Audi's products and services. With your consent, Audi can access your vehicle for the purposes\nspecified below. You can withdraw your consent at any time in the privacy settings. Data collection is only\nperformed when mobile data is activated.", es_ES="Ayúdenos a mejorar nuestros servicios y productos. Con su consentimiento, Audi podrá acceder a su vehículo para\ncumplir los objetivos que se indican más abajo. El consentimiento se puede revocar en todo momento en los\najustes de privacidad. Solo se recopilan datos con los datos móviles activados.", fi_FI="Auta Audia parantamaan palveluitaan ja tuotteitaan. Audilla on pääsy autoosi mainituissa tarkoituksissa, mikäli\nannat siihen suostumuksesi. Voit milloin tahansa peruuttaa suostumuksesi tietosuoja-asetuksista. Tietoja\nkerätään vain, kun mobiilidata on aktivoitu.", fr_FR="Aidez-nous chez Audi à améliorer nos services et produits. Avec votre consentement, Audi peut accéder à votre\nvéhicule aux fins énoncées ci-dessous. Vous pouvez le révoquer à tout moment dans les réglages de la\nconfidentialité. Le traitement des données en ligne n'a lieu que lorsque les données mobiles sont activées.", hr_HR="Pomozite nam da poboljšamo Audijeve usluge i proizvode. Uz vaše odobrenje Audi može pristupiti vašem vozilu u\ndolje navedene svrhe. Opoziv je moguć u svakom trenutku u postavkama zaštite podataka. Podaci se prikupljaju\nsamo kada su aktivirani mobilni podaci.", hu_HU="Segíts fejleszteni az Audi szolgáltatásait és termékeit! Az Audi az alábbiakban felsorolt célokra férhet hozzá\njárművedhez, amennyiben hozzájárulsz. Az adatvédelmi beállításokban bármikor visszavonhatod a\nhozzájárulásodat. Az adatgyűjtésre csak aktivált mobil adatoknál kerül sor.", it_IT="Ci aiuti a migliorare i servizi e i prodotti Audi. Con il Suo consenso, Audi può accedere alla Sua vettura per le\nfinalità riportate di seguito. La revoca è possibile in qualsiasi momento nelle impostazioni per la protezione dati.\nLa rilevazione di dati avviene solo quando i dati mobili sono attivati.", nl_NL="Help mee om diensten en producten van Audi te verbeteren. Met jouw toestemming kan Audi voor de hierna\ngenoemde doeleinden toegang krijgen tot jouw voertuig. Intrekking is altijd in de privacy-instellingen mogelijk.\nGegevensverzameling vindt alleen plaats als mobiele data zijn geactiveerd.", no_NO="Hjelp oss å forbedre Audis tjenester og produkter. Hvis du gir samtykke til det, kan Audi få tilgang til bilen din for\nformålene nevnt under. Du kan når som helst trekke tilbake samtykket i personverninnstillingene.\nDatainnsamling skjer bare når mobildata er aktivert.", pl_PL="Pomóż nam doskonalić usługi i produkty Audi. W celach wymienionych poniżej, Audi może uzyskiwać dostęp do\nTwojego pojazdu, jeśli wyrazisz na to zgodę. Możesz ją cofnąć w każdej chwili w ustawieniach polityki prywatności.\nGromadzenie danych odbywa się tylko przy włączonych danych mobilnych.", pt_PT="Ajuda a Audi a melhorar os serviços e os produtos. Dando a tua permissão a Audi pode aceder ao teu veículo com a\nfinalidade abaixo referida. Isto pode ser cancelado em qualquer momento nos ajustes da proteção de dados. O\nlevantamento dos dados só pode ser feito após a ativação dos dados móveis.", ro_RO="Ajutaţi la îmbunătăţirea serviciilor şi produselor la Audi. Cu acordul dumneavoastră, Audi poate accesa\nautovehiculul dumneavoastră în scopurile de mai jos. Puteţi revoca acordul dumneavoastră în orice moment, în\nsetările de protecţia datelor. Colectarea datelor are loc numai când sunt activate datele mobile.", ru_RU="Помочь улучшить сервисы и продукты Audi. С вашего согласия Audi может получить доступ к вашему\nавтомобилю для указанных ниже целей. Отзыв согласия возможен в любое время в настройках защиты\nданных. Сбор данных осуществляется только при активации мобильных данных.", sk_SK="Pomôžte zlepšiť služby a produkty v spoločnosti Audi. S vaším súhlasom môže Audi pristupovať k vášmu vozidlu\nna účely uvedené nižšie. Odvolanie je možné kedykoľvek v nastaveniach ochrany údajov. Získavanie údajov\nprebieha iba vtedy, keď sú aktivované mobilné dáta.", sl_SI="Pomagajte izboljšati storitve in produkte znamke Audi. Z vašim soglasjem lahko Audi za spodaj navedene namene\ndostopa do vašega vozila. Soglasje lahko kadar koli prekličete v nastavitvah zasebnosti. Zbiranje podatkov poteka\nsamo, ko so mobilni podatki aktivirani.", sr_RS="Pomozite nam da poboljšamo usluge i proizvode kompanije Audi. Uz vašu saglasnost, Audi može da pristupi\nvašem vozilu u svrhe navedene u nastavku. Opoziv možete u svakom trenutku da izvršite u podešavanjima za\nzaštitu podataka. Prikupljanje podataka se vrši samo ako su mobilni podaci aktivirani.", sv_SE="Hjälp oss att förbättra Audis tjänster och produkter. Med ditt samtycke kan Audi komma åt ditt fordon för\nnedanstående syften. Du kan när som helst dra tillbaka ditt samtycke i integritetsinställningarna. Datainsamling\nsker endast när mobildata har aktiverats.", tr_TR="Audi'de hizmetlerin ve ürünlerin iyileştirilmesine yardımcı ol. Onay vermen ile Audi, aşağıda belirtilen amaçlar\ndoğrultusunda aracına erişebilir. Veri koruma ayarlarında her zaman bir iptal mümkündür. Veri toplama sadece\nmobil veri etkinleştirilmişse gerçekleşir.", uk_UA="Допомогти поліпшити служби та продукти Audi. З вашої згоди Audi може отримати доступ до вашого\nавтомобіля для зазначених нижче цілей. Відкликання згоди можливе в будь-який час у налаштуваннях\nзахисту даних. Збір даних здійснюється тільки при активації мобільних даних.")
screen_content__pso_android_pin = TextObject(bs_BA="Kreirajte PIN sa najmanje 4 cifre.", cs_CZ="Určete PIN s nejméně 4 číslicemi.", da_DK="Definer en pinkode på mindst fire cifre.", de_DE="Lege eine PIN mit mindestens 4 Ziffern\nfest.", el_GR="Καθορίστε ένα PIN με τουλάχιστον 4\nχαρακτήρες.", en_GB="Please specify a PIN with at least 4 digits.", es_ES="Defina un PIN con al menos 4 dígitos.", fi_FI="Aseta vähintään nelinumeroinen PIN-koodi.", fr_FR="Définissez un code PIN d'au moins 4\nchiffres.", hr_HR="Kreirajte PIN s najmanje 4 znamenke.", hu_HU="Állíts be egy legalább 4 jegyű PIN-kódot.", it_IT="Impostare un PIN con almeno 4 cifre.", nl_NL="Maak een pincode met minimaal 4 cijfers\naan.", no_NO="Lag en PIN-kode med minst fire sifre.", pl_PL="Zdefiniuj co najmniej 4-cyfrowy kod PIN.", pt_PT="Define um PIN com 4 digitos no mínimo.", ro_RO="Stabiliţi un cod PIN cu cel puţin 4 cifre.", ru_RU="Установите PIN длиной не менее\n4 символов.", sk_SK="Stanovte PIN s najmenej 4 znakmi.", sl_SI="Določite PIN-kodo z najmanj 4 številkami.", sr_RS="Kreirajte PIN sa najmanje 4 cifre.", sv_SE="Fastställ en PIN med minst 4 tecken.", tr_TR="En az 4 karakterden oluşan bir PIN belirle.", uk_UA="Установіть PIN-код завдовжки\nщонайменше 4 символи.")
screen_content__pso_android_pin_confirm = TextObject(bs_BA="Potvrdite svoj unos", cs_CZ="Potvrďte své zadání", da_DK="Bekræft din angivelse.", de_DE="Bestätige deine Eingabe", el_GR="Επιβεβαιώστε την καταχώρισή σας", en_GB="Confirm your entry", es_ES="Confirmar PIN", fi_FI="Vahvista syöttämäsi tiedot", fr_FR="Confirmez votre saisie", hr_HR="Potvrdite svoj unos", hu_HU="Erősítsd meg a beviteledet", it_IT="Confermare l'immissione", nl_NL="Bevestig je invoer", no_NO="Bekreft inntastingen", pl_PL="Potwierdź swój wpis", pt_PT="Confirma a tua introdução", ro_RO="Confirmaţi datele introduse", ru_RU="Подтвердите ввод", sk_SK="Potvrďte svoje zadanie", sl_SI="Potrdite svoj vnos", sr_RS="Potvrdite svoj unos", sv_SE="Bekräfta inmatningen", tr_TR="Girişini onayla", uk_UA="Підтвердіть введення")
screen_content__pso_primary_user = TextObject(bs_BA="Za ovo vozilo još nije određen glavni korisnik. Glavni korisnik može dodjeljivati ovlaštenja drugim korisnicima u\naplikaciji myAudi (npr. za korištenje usluga Audi connect koje se odnose na vozilo).\n\nDa biste odredili glavnog korisnika, potreban vam je myAudi korisnik. Ako još uvijek nemate myAudi korisnika,\nmožete se registrovati u aplikaciji myAudi.\n\nPrijavite se sa svojim myAudi korisničkim imenom (adresa e-pošte) u vozilu. Potom slijedite\nuputstvo u aplikaciji myAudi.", cs_CZ="Pro toto vozidlo ještě není určen hlavní uživatel. Hlavní uživatel může v aplikaci myAudi udílet oprávnění dalším\nuživatelům (např. pro používání vozidlových služeb Audi connect).\n\nPro určení hlavního uživatele potřebujete uživatele myAudi. Pokud ještě nemáte uživatele myAudi, můžete se\nregistrovat v aplikaci myAudi.\n\nPřihlaste se ve vozidle svým uživatelským jménem myAudi (e-mailovou adresou). Postupujte pak podle pokynů v\naplikaci myAudi.", da_DK="Der er endnu ikke defineret nogen primær bruger for denne bil. Den primære bruger kan tildele andre brugere\nautorisationer i myAudi-appen (fx til anvendelse af bilrelaterede Audi connect-tjenester).\n\nFor at definere en primær bruger skal du bruge en myAudi-bruger. Hvis du endnu ikke har en myAudi-bruger, kan\ndu registrere dig i myAudi-appen.\n\nLog på med dit myAudi-brugernavn (e-mailadresse) i bilen. Følg derefter vejledningen i myAudi-appen.", de_DE="Für dieses Fahrzeug ist noch kein Hauptnutzer festgelegt. Der Hauptnutzer kann in der myAudi App weiteren\nNutzern Berechtigungen erteilen (z. B. für die Nutzung fahrzeugbezogener Audi connect Dienste).  Um einen\nHauptnutzer festzulegen, benötigst du einen myAudi Nutzer. Solltest du noch keinen myAudi Nutzer haben,\nkannst du dich in der myAudi App registrieren.\n\nMelde dich mit deinem myAudi Benutzernamen (E-Mail-Adresse) im Fahrzeug an. Folge anschließend der\nAnleitung in der myAudi App.", el_GR="Δεν έχει καθοριστεί ακόμη βασικός χρήστης για αυτό το όχημα. Ο βασικός χρήστης μπορεί στην εφαρμογή myAudi\nνα χορηγήσει δικαιώματα σε περαιτέρω χρήστες (π.χ., για τη χρήση των υπηρεσιών Audi connect που αφορούν στο\nόχημα_.\n\nΓια να μπορέσετε να καθορίσετε έναν βασικό χρήστη, θα χρειαστείτε έναν λογαριασμό myAudi. Εάν δεν έχετε\nακόμη λογαριασμό myAudi, μπορείτε να εγγραφείτε στην εφαρμογή myAudi.\n\nΣυνδεθείτε (log in) στο όχημα με το όνομα χρήστη σας myAudi (διεύθυνση email). Στη συνέχεια ακολουθήστε τις\nοδηγίες στην εφαρμογή myAudi.", en_GB="A key user has not yet been assigned to this vehicle. The key user can grant other users rights in the myAudi app\n(e.g. for the use of vehicle-related Audi connect services)\n\nTo assign a key user, a myAudi user is required. If you do not have a myAudi user, you can register in the\nmyAudi app.\n\nLog in to the vehicle with your myAudi username (e-mail address). Then follow the instructions in the\nmyAudi app.", es_ES="Este vehículo no tiene todavía usuario principal. El usuario principal puede conceder permisos a otros usuarios en\nla App myAudi (p. ej., para utilizar servicios Audi connect relacionados con el vehículo).\n\nPara determinar un usuario principal, necesita un usuario myAudi. Si todavía no tiene usuario myAudi, puede\nregistrarse en la App myAudi.\n\nInicie sesión en el vehículo con su nombre de usuario myAudi (dirección de e-mail). A continuación, siga\nlas instrucciones de la App myAudi.", fi_FI="Tälle autolle ei ole vielä määritetty pääkäyttäjää. Pääkäyttäjä voi myöntää oikeuksia muille käyttäjille\nmyAudi-sovelluksessa (esim. autokohtaisten Audi connect -palvelujen käyttöä varten).\n\nPääkäyttäjän määrittämiseen tarvitaan myAudi-käyttäjätili. Mikäli tiliä ei vielä ole, voit rekisteröityä\nmyAudi-sovellukseen.\n\nKirjaudu autoon myAudi-käyttäjänimelläsi (sähköpostiosoitteella). Noudata sitten myAudi-sovelluksen ohjeita.", fr_FR="Pour l'instant, aucun utilisateur principal n'est défini pour ce véhicule. L'utilisateur principal peut accorder des\nautorisations à d'autres utilisateurs dans l'application myAudi (par ex. pour l'utilisation de services Audi connect\nspécifiques au véhicule).\n\nUn profil utilisateur myAudi est requis pour définir un utilisateur principal. Si vous n'avez pas encore de profil\nutilisateur myAudi, vous pouvez vous inscrire dans l'application myAudi.\n\nConnectez-vous dans le véhicule avec votre nom d'utilisateur myAudi (adresse e-mail). Suivez ensuite les\ninstructions dans l'application myAudi.", hr_HR="Za ovo vozilo još nije određen glavni korisnik. Glavni korisnik može dodatnim korisnicima u aplikaciji myAudi\ndodjeljivati odobrenja (npr. za korištenje Audi connect usluga koje se odnose na vozilo).\n\nKako biste odredili glavnog korisnika, treba vam myAudi korisnički račun. Ako još nemate myAudi korisnički\nračun, možete se registrirati u myAudi aplikaciji.\n\nPrijavite se sa svojim myAudi korisničkim imenom (e-mail adresa) u vozilu. Nakon toga slijedite upute u myAudi\naplikaciji.", hu_HU="Ehhez a járműhöz még nincs megadva főfelhasználó. A főfelhasználó jogosultságokat adhat más\nfelhasználóknak a myAudi alkalmazásban (pl. a járműhöz kapcsolódó Audi connect szolgáltatások használatára).\n\nA főfelhasználó beállításához szükség van egy myAudi felhasználóra. Ha még nincs myAudi felhasználód, akkor\na myAudi alkalmazásban regisztrálhatsz.\n\nJelentkezz be myAudi felhasználóneveddel (e-mail-cím) a jáműben. Kövesd ezután a myAudi alkalmazás\nutasítását.", it_IT="Per questa vettura non è ancora stato impostato un utente principale. L'utente principale può concedere le\nautorizzazioni ad altri utenti nell'app myAudi (per es. per l'utilizzo dei servizi Audi connect relativi alla vettura).\n\nPer impostare un utente principale è necessario un utente myAudi. Se non si dispone ancora di un utente\nmyAudi, è possibile registrarsi nell'app myAudi.\n\nEffettuare il login nella vettura con il proprio nome utente myAudi (indirizzo e-mail). Quindi seguire le istruzioni\nnell'app myAudi.", nl_NL="Er is nog geen hoofdgebruiker gedefinieerd voor dit voertuig. De hoofdgebruiker kan autorisaties toekennen aan\nandere gebruikers in de myAudi app (bijv. voor het gebruik van voertuiggerelateerde Audi connect-diensten).\n\nOm een hoofdgebruiker te definiëren, heb je een myAudi-gebruiker nodig. Als je nog geen myAudi-gebruiker\nhebt, kun je je registreren in de myAudi-app.\n\nLog in het voertuig in met je myAudi-gebruikersnaam (e-mailadres). Volg vervolgens de instructies in\nde myAudi app.", no_NO="Det er ikke opprettet en hovedbruker for denne bilen ennå. Hovedbrukeren kan gi tilgangstillatelser til andre\nbrukere i myAudi-appen (for eksempel for bruk av bilrelaterte Audi connect-tjenester).\n\nDu må ha en myAudi-bruker for å definere en hovedbruker. Hvis du ikke har en myAudi-bruker, kan du registrere\ndeg i myAudi-appen.\n\nLogg på i bilen med myAudi-brukernavnet ditt (e-postadresse). Følg deretter anvisningene i myAudi-appen.", pl_PL="Dla tego pojazdu nie zdefiniowano jeszcze użytkownika głównego. Główny użytkownik może nadawać\nuprawnienia innym użytkownikom w aplikacji myAudi (np. do korzystania z usług Audi connect związanych z\npojazdem).\n\nAby zdefiniować użytkownika głównego, potrzebny jest użytkownik myAudi. Jeśli nie masz jeszcze użytkownika\nmyAudi, możesz zarejestrować się w aplikacji myAudi.\n\nZaloguj się do pojazdu z użyciem swojej nazwy użytkownika myAudi (adresu e-mail). Następnie postępuj zgodnie\nz instrukcjami w aplikacji myAudi.", pt_PT="Ainda não está definido um utilizador principal para este veículo. Na myAudi App o utilizador principal pode\nconceder permissões para mais utilizadores (por ex., para utilização dos serviços Audi connect relacionados com\no veículo.\n\nPara definires um utilizador principal necessitas de um utilizador myAudi. Caso não tenhas um utilizador\nmyAudi, podes registar-te na myAudi App.\n\nFaz login no veículo com o teu nome de utilizador Audi (endereço de e-mail). Depois segue as indicações na\nmyAudi App.", ro_RO="Pentru acest autovehicul nu este încă stabilit niciun utilizator principal. Utilizatorul principal poate aloca\ndrepturi altor utilizatori în aplicaţia myAudi (de ex. pentru utilizarea serviciilor Audi connect aferente\nautovehiculului).\n\nPentru a stabili un utilizator principal, aveţi nevoie de un utilizator myAudi. Dacă nu dispuneţi încă de un\nutilizator myAudi, vă puteţi înregistra în aplicaţia myAudi.\n\nAutentificaţi-vă cu numele de utilizator myAudi (adresa de e-mail) în autovehicul. Apoi urmaţi instrucţiunile din\naplicaţia myAudi.", ru_RU="Для данного автомобиля еще не определен основной пользователь. Основной пользователь может\nпредоставлять полномочия другим пользователям в приложении myAudi (например, для использования\nсвязанных с автомобилем сервисов Audi connect).\n\nЧтобы определить основного пользователя, необходимо иметь пользователя myAudi. Если у вас еще нет\nпользователя myAudi, вы можете зарегистрироваться в приложении myAudi.\n\nВойдите в автомобиль под своим именем пользователя myAudi (адрес электронной почты). Затем следуйте\nинструкциям в приложении myAudi.", sk_SK="Pre toto vozidlo ešte nie je definovaný žiadny hlavný používateľ. Hlavný používateľ môže v aplikácii myAudi\nudeľovať oprávnenia iným používateľom (napr. na používanie služieb Audi connect súvisiacich s vozidlom).\n\nAk chcete definovať hlavného používateľa, potrebujete používateľa myAudi. Ak ešte nemáte používateľa myAudi,\nmôžete sa zaregistrovať v aplikácii myAudi.\n\nPrihláste sa do vozidla pomocou vášho používateľského mena myAudi (e-mailová adresa). Následne postupujte\npodľa návodu v aplikácii myAudi.", sl_SI="Za to vozilo še ni določen glavni uporabnik. Glavni uporabnik lahko v aplikaciji myAudi podeljuje pooblastila\ndrugim uporabnikom (npr. za uporabo storitev Audi connect v vozilu).\n\nZa določitev glavnega uporabnika morate biti uporabnik myAudi. Če še niste uporabnik myAudi, se lahko\nregistrirate v aplikaciji myAudi.\n\nS svojim uporabniškim imenom myAudi (elektronski naslov) se prijavite v vozilu. Nato sledite navodilom v\naplikaciji myAudi.", sr_RS="Za ovo vozilo još nije definisan glavni korisnik. Glavni korisnik može da dodeljuje ovlašćenja drugim korisnicima u\naplikaciji myAudi (npr. za korišćenje usluga Audi connect koje se odnose na vozilo).\n\nDa biste definisali glavnog korisnika, potreban vam je myAudi korisnik. Ako još uvek nemate myAudi korisnika,\nmožete da se registrujete u aplikaciji myAudi.\n\nPrijavite se sa svojim myAudi korisničkim imenom (adresa e-pošte) u vozilu. Potom sledite uputstvo u\naplikaciji myAudi.", sv_SE="För detta fordon är ingen huvudanvändare ännu registrerad. Huvudanvändaren kan godkänna behörigheter för\nandra användare i myAudi-appen (t.ex. för användning av fordonsberoende Audi connect-tjänster).\n\nFör att ange en huvudanvändare behöver du en myAudi-användare.\n\nOm du inte har en myAudi-användare än kan du registrera dig i myAudi-appen.", tr_TR="Bu araç için henüz ana kullanıcı belirlenmedi. Ana kullanıcı myAudi uygulamasında diğer kullanıcılara yetki\nverebilir (örn. araçla ilgili Audi connect hizmetlerinin kullanımı için).\n\nBir ana kullanıcı belirlemek için, bir myAudi kullanıcısına ihtiyacın vardır. Henüz bir myAudi kullanıcın yoksa,\nmyAudi uygulamasında kayıt olabilirsin.\n\nmyAudi kullanıcı adınla (E-posta adresi) araçta oturum aç. Ardından myAudi uygulamasındaki talimatları izle.", uk_UA="Для цього автомобіля ще не встановлено основного користувача. Основний користувач може наділити\nповноваженнями інших користувачів на порталі myAudi(наприклад, для використання служб Audi connect,\nпов'язаних з автомобілем).\n\nЩоб визначити головного користувача, потрібно мати обліковий запис myAudi.\nЯкщо у вас ще немає облікового запису myAudi, ви можете зареєструватися в програмі myAudi.\n\nУвійдіть в автомобіль, використовуючи своє ім'я користувача myAudi (адреса електронної пошти). Потім\nдотримуйтесь інструкцій у програмі myAudi.")
screen_content__pso_security_already_selected_first_part_android = TextObject(bs_BA="Vaša trenutna PIN zaštita: PIN vozila", cs_CZ="Vaše aktuální ochrana PIN: PIN vozidla", da_DK="Din aktuelle pinkodebeskyttelse: Bilpinkode", de_DE="Dein aktueller PIN-Schutz: Fahrzeug-PIN", el_GR="Η τρέχουσα προστασία PIN σας: PIN οχήματος", en_GB="Your current PIN protection: vehicle PIN", es_ES="Protección con PIN actual: PIN del vehículo", fi_FI="Nykyinen PIN-suojauksesi: auton PIN-koodi", fr_FR="Votre protection actuelle par code PIN: code PIN du véhicule", hr_HR="Vaš trenutačni PIN: PIN vozila", hu_HU="Jelenlegi PIN-kód védelmed: jármű PIN-kód", it_IT="Attuale protezione con PIN: PIN vettura", nl_NL="Je huidige pincodebescherming: Voertuigpincode", no_NO="Nåværende PIN-beskyttelse: Bilens PIN-kode", pl_PL="Twoje aktualne zabezpieczenie kodem PIN: kod PIN pojazdu", pt_PT="O teu PIN de proteção atual: PIN do veículo", ro_RO="PIN-ul dvs. de protecţie actual: PIN autovehicul", ru_RU="Ваш текущий PIN-код защиты: PIN-код автомобиля", sk_SK="Vaša aktuálna ochrana PIN: PIN vozidla", sl_SI="Vaša trenutna zaščita s PIN-kodo: PIN-koda vozila", sr_RS="Vaša trenutna PIN zaštita: PIN vozila", sv_SE="Ditt aktuella PIN-skydd: fordons-PIN", tr_TR="Mevcut PIN koruman: Araç PIN'i", uk_UA="Ваш поточний PIN-код захисту: PIN-код автомобіля")
screen_content__pso_security_already_selected_first_part_oem = TextObject(bs_BA="Vaša trenutna PIN zaštita: myAudi PIN", cs_CZ="Vaše aktuální ochrana PIN: myAudi PIN", da_DK="Din aktuelle pinkodebeskyttelse: myAudi-pinkode", de_DE="Dein aktueller PIN-Schutz: myAudi PIN", el_GR="Η τρέχουσα προστασία PIN σας: myAudi PIN", en_GB="Your current PIN protection: myAudi PIN", es_ES="Protección con PIN actual: PIN myAudi", fi_FI="Nykyinen PIN-suojauksesi: myAudi-PIN", fr_FR="Votre protection actuelle par code PIN: code PIN myAudi", hr_HR="Vaš trenutačni PIN: myAudi PIN", hu_HU="Jelenlegi PIN-kód védelmed: myAudi PIN", it_IT="Attuale protezione con PIN: PIN myAudi", nl_NL="Je huidige pincodebescherming: myAudi PIN", no_NO="Nåværende PIN-beskyttelse: myAudi-PIN", pl_PL="Twoje aktualne zabezpieczenie kodem PIN: kod PIN myAudi", pt_PT="O teu PIN de proteção atual: PIN myAudi", ro_RO="PIN-ul dvs. de protecţie actual: PIN myAudi", ru_RU="Ваша текущая защита с помощью PIN-кода: myAudi PIN", sk_SK="Vaša aktuálna ochrana PIN: myAudi PIN", sl_SI="Vaša trenutna zaščita s PIN-kodo: PIN-koda myAudi", sr_RS="Vaša trenutna PIN zaštita: myAudi PIN", sv_SE="Ditt aktuella PIN-skydd: myAudi-PIN", tr_TR="Mevcut PIN koruman: myAudi PIN", uk_UA="Ваш поточний PIN-код захисту: PIN-код myAudi")
screen_content__pso_security_already_selected_second_part = TextObject(bs_BA="PIN zaštita može se promijeniti u postavkama.", cs_CZ="Ochranu PIN můžete změnit v nastaveních.", da_DK="Pinkodebeskyttelsen kan ændres i indstillingerne.", de_DE="Der PIN-Schutz kann in den Einstellungen geändert werden.", el_GR="Η προστασία PIN μπορεί να αλλάξει στις ρυθμίσεις.", en_GB="The PIN protection can be changed in the settings.", es_ES="La protección con PIN se puede modificar en los ajustes.", fi_FI="PIN-suojausta voidaan muuttaa asetuksista.", fr_FR="Vous pouvez modifier la protection par code PIN dans les réglages.", hr_HR="PIN se može promijeniti u postavkama.", hu_HU="PIN-kód védelmed a beállításokban módosítható.", it_IT="È possibile modificare la protezione con PIN nelle impostazioni.", nl_NL="Je pincode kan worden gewijzigd in de instellingen.", no_NO="Du kan endre PIN-beskyttelsen i innstillingene.", pl_PL="Zabezpieczenie kodem PIN można zmienić w ustawieniach.", pt_PT="O PIN de proteção pode ser alterado nos ajustes.", ro_RO="Protecţia PIN poate fi modificată în setări.", ru_RU="PIN-код можно изменить в настройках.", sk_SK="Ochranu kódom PIN je možné zmeniť v nastaveniach.", sl_SI="Zaščito s PIN-kodo lahko spremenite v nastavitvah.", sr_RS="PIN zaštita može da se promeni u podešavanjima.", sv_SE="PIN-skyddet kan ändras i inställningarna.", tr_TR="PIN koruması ayarlardan değiştirilebilir.", uk_UA="PIN-код можна змінити в налаштуваннях.")
screen_content__speech_description = TextObject(bs_BA="Uz pomoć Audi assistant-a možete glasovno upravljati brojnim funkcijama u vozilu. Audi assistant daje proaktivne\nprijedloge i rutine u odgovarajućim situacijama i u potrebnom obimu.", cs_CZ="Za pomoci Audi assistanta můžete obsluhovat mnohé funkce ve vozidle hlasově. Audi assistant udílí proaktivní\nnávrhy a rutiny ve správných situacích a v potřebném rozsahu.", da_DK="Ved hjælp af Audi assistant kan du stemmebetjene mange funktioner i bilen. Audi assistant kommer med\nproaktive forslag og rutiner til dig i de rigtige situationer og i det nødvendige omfang.", de_DE="Mit Hilfe des Audi assistant kannst du viele Funktionen im Fahrzeug per Sprache bedienen. Der Audi assistant\nunterbreitet dir proaktive Vorschläge und Routinen in den richtigen Situationen und im benötigten Umfang.", el_GR="Με τη βοήθεια της Audi assistant μπορείτε να χειριστείτε φωνητικά πολλές λειτουργίες στο όχημα. Η Audi assistant\nσας υποβάλλει προδραστικές προτάσεις και ρουτίνες στις σωστές καταστάσεις και στην απαιτούμενη έκταση.", en_GB="You can operate lots of functions in the vehicle by voice with the Audi assistant. The Audi assistant makes\nproactive suggestions and offers you routines in the right situations according to your needs.", es_ES="Con ayuda del Audi assistant puede controlar por voz muchas funciones del vehículo. El Audi assistant le\npropondrá rutinas y sugerencias proactivas en determinadas situaciones y en la medida necesaria.", fi_FI="Audi assistantin avulla voit käyttää monia toimintoja autossa puheen avulla. Audi assistant ehdottaa ennakoivia\nehdotuksia ja rutiineja oikeissa tilanteissa ja tarvittavassa laajuudessa.", fr_FR="L'Audi assistant vous permet d'utiliser de nombreuses fonctions ds le véhicule au moyen des commandes vocales.\nL'Audi assistant vous soumet de manière mesurée des suggest. proactives et des routines ds les situat. adéquates", hr_HR="Pomoću Audi assistanta velikim brojem funkcija u vozilu možete rukovati govorom. Audi assistant proaktivno daje\nprijedloge i predlaže rutine u pravim situacijama i u potrebnom opsegu.", hu_HU="Az Audi assistant segítségével számos funkciót vezérelhetsz a járműben hanggal. Az Audi assistant proaktív\njavaslatokat és rutinokat ad a megfelelő helyzetekben és a szükséges mértékben.", it_IT="Grazie all'Audi assistant è possibile eseguire molte funzioni a bordo della vettura tramite comandi vocali. L'Audi\nassistant suggerisce proposte proattive e routine nelle situazioni giuste e nella misura necessaria.", nl_NL="Met behulp van de Audi assistant kun je veel functies in het voertuig met spraak bedienen.De Audi assistent geeft\nje proactief suggesties en routines in de juiste situaties in in de vereiste mate.", no_NO="Med Audi assistant kan du styre mange funksjoner i bilen med talekommandoer. Audi assistant kommer med\nproaktive forslag og kan lage situasjonsbetingede rutiner.", pl_PL="Z pomocą Audi assistant można obsługiwać głosowo wiele funkcji w pojeździe. Audi assistant dostarcza\nproaktywne sugestie i rutyn w odpowiednich sytuacjach i w wymaganym zakresie.", pt_PT="Com o auxílio do Audi assistant podes controlar muitas funções no veículo através da voz. O Audi assistant dá-te\nrecomendações proativas e rotinas nas situações corretas e à medida das necessidades.", ro_RO="Cu Audi assistant puteţi opera multe funcţii din autovehicul prin comandă vocală. Audi assistant vă oferă\npropuneri proactive şi rutine în situaţiile potrivite şi în măsura necesară.", ru_RU="С помощью Audi assistant вы можете управ. многими функциями а/м голосом. Audi assistant предоставляет\nвам проактивные рекомендации и стандартные действия в нужных ситуациях и в необходимом объеме.", sk_SK="Pomocou Audi assistant môžete ovládať mnoho funkcií vozidla hlasom. Audi assistant ti ponúka proaktívne návrhy\na rutiny v správnych situáciách a v potrebnom rozsahu.", sl_SI="S pomočjo sistema Audi assistant lahko glasovno upravljate številne funkcije v vozilu. Audi assistant vam\nproaktivne predloge in rutinske postopke posreduje v pravih situacijah in v potrebnem obsegu.", sr_RS="Uz pomoć Audi assistant-a, brojnim funkcijama u vozilu možete da upravljate putem govora. Audi assistant vam\nprikazuje proaktivne predloge i rutine u odgovarajućim situacijama i u neophodnom ospegu.", sv_SE="Med hjälp av Audi assistant kan du röststyra flera funktioner i bilen. Audi assistant erbjuder dig proaktiva förslag\noch rutiner i rätt situationer och i den omfattning som behövs.", tr_TR="Audi assistant'ın yardımıyla araçtaki birçok fonksiyonu sesli komut ile kullanabilirsin. Audi assistant sana doğru\ndurumlarda ve gerektiği ölçüde proaktif öneriler ve rutinler sunar.", uk_UA="За допомогою Audi assistant ви можете керувати багатьма функціями автомобіля голосом. Audi assistant\nнадає вам проактивні пропозиції та стандартні дії в потрібних ситуаціях і в необхідному обсязі.")
screen_content__speech_description_minimal = TextObject(cs_CZ="Hlasovým ovládáním můžete hlasem obsluhovat různé funkce jako rádio nebo telefon", da_DK="Med stemmebetjeningsfunktionen kan du stemmebetjene forskellige funktioner som fx radio eller telefon.", de_DE="Mit der Sprachbedienung können verschiedene Funktionen, wie Radio oder Telefon, per Sprache bedient werden", el_GR="Με τον φωνητικό χειρισμό μπορεί να γίνει χειρισμός διαφόρων λειτουργιών, όπως ραδιόφωνο ή τηλέφωνο", en_GB="You can use speech control to operate various functions by voice, such as the radio or the telephone.", es_ES="El manejo por voz le permite controlar diferentes funciones, como la radio o el teléfono", fi_FI="Puheohjauksella voi puheen avulla käyttää erilaisia toimintoja, kuten radiota tai puhelinta", fr_FR="Le système à commande vocale vous permet d'utiliser différentes fonctions telles que la radio ou le téléphone au\nmoyen des commandes vocales.", hu_HU="A beszédvezérléssel különböző funkciók, például a rádió vagy a telefon, hanggal is működtethetők", it_IT="Con il sistema di comando vocale è possibile comandare con la voce diverse funzioni, come radio o telefono", nl_NL="Met de spraakbediening kunnen verschillende functies, zoals radio of telefoon, met spraak worden bediend", no_NO="Med stemmestyringen kan du styre ulike funksjoner, for eksempel radio og telefon, med stemmen", pl_PL="Obsługa głosowa pozwala obsługiwać głosem rozmaite funkcje, jak radio czy telefon", pt_PT="Através do comando por voz é possível acionar várias funções, como o rádio ou o telefone, com a voz", ru_RU="С помощью голосового управления можно управлять различными функциями, такими как радио или\nтелефон, с помощью голоса", sv_SE="Med röststyrningen kan olika funktioner som t.ex. radio eller telefon styras med rösten", tr_TR="Sesle kontrol ile, radyo veya telefon gibi çeşitli fonksiyonlar konuşarak kumanda edilebilir")
screen_content__speech_description_no_smart_system = TextObject(cs_CZ="Za pomoci Audi assistanta můžete obsluhovat mnohé funkce ve vozidle hlasově.", da_DK="Ved hjælp af Audi assistant kan du stemmebetjene mange funktioner i bilen.", de_DE="Mit Hilfe des Audi assistant kannst du viele Funktionen im Fahrzeug per Sprache bedienen.", el_GR="Με τη βοήθεια της Audi assistant μπορείτε να χειριστείτε φωνητικά πολλές λειτουργίες στο όχημα.", en_GB="You can operate lots of functions in the vehicle by voice with the Audi assistant.", es_ES="Con ayuda del Audi assistant puede controlar por voz muchas funciones del vehículo.", fi_FI="Audi assistantin avulla voit käyttää monia toimintoja autossa puheen avulla.", fr_FR="L'Audi assistant vous permet d'utiliser de nombreuses fonctions dans le véhicule au moyen des commandes\nvocales.", hu_HU="Az Audi assistant segítségével számos funkciót vezérelhetsz a járműben hanggal.", it_IT="Grazie all'Audi assistant è possibile eseguire molte funzioni a bordo della vettura tramite comandi vocali.", nl_NL="Met behulp van Audi assistant kun je veel functies in het voertuig met spraak bedienen.", no_NO="Med Audi assistant kan du styre mange funksjoner i bilen med stemmen.", pl_PL="Za pomocą funkcji Audio assistant możesz obsługiwać głosowo wiele funkcji samochodu.", pt_PT="Com o auxílio do Audi assistant podes controlar através da voz muitas funções no veículo.", ru_RU="С помощью Audi Аssistant вы можете управлять многими функциями автомобиля с помощью голоса.", sv_SE="Med hjälp av Audi assistant kan du röststyra flera funktioner i fordonet.", tr_TR="Audi assistant'ın yardımıyla araçtaki birçok fonksiyonu sesli komut ile kullanabilirsin.")
screen_content__speech_description_offline = TextObject(bs_BA="Uz pomoć Audi assistant-a možete glasovno upravljati brojnim funkcijama u vozilu. Audi assistant daje proaktivne prijedloge i rutine u odgovarajućim situacijama i u potrebnom obimu.", cs_CZ="Za pomoci Audi assistanta můžete obsluhovat mnohé funkce ve vozidle hlasově. Audi assistant udílí proaktivní\nnávrhy a rutiny ve správných situacích a v potřebném rozsahu.", da_DK="Ved hjælp af Audi assistant kan du stemmebetjene mange funktioner i bilen. Audi assistant kommer med\nproaktive forslag og rutiner til dig i de rigtige situationer og i det nødvendige omfang.", de_DE="Mit Hilfe des Audi assistant kannst du viele Funktionen im Fahrzeug per Sprache bedienen. Der Audi assistant\nunterbreitet dir proaktive Vorschläge und Routinen in den richtigen Situationen und im benötigten Umfang.", el_GR="Με τη βοήθεια της Audi assistant μπορείτε να χειριστείτε φωνητικά πολλές λειτουργίες στο όχημα. Η Audi assistant\nσας υποβάλλει προδραστικές προτάσεις και ρουτίνες στις σωστές καταστάσεις και στην απαιτούμενη έκταση.", en_GB="You can operate lots of functions in the vehicle by voice with the Audi assistant. The Audi assistant makes\nproactive suggestions and offers you routines in the right situations according to your needs.", es_ES="Con ayuda del Audi assistant puede controlar por voz muchas funciones del vehículo. El Audi assistant le\npropondrá rutinas y sugerencias proactivas en determinadas situaciones y en la medida necesaria.", fi_FI="Audi assistantin avulla voit käyttää monia toimintoja autossa puheen avulla. Audi assistant ehdottaa ennakoivia\nehdotuksia ja rutiineja oikeissa tilanteissa ja tarvittavassa laajuudessa.", fr_FR="L'Audi assistant vous permet d'utiliser de nombreuses fonctions ds le véhicule au moyen des commandes vocales.\nL'Audi assistant vous soumet de manière mesurée des suggest. proactives et des routines ds les situat. adéquates", hr_HR="Pomoću Audi assistanta velikim brojem funkcija u vozilu možete rukovati govorom. Audi assistant proaktivno daje prijedloge i predlaže rutine u pravim situacijama i u potrebnom opsegu.", hu_HU="Az Audi assistant segítségével számos funkciót vezérelhetsz a járműben hanggal. Az Audi assistant proaktív\njavaslatokat és rutinokat ad a megfelelő helyzetekben és a szükséges mértékben.", it_IT="Grazie all'Audi assistant è possibile eseguire molte funzioni a bordo della vettura tramite comandi vocali. L'Audi\nassistant suggerisce proposte proattive e routine nelle situazioni giuste e nella misura necessaria.", nl_NL="Met behulp van de Audi assistant kun je veel functies in het voertuig met spraak bedienen.De Audi assistent geeft\nje proactief suggesties en routines in de juiste situaties in in de vereiste mate.", no_NO="Med Audi assistant kan du styre mange funksjoner i bilen med talekommandoer. Audi assistant kommer med\nproaktive forslag og kan lage situasjonsbetingede rutiner.", pl_PL="Z pomocą Audi assistant można obsługiwać głosowo wiele funkcji w pojeździe. Audi assistant dostarcza\nproaktywne sugestie i rutyn w odpowiednich sytuacjach i w wymaganym zakresie.", pt_PT="Com o auxílio do Audi assistant podes controlar muitas funções no veículo através da voz. O Audi assistant dá-te\nrecomendações proativas e rotinas nas situações corretas e à medida das necessidades.", ro_RO="Cu Audi assistant puteţi opera multe funcţii din autovehicul prin comandă vocală. Audi assistant vă oferă propuneri proactive şi rutine în situaţiile potrivite şi în măsura necesară.", ru_RU="С помощью Audi assistant вы можете управ. многими функциями а/м голосом. Audi assistant предоставляет\nвам проактивные рекомендации и стандартные действия в нужных ситуациях и в необходимом объеме.", sk_SK="Pomocou Audi assistant môžete ovládať mnoho funkcií vozidla hlasom. Audi assistant ti ponúka proaktívne návrhy a rutiny v správnych situáciách a v potrebnom rozsahu.", sl_SI="S pomočjo sistema Audi assistant lahko glasovno upravljate številne funkcije v vozilu. Audi assistant vam proaktivne predloge in rutinske postopke posreduje v pravih situacijah in v potrebnem obsegu.", sr_RS="Uz pomoć Audi assistant-a, brojnim funkcijama u vozilu možete da upravljate putem govora. Audi assistant vam prikazuje proaktivne predloge i rutine u odgovarajućim situacijama i u neophodnom ospegu.", sv_SE="Med hjälp av Audi assistant kan du röststyra flera funktioner i bilen. Audi assistant erbjuder dig proaktiva förslag\noch rutiner i rätt situationer och i den omfattning som behövs.", tr_TR="Audi assistant'ın yardımıyla araçtaki birçok fonksiyonu sesli komut ile kullanabilirsin. Audi assistant sana doğru\ndurumlarda ve gerektiği ölçüde proaktif öneriler ve rutinler sunar.", uk_UA="За допомогою Audi assistant ви можете керувати багатьма функціями автомобіля голосом. Audi assistant надає вам проактивні пропозиції та стандартні дії в потрібних ситуаціях і в необхідному обсязі.")
screen_content__speech_unsupported = TextObject(bs_BA="Audi assistant nije raspoloživ na podešenom jeziku. Odaberite\nneki drugi sistemski jezik.", cs_CZ="Audi assistant je v nastaveném jazyce nedostupný. Zvolte prosím\njiný jazyk systému.", da_DK="Audi assistant er ikke tilgængelig på det indstillede sprog.\nVælg et andet systemsprog.", de_DE="Der Audi assistant ist in der eingestellten Sprache nicht\nverfügbar. Bitte wähle eine andere Systemsprache aus.", el_GR="Η Audi assistant δεν είναι διαθέσιμη στη ρυθμισμένη γλώσσα.\nΕπιλέξτε μια άλλη γλώσσα συστήματος.", en_GB="The Audi assistant is not available in the selected language.\nPlease select another system language.", es_ES="El Audi assistant no está disponible en el idioma ajustado.\nPor favor, seleccione otro idioma.", fi_FI="Audi assistant ei ole käytettävissä asetetulla kielellä.\nValitse toinen järjestelmäkieli.", fr_FR="L'Audi assistant n'est pas disponible dans la langue réglée.\nVeuillez sélectionner une autre langue du système.", hr_HR="Audi assistant u namještenom jeziku nije raspoloživ.\nOdaberite drugi sistemski jezik.", hu_HU="Az Audi assistant a beállított nyelven nem áll rendelkezésre.\nKérünk, válassz egy másik rendszernyelvet.", it_IT="L'Audi assistant non è disponibile nella lingua impostata.\nSelezionare un'altra lingua del sistema.", nl_NL="De Audi assistant is niet beschikbaar in de ingestelde taal.\nSelecteer een andere systeemtaal.", no_NO="Audi assistant er ikke tilgjengelig på språket som er innstilt. Velg\net annet systemspråk.", pl_PL="Audi assistant nie jest dostępny w ustawionym języku. Proszę\nwybrać inny język systemowy.", pt_PT="O Audi assistant não está disponível no idioma selecionado.\nPor favor, seleciona outro idioma do sistema.", ro_RO="Audi assistant nu este disponibil în limba selectată. Selectaţi o\naltă limbă a sistemului.", ru_RU="Audi assistant недоступен на установленном языке.\nПожалуйста, выберите другой язык системы.", sk_SK="Audi assistant v nastavenom jazyku nie je dostupný.\nProsím, zvoľte iný jazyk systému.", sl_SI="Audi assistant ni na voljo v izbranem jeziku. Izberite drug\nsistemski jezik.", sr_RS="Audi assistant nije dostupan na podešenom jeziku. Molimo vas\nda izaberete drugi sistemski jezik.", sv_SE="Audi assistant är inte tillgänglig på det inställda språket. Välj ett\nannat systemspråk.", tr_TR="Audi assistant, ayarlanan dilde mevcut değildir. Lütfen başka bir\nsistem dili seç.", uk_UA="Audi assistant недоступний на встановленій мові. Будь ласка,\nвиберіть іншу мову системи.")
screen_content__wbl_connection_error_description = TextObject(bs_BA="Došlo je do greške u povezivanju. Pokušajte ponovo ili nastavite uređivanje kao\nlokalni korisnik.\n\nVašeg myAudi korisnika možete kasnije povezati sa Vašim lokalnim korisnikom pod\nopcijom za upravljanje korisnicima. U tu svrhu otvorite profil Vašeg korisnika i\nodaberite „Povezivanje myAudi korisnika“.", cs_CZ="Došlo k chybě připojení. Zkuste to prosím znovu nebo pokračujte v nastavení jako místní uživatel. \nUživatele myAudi můžete k místnímu uživateli připojit později ve správě uživatelů. Za tímto účelem\notevřete profil svého uživatele a vyberte možnost „Přidat uživatele myAudi“.", da_DK="Forbindelsesfejl opstået. Forsøg igen, eller fortsæt konfiguration som lokal bruger.\n\nDu kan senere forbinde din myAudi-bruger med din lokale bruger i brugeradministrationen.\nÅbn i den forbindelse din brugers profil, og vælg \"Forbind myAudi-bruger\".", de_DE="Es ist ein Verbindungsfehler aufgetreten. Bitte versuche es erneut oder setze die Einrichtung als\nlokaler Nutzer fort.\n\nDu kannst deinen myAudi Nutzer später in der Nutzerverwaltung mit deinem lokalen Nutzer\nverbinden. Öffne dafür das Profil deines Nutzers und wähle \"myAudi Nutzer verknüpfen\".", el_GR="Παρουσιάστηκε σφάλμα σύνδεσης. Προσπαθήστε ξανά ή συνεχίστε τη ρύθμιση ως τοπικός χρήστης.\n\nΜπορείτε αργότερα, στη διαχείριση χρηστών, να συνδέσετε τον λογαριασμό σας χρήστη myAudi με τον\nτοπικό σας λογαριασμό χρήστη. Για τον σκοπό αυτό, ανοίξτε το προφίλ του λογαριασμού χρήστη σας\nκαι επιλέξτε \"Σύνδεση λογαριασμού χρήστη myAudi\".", en_GB="A connection error has occurred. Please try again or continue setup as a local user.\n\nYou can connect your myAudi user with your local user later in user management. To do this, open\nyour user profile and select \"Link myAudi user\".", es_ES="Se ha producido un error de conexión. Por favor, inténtelo de nuevo o siga con la instalación\ncomo usuario local.\n\nPodrá conectar su usuario myAudi con su usuario local más tarde en la gestión de usuarios.\nPara ello, abra el perfil de su usuario y seleccione \"Vincular usuario myAudi\".", fi_FI="Tapahtui yhteysvirhe. Yritä uudelleen tai jatka käyttöönottoa paikallisena käyttäjänä.\n\nVoit yhdistää myAudi-käyttäjätilisi paikalliseen käyttäjätiliisi myöhemmin käyttäjähallinnassa. Avaa\ntätä varten käyttäjäprofiilisi ja valitse \"Yhdistä myAudi-käyttäjätili\".", fr_FR="Une erreur de connexion s'est produite. Veuillez réessayer ou poursuivez la configuration en tant\nqu'utilisateur local.\n\nVous pourrez connecter ultérieurement votre profil utilisateur myAudi à votre profil utilisateur local\ndans la gestion des utilisateurs. Pour ce faire, ouvrez le profil de votre utilisateur et sélectionnez\n«Associer l'utilisateur myAudi».", hr_HR="Nastupila je greška u spajanju. Pokušajte ponovno ili nastavite s uređivanjem kao lokalni korisnik.\n\nSvoj myAudi korisnički račun možete kasnije u funkciji administracije korisnika spojiti sa svojim\nlokalnim korisničkim računom. U tu svrhu otvorite profil svog korisničkog računa i odaberite \"Povezati\nmyAudi korisnički račun\".", hu_HU="Kapcsolódási hiba történt. Próbáld újra, vagy folytasd a beállítást helyi felhasználóként.\n\nA myAudi felhasználódat később a felhasználókezelésben összekapcsolhatod a helyi felhasználóddal.\nEhhez nyisd meg a felhasználód profilját, és válaszd ki a „myAudi felhasználó összekapcsolása”\nlehetőséget.", it_IT="Si è verificato un errore di collegamento. Si prega di riprovare o di continuare la configurazione come\nutente locale.\n\nIn un secondo momento sarà possibile collegare nella gestione utenti il proprio utente myAudi con\nl'utente locale. Per farlo, aprire il proprio profilo utente e selezionare \"Collega utente myAudi\".", nl_NL="Er is een verbindingsfout opgetreden. Probeer het opnieuw of ga verder met instellen als lokale\ngebruiker.  Je kunt je myAudi-gebruiker later in Gebruikersbeheer koppelen aan je lokale gebruiker.\nOpen hiervoor je gebruikersprofiel en selecteer \"myAudi-gebruiker toevoegen\".", no_NO="Det har oppstått en forbindelsesfeil. Prøv igjen eller fortsett oppsettet som lokal bruker.\n\nDu kan koble myAudi-brukeren sammen med den lokale brukeren din i brukeradministrasjonen senere\nved å åpne brukerprofilen og velge «Tilknytt myAudi-bruker».", pl_PL="Wystąpił błąd połączenia. Spróbuj ponownie lub kontynuuj konfigurowanie jako użytkownik lokalny.\n\nMożesz połączyć użytkownika myAudi z użytkownikiem lokalnym później w zarządzaniu\nużytkownikami. Aby to zrobić, otwórz profil użytkownika i wybierz „Powiąż użytkownika myAudi”.", pt_PT="Ocorreu uma falha na ligação. Por favor, volta a tentar ou continua a configuração como utilizador\nlocal.\n\nMais tarde podes ligar o teu utilizador myAudi ao teu utilizador local na Gestão de utilizadores.  Para\nisso, abre o perfil do teu utilizador e seleciona \"Associar utilizador myAudi\".", ro_RO="A apărut o eroare de conectare. Reîncercaţi mai târziu sau continuaţi instalarea ca şi utilizator local.\n\nPuteţi asocia mai târziu utilizatorul myAudi cu utilizatorul local, în administrarea utilizatorilor. Pentru\naceasta, deschideţi profilul utilizatorului dumneavoastră şi alegeţi \"asociere utilizator myAudi\".", ru_RU="Произошла ошибка подключения. Пожалуйста, попробуйте еще раз или продолжите настройку в\nкачестве локального пользователя. Вы можете подключить пользователя myAudi к локальному\nпользователю позже в управлении пользователями. Для этого откройте профиль пользователя и\nвыберите «Добавить пользователя myAudi».", sk_SK="Vyskytla sa chyba pripojenia. Prosím, pokúste sa o to znova neskôr alebo pokračujte v nastavovaní ako\nlokálny používateľ.\n\nSvojho používateľa myAudi môžete neskôr spojiť so svojim lokálnym používateľom v správe\npoužívateľovi. K tomu otvorte profil svojho používateľa a zvoľte „Pridať používateľa myAudi“.", sl_SI="Prišlo je do napake v povezavi. Poskusite znova ali nastavitev nadaljujte kot lokalni uporabnik.\n\nUporabnika myAudi lahko v upravljanju uporabnikov pozneje povežete z lokalnim uporabnikom.\nZa to odprite profil uporabnika in izberite \"Povezava uporabnika myAudi\".", sr_RS="Došlo je greške u povezivanju. Pokušajte ponovo ili nastavite uređivanje\nkao lokalni korisnik.\n\nVašeg myAudi korisnika možete kasnije povezati sa lokalnim korisnikom u\nupravljanju korisnicima. U tu svrhu otvorite profil vašeg korisnika i izaberite\n„Povezivanje myAudi korisnika“.", sv_SE="Ett anslutningsfel har uppstått. Försök igen senare eller fortsätt inställningen som lokal användare.\n\nDu kan ansluta din myAudi-användare senare i användarhanteringen med din lokala användare.\nÖppna bara din användares profil och välj ”Lägg till myAudi-användare”.", tr_TR="Bir bağlantı hatası oluştu. Lütfen yeniden dene veya yerel kullanıcı olarak kuruluma\ndevam et.\n\nDaha sonra myAudi kullanıcını kullanıcı yönetiminde yerel kullanıcına bağlayabilirsin.\nBunun için kullanıcının profilini aç ve \"myAudi kullanıcısı bağla\" seçeneğini seç.", uk_UA="Виникла помилка з'єднання. Будь ласка, спробуйте ще раз або продовжте налаштування як\nлокальний користувач. Ви можете підключити свого користувача myAudi до локального\nкористувача пізніше в керуванні користувачами. Для цього відкрийте профіль вашого\nкористувача і виберіть «Додати користувача myAudi».")
screen_content__wbl_generic_error_description = TextObject(bs_BA="Dodavanje Vašeg myAudi korisnika je bilo neuspješno. Pokušajte ponovo kasnije.\nAlternativno, uređivanje možete nastaviti kao lokalni korisnik.\n\nVašeg myAudi korisnika možete kasnije povezati sa Vašim lokalnim korisnikom pod\nopcijom za upravljanje korisnicima. U tu svrhu otvorite profil Vašeg korisnika i\nodaberite „Dodavanje myAudi korisnika“.", cs_CZ="Přidání uživatele myAudi nebylo úspěšné. Zkuste to prosím později. Případně můžete pokračovat v\nnastavení jako místní uživatel. Svého uživatele myAudi můžete s místním uživatelem propojit později\nve správě uživatelů. Za tímto účelem otevřete profil svého uživatele a zvolte „Přidat uživatele\nmyAudi“.", da_DK="Tilføjelse af din myAudi-bruger blev ikke gennemført korrekt. Forsøg igen senere. Alternativt kan du\nfortsætte konfigurationen som lokal bruger.\n\nDu kan senere forbinde din myAudi-bruger med din lokale bruger i brugeradministrationen.\nÅbn i den forbindelse din brugers profil, og vælg \"Forbind myAudi-bruger\".", de_DE="Das Hinzufügen deines myAudi Nutzers war nicht erfolgreich. Bitte versuche es zu einem späteren\nZeitpunkt erneut. Alternativ kannst du die Einrichtung als lokaler Nutzer fortsetzen.\n\nDu kannst deinen myAudi Nutzer später in der Nutzerverwaltung mit deinem lokalen Nutzer\nverbinden. Öffne dafür das Profil deines Nutzers und wähle \"myAudi Nutzer verknüpfen\".", el_GR="Η προσθήκη του λογαριασμού σας χρήστη myAudi δεν ήταν επιτυχής. Προσπαθήστε ξανά αργότερα.\nΕναλλακτικά, μπορείτε να συνεχίσετε τη ρύθμιση ως τοπικός χρήστης.\n\nΜπορείτε αργότερα, στη διαχείριση χρηστών, να συνδέσετε τον λογαριασμό σας χρήστη myAudi με τον\nτοπικό σας λογαριασμό χρήστη. Για τον σκοπό αυτό, ανοίξτε το προφίλ του λογαριασμού χρήστη σας\nκαι επιλέξτε \"Σύνδεση λογαριασμού χρήστη myAudi\".", en_GB="Your myAudi user was not added successfully. Please try again later. Alternatively, you can continue\nsetup as a local user.\n\nYou can connect your myAudi user with your local user later in user management. To do this, open\nyour user profile and select \"Link myAudi user\".", es_ES="No se ha podido añadir el usuario myAudi. Por favor, inténtelo de nuevo más tarde. También puede\nseguir con la instalación como usuario local.\n\nPodrá conectar su usuario myAudi con su usuario local más tarde en la gestión de usuarios. Para ello,\nabra el perfil de su usuario y seleccione \"Vincular usuario myAudi\".", fi_FI="myAudi-käyttäjätilisi lisääminen ei onnistunut. Yritä myöhemmin uudelleen. Vaihtoehtoisesti voit\njatkaa käyttöönottoa paikallisena käyttäjänä.\n\nVoit yhdistää myAudi-käyttäjätilisi paikalliseen käyttäjätiliisi myöhemmin käyttäjähallinnassa. Avaa\ntätä varten käyttäjäprofiilisi ja valitse \"Yhdistä myAudi-käyttäjätili\".", fr_FR="Le profil utilisateur myAudi n'a pas pu être ajouté. Veuillez réessayer ultérieurement.\nVous pouvez également poursuivre la configuration en tant qu'utilisateur local.\n\nVous pourrez connecter ultérieurement votre profil utilisateur myAudi à votre profil utilisateur local\ndans la gestion des utilisateurs. Pour ce faire, ouvrez le profil de votre utilisateur et sélectionnez\n«Associer l'utilisateur myAudi».", hr_HR="Dodavanje vašeg myAudi korisničkog računa nije uspjelo. Pokušajte ponovno kasnije. Alternativno s\nuređivanjem možete nastaviti kao lokalni korisnik.\n\nSvoj myAudi korisnički račun možete kasnije u funkciji administracije korisnika spojiti sa svojim\nlokalnim korisničkim računom. U tu svrhu otvorite profil svog korisničkog računa i odaberite \"Povezati\nmyAudi korisnički račun\".", hu_HU="A myAudi felhasználód hozzáadása nem volt sikeres. Próbáld újra később. Alternatívaként\nfolytathatod a beállítást helyi felhasználóként is.\n\nA myAudi felhasználódat később a felhasználókezelésben összekapcsolhatod a helyi felhasználóddal.\nEhhez nyisd meg a felhasználód profilját, és válaszd ki a „myAudi felhasználó  összekapcsolása”\nlehetőséget.", it_IT="Non è stato possibile aggiungere l'utente myAudi. Si prega di riprovare più tardi. In alternativa, è\npossibile continuare la configurazione come utente locale.\n\nIn un secondo momento sarà possibile collegare nella gestione utenti il proprio utente myAudi con\nl'utente locale. Per farlo, aprire il proprio profilo utente e selezionare \"Collega utente myAudi\".", nl_NL="Het toevoegen van je myAudi-gebruiker is niet gelukt. Probeer het op een later moment nog eens.\nEventueel kun je de installatie ook voortzetten als lokale gebruiker.  Je kunt je myAudi-gebruiker later\nin Gebruikersbeheer koppelen aan je lokale gebruiker. Open hiervoor je gebruikersprofiel en selecteer\n\"myAudi-gebruiker toevoegen\".", no_NO="Kan ikke legge til myAudi-brukeren din. Prøv igjen senere. Du kan også fortsette oppsettet som lokal\nbruker.\n\nDu kan koble myAudi-brukeren sammen med den lokale brukeren din i brukeradministrasjonen senere\nved å åpne brukerprofilen og velge «Tilknytt myAudi-bruker».", pl_PL="Dodawanie użytkownika myAudi nie powiodło się. Spróbuj ponownie później. Alternatywnie możesz\nkontynuować konfigurowanie jako użytkownik lokalny.\n\nMożesz połączyć użytkownika myAudi z użytkownikiem lokalnym później w zarządzaniu\nużytkownikami. Aby to zrobić, otwórz profil użytkownika i wybierz „Powiąż użytkownika myAudi”.", pt_PT="A introdução do teu utilizador myAudi falhou. Por favor, volta a tentar mais tarde. Em alternativa\npodes continuar a configuração como utilizador local.\n\nMais tarde podes associar o teu utilizador myAudi ao teu utilizador local na Gestão de utilizadores.\nPara isso, abre o perfil do teu utilizador e seleciona \"Associar utilizador myAudi\".", ro_RO="Adăugarea utilizatorului dumneavoastră myAudi nu s-a încheiat cu succes. Reîncercaţi mai târziu.\nAlternativ puteţi continua instalarea ca şi utilizator local.\n\nPuteţi asocia mai târziu utilizatorul myAudi cu utilizatorul local, în administrarea utilizatorilor. Pentru\naceasta, deschideţi profilul utilizatorului dumneavoastră şi alegeţi \"asociere utilizator myAudi\".", ru_RU="Добавление пользователя myAudi не удалось. Пожалуйста, повторите попытку позже. В качестве\nальтернативы вы можете продолжить настройку в качестве локального пользователя. Вы можете\nсвязать пользователя myAudi с локальным пользователем позже в управлении пользователями.\nДля этого откройте профиль пользователя и выберите «Добавить пользователя myAudi».", sk_SK="Pridanie vášho používateľa myAudi nebolo úspešné. Prosím, pokúste sa o to znovu neskôr. Prípadne\nmôžete pokračovať v nastavovaní ako lokálny používateľ.\n\nSvojho používateľa myAudi môžete neskôr spojiť s lokálnym používateľom v správe používateľov. K\ntomu otvorte profil svojho používateľa a zvoľte „Pridať používateľa myAudi“.", sl_SI="Dodajanje uporabnika myAudi ni bilo uspešno. Poskusite znova pozneje. Nastavitev lahko nadaljujte\ntudi kot lokalni uporabnik.\n\nUporabnika myAudi lahko v upravljanju uporabnikov pozneje povežete z lokalnim uporabnikom.\nZa to odprite profil uporabnika in izberite \"Povezava uporabnika myAudi\".", sr_RS="Dodavanje vašeg myAudi korisnika nije bilo uspešno. Pokušajte ponovo kasnije.\nAlternativno, uređivanje možete da nastavite kao lokalni korisnik.\n\nVašeg myAudi korisnika možete kasnije povezati sa vašim lokalnim korisnikom u\nupravljanju korisnicima. U tu svrhu otvorite profil vašeg korisnika i izaberite\n„Povezivanje myAudi korisnika“.", sv_SE="Din myAudi-användare kunde inte läggas till. Försök igen senare. Du kan också fortsätta inställningen\nsom lokal användare.\n\nDu kan ansluta din myAudi-användare senare i användarhanteringen med din lokala användare.\nÖppna bara din användares profil och välj ”Lägg till myAudi-användare”.", tr_TR="myAudi kullanıcının eklenmesi başarısız oldu. Lütfen daha sonra yeniden dene.\nAlternatif olarak kuruluma yerel kullanıcı olarak devam edebilirsin.\n\nDaha sonra myAudi kullanıcını kullanıcı yönetiminde yerel kullanıcına bağlayabilirsin.\nBunun için kullanıcının profilini aç ve \"myAudi kullanıcısı bağla\" seçeneğini seç.", uk_UA="Додати користувача myAudi не вдалося. Будь ласка, повторіть спробу пізніше. Крім того, ви\nможете продовжити налаштування як локальний користувач. Ви можете підключити свого\nкористувача myAudi до локального користувача пізніше в керуванні користувачами. Для цього\nвідкрийте профіль вашого користувача і виберіть «Додати користувача myAudi».")
screen_content__wbl_landing_page_1 = TextObject(bs_BA="Dodirnite na „Dalje“ i dodajte Vašeg  myAudi korisnika kako biste u potpunosti mogli koristiti sve\nfunkcije. Zavisno od opreme i modela Vašeg vozila, tako možete sinhronizirati Vaše individualne\npostavke između vozila i koristiti različite online funkcije. \n\nMožete nastaviti i kao lokalni korisnik, tako što ćete dorirnuti na „Preskočiti“. U tom slučaju su Vaše\nindividualne postavke sačuvane samo u vozilu. Personalizirane online funkcije nisu raspoložive.", cs_CZ="Klepněte na „Další“ a přidejte svého uživatele myAudi, abyste mohli využívat všechny funkce v plném\nrozsahu. V závislosti na výbavě a modelu vozidla můžete synchronizovat svá individuální nastavení\nmezi vozidly a využívat různé online funkce.\n\nMůžete také pokračovat jako místní uživatel klepnutím na „Přeskočit“. Vaše individuální nastavení se\nvšak poté uloží pouze ve vozidle. Personalizované online funkce nejsou k dispozici.", da_DK="Tryk på \"Fortsæt\", og tilføj din myAudi-bruger for at kunne anvende alle funktioner i fuldt omfang.\nAfhængigt af dit udstyr og din bilmodel kan du på den måde synkronisere dine individuelle\nindstillinger for flere biler og gøre brug af diverse onlinefunktioner.\n\nDu kan også fortsætte som lokal bruger ved at trykke på \"Spring over\". Dine individuelle indstillinger\ner dog så kun gemt i bilen. Individualiserede onlinefunktioner er ikke ikke tilgængelige.", de_DE="Tippe auf \"Weiter\" und füge deinen myAudi Nutzer hinzu, um alle Funktionen vollumfänglich nutzen\nzu können. Abhängig von deiner Ausstattung und deinem Fahrzeugmodell kannst du so deine\nindividuellen Einstellungen zwischen Fahrzeugen synchronisieren und verschiedene\nOnline-Funktionen nutzen.\n\nDu kannst auch als lokaler Nutzer fortfahren, indem du auf \"Überspringen\" tippst.\nDeine individuellen Einstellungen sind dann jedoch nur im Fahrzeug gespeichert. Personalisierte\nOnline-Funktionen sind nicht verfügbar.", el_GR="Πιέστε σύντομα στο “Συνέχεια” και προσθέστε τον λογαριασμό χρήστη myAudi για να μπορείτε να\nχρησιμοποιήσετε πλήρως όλες τις λειτουργίες. Ανάλογα με τον εξοπλισμό σας και το μοντέλο του\nοχήματός σας, μπορείτε να συγχρονίσετε τις ατομικές σας ρυθμίσεις μεταξύ οχημάτων και να\nχρησιμοποιήσετε διάφορες online λειτουργίες.\n\nΜπορείτε επίσης να συνεχίσετε ως τοπικός χρήστης πιέζοντας σύντομα στο “Παράλειψη”.\nΩστόσο, οι εξατομικευμένες ρυθμίσεις σας αποθηκεύονται τότε μόνο στο όχημα. Οι εξατομικευμένες\nonline λειτουργίες δεν θα είναι διαθέσιμες.", en_GB="Tap on \"Continue\" and add your myAudi user to be able to fully use all functions. Depending on the\nvehicle equipment and your vehicle model, you can synchronise your individual options between\nvehicles and use various online functions.\n\nYou can also proceed as a local user by tapping on \"Skip\". Your custom settings are then only saved in\nthe vehicle. Personalised online functions are not available.", es_ES="Pulse en \"Siguiente\" y añada su usuario myAudi para poder utilizar todas las funciones sin\nrestricciones. Así, dependiendo del equipamiento y el modelo de su vehículo, podrá sincronizar sus\najustes personalizados entre vehículos y utilizar diferentes funciones online. \n\nTambién puede continuar como usuario local pulsando “Saltar”. En ese caso, sin embargo, sus ajustes\npersonales solo se guardan en el vehículo. Las funciones online personalizadas no están disponibles.", fi_FI="Napauta \"Jatka\" ja lisää myAudi-käyttäjätilisi, jotta voit käyttää kaikkia toimintoja koko laajuudessaan.\nVarustelusta ja automallista riippuen voit siten synkronoida yksilölliset asetuksesi eri autojen kesken\nja käyttää erilaisia online-toimintoja.\n\nVoit myös jatkaa paikallisena käyttäjänä napauttamalla \"Ohita\". Yksilöllisiä asetuksiasi ei tällöin\nkuitenkaan tallenneta autoon. Personoidut online-toiminnot eivät ole käytettävissä.", fr_FR="Appuyez brièvement sur «Suivant» et ajoutez votre profil utilisateur myAudi pour profiter pleinement\nde toutes les fonctions. En fonction de votre équipement et de votre modèle de véhicule, vous pouvez\nsynchroniser vos réglages personnels entre les véhicules et utiliser différentes fonctions en ligne.\n\nVous pouvez également poursuivre en tant qu'utilisateur local en appuyant brièvement sur «Ignorer».\nVos réglages personnels sont alors uniquement mémorisés dans le véhicule. Les fonctions en ligne\npersonnalisées ne sont pas disponibles.", hr_HR="Dodirnite “Dalje” i dodajte svoj myAudi korisnički račun kako biste koristili sve funkcije u punom\nopsegu. Ovisno o opremi i modelu vozila na taj način možete sinkronizirati svoje individualne postavke\nizmeđu vozila i koristiti različite online funkcije.\n\nMožete nastaviti i kao lokalni korisnik tako da pritisnete „Preskočiti“. Vaše individualne postavke tada\nostaju pohranjene samo u vozilu. Individualizirane online funkcije nisu raspoložive.", hu_HU="Érintsd meg  a „Tovább” gombot, és add hozzá myAudi felhasználódat, hogy minden funkciót teljes\nmértékben használhass. A felszereltségtől és a járműmodelltől függően szinkronizálhatod egyéni\nbeállításaidat a járművek között, és használhatod a különböző online funkciókat.\n\nA „Kihagyás” gombot megérintve helyi felhasználóként is folytathatod a műveletet. Egyéni\nbeállításaid azonban ekkor csak a járműben kerülnek elmentésre. A személyre szabott online funkciók\nnem állnak rendelkezésre.", it_IT="Toccare \"Continua\" e aggiungere il proprio utente myAudi per poter utilizzare tutte le funzioni in\nmodo completo. A seconda dell'equipaggiamento e del modello di vettura, è possibile sincronizzare le\nimpostazioni personalizzate tra più vetture e utilizzare varie funzioni online.\n\nÈ anche possibile continuare come utente locale toccando \"Salta\". In questo caso, le impostazioni\npersonalizzate verranno memorizzate solo nella vettura. Le funzioni online personalizzate non sono\ndisponibili.", nl_NL="Tik op \"Volgende\" en voeg je myAudi-gebruiker toe om alle functies volledig te kunnen gebruiken.\nAfhankelijk van je uitrusting en voertuigmodel kun je je individuele instellingen tussen voertuigen\nsynchroniseren en verschillende onlinefuncties gebruiken.\n\nJe kunt ook doorgaan als lokale gebruiker door op \"Overslaan\" te tikken. Je individuele instellingen\nworden dan echter alleen in het voertuig opgeslagen. Gepersonaliseerde onlinefuncties zijn niet\nbeschikbaar.", no_NO="Trykk på \"Fortsett\", og legg til myAudi-brukeren din for å bruke alle funksjonene i fullt omfang. Da\nkan du synkronisere innstillingene dine mellom biler og bruke forskjellige online-funksjoner (avhengig\nav utstyr og modell).\n\nDu kan også fortsette som lokal bruker, ved å trykke på \"Hopp over\". Da blir de personlige\ninnstillingene dine bare lagret i bilen. Tilpassede online-funksjoner er ikke tilgjengelige.", pl_PL="Dotknij „Dalej” i dodaj swojego użytkownika myAudi, aby móc w pełni korzystać ze wszystkich funkcji.\nW zależności od wyposażenia i modelu pojazdu można synchronizować poszczególne ustawienia\nmiędzy pojazdami i korzystać z różnych funkcji online.\n\nMożesz także kontynuować jako użytkownik lokalny, dotykając „Pomiń”. Spersonalizowane ustawienia\nzostaną jednak zapisane tylko w pojeździe. Spersonalizowane funkcje online nie są dostępne.", pt_PT="Toca em \"Continuar\" e introduz o teu utilizador myAudi para poderes utilizar plenamente todas as\nfunções. Em função do teu equipamento e do modelo do teu veículo podes sincronizar entre veículos\nos teus ajustes individuais e utilizar várias funções online. \n\nPodes também continuar como utilizador local clicando em \"Saltar\". Contudo, os teus ajustes\nindividuais serão guardados apenas no veículo. As funções online personalizadas não estão\ndisponíveis.", ro_RO="Apăsaţi pe \"Continuare\" şi adăugaţi utilizatorul myAudi, pentru a putea utiliza integral toate funcţiile.\nÎn funcţie de echipare şi de modelul autovehiculului dumneavoastră, puteţi sincroniza astfel setările\ndumneavoastră individuale între autovehicule şi puteţi utiliza diferite funcţii online.\n\nPuteţi continua şi ca utilizator local, apăsând \"Omitere\". Setările dumneavoastră individuale vor fi\nmemorate în acest caz doar în autovehicul. Funcţiile online personalizate nu sunt disponibile.", ru_RU="Нажмите «Далее» и добавьте своего пользователя myAudi, чтобы иметь возможность\nиспользовать все функции в полном объеме. В зависимости от комплектации и модели\nавтомобиля вы можете синхронизировать свои индивидуальные настройки между автомобилями\nи использовать различные онлайн-функции. Вы также можете продолжить работу в качестве\nлокального пользователя, нажав на кнопку «Пропустить». Однако в этом случае ваши\nиндивидуальные настройки сохраняются только в автомобиле. Персональные онлайн-функции\nнедоступны.", sk_SK="Krátko stlačte „Ďalej“ a pridajte svojho používateľa myAudi, aby ste mohli využívať všetky funkcie v\nplnom rozsahu. V závislosti od svojej výbavy a modelu vozidla si tak môžete synchronizovať svoje\nindividuálne nastavenia medzi vozidlami a využívať rôzne online funkcie.\n\nMôžete tiež pokračovať ako lokálny používateľ krátkym stlačením „Preskočiť“. Vaše individuálne\nnastavenia však budú uložené iba vo vozidle. Personalizované online funkcie nie sú k dispozícii.", sl_SI="Za uporabo vseh funkcij v polnem obsegu pritisnite \"Naprej\" in dodajte uporabnika myAudi.\nOdvisno od opreme in modela vozila lahko svoje individualne nastavitve sinhronizirate med vozili\nin uporabljate različne spletne funkcije.\n\nKot lokalni uporabnik lahko nadaljujete tudi tako, da pritisnete \"Preskoči\". Vaše individualne\nnastavitve se nato shranijo samo v vozilu. Personalizirane spletne funkcije niso na voljo.", sr_RS="Dodirnite na „Dalje“ i dodajte vašeg myAudi korisnika da biste sve funkcije mogli koristiti u celosti. U\nzavisnosti od opreme i modela vašeg vozila, na ovaj način možete sinhronizovati vaša individualna\npodešavanja između vozila i koristiti različite onlajn funkcije. \n\nMožete da nastavite i kao lokalni korisnik tako što ćete dodirnuti na „Preskočiti“. Vaša individualna\npodešavanja su, u tom slučaju, sačuvana samo u vozilu. Personalizovane onlajn funkcije nisu\ndostupne.", sv_SE="Tryck på \"Fortsätt\" och lägg till din myAudi-användare för att kunna använda alla funktioner fullt ut.\nBeroende på din utrustning och bilmodell kan du då synkronisera dina individuella inställningar\nmellan bilar och använda olika onlinefunktioner.\n\nDu kan även fortsätta som lokal användare genom att trycka på \"Hoppa över\". Dina individuella\ninställningar är då endast sparade i bilen. Personliga onlinefunktioner är inte tillgängliga.", tr_TR="Tüm fonksiyonları tam kapsamlı olarak kullanabilmek için “Devam” üzerine dokun ve myAudi\nkullanıcını ekle. Donanımına ve araç modeline bağlı olarak kişisel ayarlarını araçlar arasında\nsenkronize edebilir ve çeşitli çevrimiçi fonksiyonları kullanabilirsin.\n\nAyrıca \"Atla\" üzerine dokunarak yerel kullanıcı olarak da devam edebilirsin. Ancak kişisel ayarların\nsadece araca kaydedilir. Kişiselleştirilmiş çevrimiçi fonksiyonlar mevcut değildir.", uk_UA="Натисніть «Далі» та додайте свого користувача myAudi, щоб мати змогу користуватися всіма\nфункціями в повному обсязі. Залежно від вашої комплектації та моделі автомобіля, ви можете\nсинхронізувати індивідуальні налаштування між автомобілями та користуватися різними онлайн\nфункціями. Ви також можете продовжити роботу як локальний користувач, натиснувши\n«Пропустити». Однак у цьому випадку ваші персоналізовані налаштування будуть збережені лише\nв автомобілі. Персоналізовані онлайн-функції будуть недоступні.")
screen_content__wbl_landing_page_2 = TextObject(bs_BA="Dodirivanjem na „Dalje“ se mobilni podaci privremeno aktiviraju,\nkako biste mogli dodati Vašeg myAudi korisnika.", cs_CZ="Klepnutím na „Další“ dočasně aktivujete mobilní data, abyste mohli přidat uživatele myAudi.", da_DK="Ved at trykke på \"Fortsæt\" aktiveres mobildata midlertidigt, så du kan tilføje din myAudi-bruger.", de_DE="Durch Tippen auf \"Weiter\" werden die mobilen Daten vorübergehend aktiviert, damit du deinen\nmyAudi Nutzer hinzufügen kannst.", el_GR="Αγγίζοντας σύντομα το \"Συνέχεια\", ενεργοποιούνται προσωρινά τα δεδομένα κινητής τηλεφωνίας, για να\nμπορέσετε να προσθέσετε τον λογαριασμό σας χρήστη myAudi.", en_GB="Tapping on \"Continue\" will temporarily activate mobile data so that you can add your myAudi user.", es_ES="Pulsando \"Siguiente\" se activarán los datos móviles temporalmente para que pueda añadir su usuario\nmyAudi.", fi_FI="Koskettamalla \"Jatka\" mobiilidata aktivoidaan tilapäisesti, jotta voit lisätä myAudi-käyttäjäprofiilisi.", fr_FR="En appuyant brièvement sur «Suite», les données mobiles sont activées temporairement pour que\nvous puissiez ajouter votre profil utilisateur myAudi.", hr_HR="Pritiskom na \"Dalje\" mobilni podaci privremeno će se aktivirati kako biste mogli dodati svoj myAudi\nkorisnički račun.", hu_HU="A „Tovább” gombra kattintva ideiglenesen aktiválódnak a mobil adatok, így hozzáadhatod a myAudi\nfelhasználódat.", it_IT="Toccando \"Continua\" si attiveranno temporaneamente i dati mobili per poter aggiungere il proprio\nutente myAudi.", nl_NL="Als je op “Volgende” tikt, worden de mobiele gegevens tijdelijk geactiveerd zodat je je\nmyAudi-gebruiker kunt toevoegen.", no_NO="Trykk på Fortsett for å aktivere mobildata midlertidig, slik at du kan legge til myAudi-brukeren din.", pl_PL="Dotknięcie przycisku „Dalej” powoduje tymczasową aktywację danych mobilnych, aby można było\ndodać użytkownika myAudi.", pt_PT="Tocando em \"Continuar\" os dados móveis são temporariamente ativados para que possas adicionar o\nteu utilizador myAudi.", ro_RO="Prin apăsare pe \"Continuare\" se activează temporar datele mobile, pentru a vă permite să adăugaţi\nutilizatorul myAudi.", ru_RU="Нажатие кнопки «Далее» временно активирует мобильные данные, чтобы вы могли добавить\nсвоего пользователя myAudi.", sk_SK="Krátkym stlačením „Ďalej“ sa dočasne aktivujú mobilné dáta, aby ste mohli pridať vášho používateľa\nmyAudi.", sl_SI="S pritiskom na \"Naprej\" se začasno aktivirajo mobilni podatki, tako da lahko dodate uporabnika\nmyAudi.", sr_RS="Dodirom na „Dalje“ mobilni podaci se privremeno aktiviraju da biste mogli da dodate vašeg myAudi\nkorisnika.", sv_SE="När du trycker på ”Fortsätt” aktiveras mobildata tillfälligt så att du kan lägga till din\nmyAudi-användare.", tr_TR="\"Devam\" üzerine dokunarak, myAudi kullanıcını ekleyebilmen için mobil veriler geçici olarak\netkinleştirilir.", uk_UA="Натискання кнопки «Далі» тимчасово активує мобільні дані, щоб ви могли додати свого\nкористувача myAudi.")
screen_content__wbl_select_nick_name = TextObject(bs_BA="Odaberite korisničko ime za Vašeg lokalnog korisnika.", cs_CZ="Zvolte uživatelské jméno pro místního uživatele.", da_DK="Vælg et brugernavn til din lokale bruger.", de_DE="Wähle einen Benutzernamen für deinen lokalen Nutzer.", el_GR="Επιλέξτε ένα όνομα χρήστη για τον τοπικό λογαριασμό σας χρήστη.", en_GB="Select a user name for your local user.", es_ES="Seleccione un nombre para su usuario local.", fi_FI="Valitse käyttäjänimi paikalliselle käyttäjäprofiilillesi.", fr_FR="Sélectionnez un nom d'utilisateur pour votre profil utilisateur local.", hr_HR="Odaberite korisničko ime za svoj lokalni korisnički račun.", hu_HU="Válassz egy felhasználónevet a helyi felhasználód számára.", it_IT="Impostare un nome utente per l'utente locale.", nl_NL="Kies een gebruikersnaam voor je lokale gebruiker.", no_NO="Velg et brukernavn til den lokale brukeren.", pl_PL="Wybierz nazwę swojego użytkownika lokalnego.", pt_PT="Escolhe um nome de utilizador para o teu utilizador local.", ro_RO="Alegeţi un nume de utilizator pentru utilizatorul dumneavoastră local.", ru_RU="Выберите имя пользователя для локального пользователя.", sk_SK="Vyberte používateľské meno pre vášho lokálneho používateľa.", sl_SI="Izberite uporabniško ime za lokalnega uporabnika.", sr_RS="Izaberite korisničko ime za vašeg lokalnog korisnika.", sv_SE="Välj ett användarnamn för din lokala användare.", tr_TR="Yerel kullanıcın için bir kullanıcı adı seç.", uk_UA="Виберіть ім'я користувача для вашого локального користувача.")
screen_content__wbl_user_already_exists = TextObject(bs_BA="Korisnik %1 već postoji na listi korisnika.\n\nŽelite li sada preći na ovog korisnika ili se ponovo prijaviti?", cs_CZ="Uživatel %1 již existuje v seznamu uživatelů.\n\nChcete se nyní přepnout na tohoto uživatele nebo se znovu přihlásit?", da_DK="Brugeren %1 eksisterer allerede på brugerlisten.\n\nVil du skifte til denne bruger nu eller logge på igen?", de_DE="Der Nutzer %1 existiert bereits in der Nutzerliste.\n\nMöchtest du jetzt zu diesem Nutzer wechseln oder dich erneut anmelden?", el_GR="Ο χρήστης %1 υπάρχει ήδη στη λίστα χρηστών.\n\nΘέλετε να αλλάξετε τώρα σε αυτόν τον χρήστη ή να συνδεθείτε (log in) εκ νέου;", en_GB="User %1 is already in the user list.\n\nWould you like to switch to this user now or log in again?", es_ES="El usuario %1 ya existe en la lista de usuarios.\n\n¿Desea cambiar ahora a dicho usuario o iniciar sesión de nuevo?", fi_FI="Käyttäjä %1 on jo olemassa käyttäjien luettelossa.\n\nHaluatko nyt vaihtaa tähän käyttäjään vai kirjautua uudelleen?", fr_FR="Le profil utilisateur %1 existe déjà dans la liste des profils.\n\nSouhaitez-vous accéder maintenant à ce profil utilisateur ou vous reconnecter?", hr_HR="Korisnički račun %1 već postoji u popisu korisničkih računa.\n\nŽelite li se sada prebaciti na taj korisnički račun ili se iznova prijaviti?", hu_HU="%1 felhasználó már létezik a felhasználólistán.\n\nÁtváltasz erre a felhasználóra, vagy újra bejelentkezel?", it_IT="L'utente %1 esiste già nella lista utenti.\n\nSi desidera passare adesso a questo utente o effettuare nuovamente il login?", nl_NL="Gebruiker %1 bestaat al in de gebruikerslijst.\n\nWil je nu overschakelen naar deze gebruiker of opnieuw inloggen?", no_NO="Brukeren %1 finnes allerede i brukerlisten.\n\nVil du bytte til denne brukeren eller logge på igjen?", pl_PL="Użytkownik %1 już istnieje na liście użytkowników.\n\nCzy chcesz teraz przełączyć się na tego użytkownika czy zalogować się ponownie?", pt_PT="O utilizador %1 já existe na lista de utilizadores.\n\nQueres mudar agora para este utilizador ou voltar a fazer login?", ro_RO="Utilizatorul %1 există deja în lista de utilizatori.\n\nDoriţi să comutaţi acum la acest utilizator sau doriţi să vă autentificaţi din nou?", ru_RU="Пользователь %1 уже существует в списке пользователей. Хотите ли вы\nпереключиться на этого пользователя сейчас или войти в систему снова?", sk_SK="Používateľ %1 už v zozname používateľov existuje.\n\nChcete sa teraz prepnúť na tohto používateľa alebo sa chcete znovu prihlásiť?", sl_SI="Uporabnik %1 že obstaja na seznamu uporabnikov.\n\nAli želite zdaj preklopiti na tega uporabnika ali se želite znova prijaviti?", sr_RS="Korisnik %1 već postoji na listi korisnika.\n\nDa li želite sada da prebacite na ovog korisnika ili da se ponovo prijavite?", sv_SE="Användaren %1 finns redan i användarlistan.\n\nVill du byta till användaren nu eller logga in igen?", tr_TR="Kullanıcı %1 zaten kullanıcı listesinde mevcut.\n\nŞimdi bu kullanıcıya geçmek mi yoksa tekrar oturum açmak mı istersin?", uk_UA="Користувач %1 вже існує у списку користувачів.\n\nВи хочете переключитися на цього користувача зараз або увійти знову?")
