texttool_globals_dialog_title___speech_info_just_talk = TextObject(cs_CZ="Informace k jednoduchému mluvení", da_DK="Informationer vedr. \"Begynd bare at tale\"", de_DE="Informationen zu Einfach lossprechen", el_GR="Πληροφορίες σχετικά με το Ξεκινήστε απλά να μιλάτε", en_GB="Information on \"Simply start talking\"", es_ES="Información sobre Empezar a hablar sin más", fi_FI="Tietoa Aktivoi järjestelmä alkamalla puhua -toiminnosta", fr_FR="Infos sur fonct. «Dialoguer simplement»", hu_HU="Info: az „Egyszerűen csak megszólalok”", it_IT="Informazioni su Parlare direttamente", nl_NL="Informatie over Gewoon praten", no_NO="Informasjon om funksjonen «Bare begynn å snakke»", pl_PL="Informacje o funkcji Po prostu powiedz", pt_PT="Informações sobre falar diretamente", ru_RU="Информация о функции «Просто начните говорить»", sv_SE="Information om Tala bara", tr_TR="Sadece konuş hakkında bilgiler")
